INSERT INTO `movies` (`movie_id`, `tags`, `title`, `overview`, `original_language`, `popularity`, `vote_average`, `genres`, `directeur`, `acteurs`) VALUES
(1, '', 'la casa de papel', 'Un groupe de criminels, dirigé par un mystérieux homme appelé \"Le Professeur\",\r\norganise le plus grand braquage de l’histoire à la Fabrique nationale de la\r\nmonnaie et du timbre d’Espagne. Leur objectif est d’imprimer des milliards\r\nd’euros tout en tenant les otages et la police sous pression. Entre stratégie,\r\némotions et tensions, chaque membre du groupe devra faire face à des choix\r\ndifficiles pour mener à bien leur mission.', 'es', 126, 8, 'action crime drama thriller', 'Alex Pina ', 'Úrsula Corberó, Álvaro Morte, Itziar Ituño, Pedro Alonso, Miguel Herrán, Jaime Lorente, Esther Acebo'),
(5, 'hotel new year\'s eve witch bet hotel room sperm los angeles hoodlum woman director episode film', 'Four Rooms', 'It\'s Ted the Bellhop\'s first night on the job...and the hotel\'s very unusual guests are about to place him in some outrageous predicaments. It seems that this evening\'s room service is serving up one unbelievable happening after another.', 'en', 22.87623, 6.5, 'Crime Comedy', 'Allison Anders', 'Tim Roth Antonio Banderas Jennifer Beals'),
(11, 'android galaxy hermit death star lightsaber jedi rescue mission empire rebellion planet smuggler the force space opera galactic war stormtrooper totalitarianism', 'Star Wars', 'Princess Leia is captured and held hostage by the evil Imperial forces in their effort to take over the galactic Empire. Venturesome Luke Skywalker and dashing captain Han Solo team together with the loveable robot duo R2-D2 and C-3PO to rescue the beautiful princess and restore peace and justice in the Empire.', 'en', 126.393695, 8.1, 'Adventure Action Science Fiction', 'George Lucas', 'Mark Hamill Harrison Ford Carrie Fisher'),
(12, 'father son relationship harbor underwater fish tank great barrier reef missing child aftercreditsstinger duringcreditsstinger short term memory loss clownfish father son reunion protective father', 'Finding Nemo', 'Nemo, an adventurous young clownfish, is unexpectedly taken from his Great Barrier Reef home to a dentist\'s office aquarium. It\'s up to his worrisome father Marlin and a friendly but forgetful fish Dory to bring Nemo home -- meeting vegetarian sharks, surfer dude turtles, hypnotic jellyfish, hungry seagulls, and more along the way.', 'en', 85.688789, 7.6, 'Animation Family', 'Andrew Stanton', 'Albert Brooks Ellen DeGeneres Alexander Gould'),
(13, 'vietnam veteran hippie mentally disabled running based on novel vietnam vietnam war friendship love family relationships bully mother son relationship military hugging shrimping wounded soldier flashback park bench amputee', 'Forrest Gump', 'A man with a low IQ has accomplished great things in his life and been present during significant historic events - in each case, far exceeding what anyone imagined he could do. Yet, despite all the things he has attained, his one true love eludes him. \'Forrest Gump\' is the story of a man who rose above his challenges, and who proved that determination, courage, and love are more important than ability.', 'en', 138.133331, 8.2, 'Comedy Drama Romance', 'Robert Zemeckis', 'Tom Hanks Robin Wright Gary Sinise'),
(14, 'male nudity female nudity adultery midlife crisis coming out first time camcorder virgin nudity film maker estate agent satire loneliness dark comedy suburbia coming of age marijuana exercise parent child relationship bittersweet affair', 'American Beauty', 'Lester Burnham, a depressed suburban father in a mid-life crisis, decides to turn his hectic life around after developing an infatuation with his daughter\'s attractive friend.', 'en', 80.878605, 7.9, 'Drama', 'Sam Mendes', 'Kevin Spacey Annette Bening Thora Birch'),
(18, 'clone taxi cyborg egypt future stowaway space travel race against time arms dealer love alien priest end of the world good vs evil shootout police chase cab driver new york city space opera military opera singer resort hotel ancient astronaut archeologist ancient evil cruise liner', 'The Fifth Element', 'In 2257, a taxi driver is unintentionally given the task of saving a young girl who is part of the key that will ensure the survival of humanity.', 'en', 109.528572, 7.3, 'Adventure Fantasy Action Thriller Science Fiction', 'Luc Besson', 'Bruce Willis Gary Oldman Ian Holm'),
(20, 'farewell responsability dying and death night shift daughter secret love mother daughter relationship woman director', 'My Life Without Me', 'A Pedro Almodovar production in which a fatally ill mother with only two months to live creates a list of things she wants to do before she dies with out telling her family of her illness.', 'en', 7.958831, 7.2, 'Drama Romance', 'Isabel Coixet', 'Sarah Polley Amanda Plummer Scott Speedman'),
(22, 'exotic island blacksmith east india trading company gold marriage proposal mutiny jamaica skeleton daughter governor wooden eye gold coin pirate alcoholic swashbuckler caribbean aftercreditsstinger pirate ship capuchin monkey tortuga', 'Pirates of the Caribbean: The Curse of the Black Pearl', 'Jack Sparrow, a freewheeling 17th-century pirate who roams the Caribbean Sea, butts heads with a rival pirate bent on pillaging the village of Port Royal. When the governor\'s daughter is kidnapped, Sparrow decides to help the girl\'s love save her. But their seafaring mission is hardly simple.', 'en', 271.972889, 7.5, 'Adventure Fantasy Action', '', 'Johnny Depp Geoffrey Rush Orlando Bloom'),
(24, 'japan coma martial arts kung fu underworld yakuza sword bride revenge gore female yakuza blood wedding samurai sword part animation', 'Kill Bill: Vol. 1', 'An assassin is shot at the altar by her ruthless employer, Bill and other members of their assassination circle – but \'The Bride\' lives to plot her vengeance. Setting out for some payback, she makes a death list and hunts down those who wronged her, saving Bill for last.', 'en', 79.754966, 7.7, 'Action Crime', 'Quentin Tarantino', 'Uma Thurman Lucy Liu Vivica A. Fox'),
(25, 'sniper marine corps saudi arabia petrol golf war u.s. marine', 'Jarhead', 'Jarhead is a film about a US Marine Anthony Swofford’s experience in the Gulf War. After putting up with an arduous boot camp, Swafford and his unit are sent to the Persian Gulf where they are earger to fight but are forced to stay back from the action. Meanwhile Swofford gets news of his girlfriend is cheating on him. Desperately he wants to kill someone and finally put his training to use.', 'en', 32.227223, 6.6, 'Drama War', 'Sam Mendes', 'Jamie Foxx Jake Gyllenhaal Scott MacDonald'),
(28, 'guerrilla river vietnam vietcong cambodia army insanity tribe green beret jungle apocalypse death napalm', 'Apocalypse Now', 'At the height of the Vietnam war, Captain Benjamin Willard is sent on a dangerous mission that, officially, \"does not exist, nor will it ever exist.\" His goal is to locate - and eliminate - a mysterious Green Beret Colonel named Walter Kurtz, who has been leading his personal army on illegal guerrilla missions into enemy territory.', 'en', 49.973462, 8, 'Drama War', 'Francis Ford Coppola', 'Martin Sheen Marlon Brando Robert Duvall'),
(35, 'father son relationship lake springfield the simpsons duff beer garbage pig pollution environmental protection agency quarantine alcoholism love alaska dysfunctional family dysfunctional marriage ecology saving lives first love duringcreditsstinger donuts', 'The Simpsons Movie', 'After Homer accidentally pollutes the town\'s water supply, Springfield is encased in a gigantic dome by the EPA and the Simpsons are declared fugitives.', 'en', 46.875375, 6.9, 'Animation Comedy Family', 'David Silverman', 'Dan Castellaneta Julie Kavner Nancy Cartwright'),
(38, 'deja vu regret jealousy amnesia dream operation relationship problems love memory brainwashing relationship heartbreak nonlinear timeline love story bittersweet', 'Eternal Sunshine of the Spotless Mind', 'Joel Barish, heartbroken that his girlfriend underwent a procedure to erase him from her memory, decides to do the same. However, as he watches his memories of her fade away, he realises that he still loves her, and may be too late to correct his mistake.', 'en', 56.481487, 7.9, 'Science Fiction Drama Romance', 'Michel Gondry', 'Jim Carrey Kate Winslet Kirsten Dunst'),
(55, 'homeless person mexico city daughter secret love dogfight money dog nonlinear timeline multiple storylines new mexican cinema', 'Amores perros', 'Three different people in Mexico City are catapulted into dramatic and unforeseen circumstances in the wake of a terrible car crash: a young punk stumbles into the sinister underground world of dog fighting; an injured supermodel\'s designer pooch disappears into the apartment\'s floorboards; and an ex-radical turned hit man rescues a gunshot Rotweiler.', 'es', 23.281616, 7.6, 'Drama Thriller', 'Alejandro González Iñárritu', 'Gael García Bernal Vanessa Bauche Goya Toledo'),
(58, 'witch fortune teller bondage exotic island monster captain card game east india trading company compass ship daughter pirate swashbuckler aftercreditsstinger', 'Pirates of the Caribbean: Dead Man\'s Chest', 'Captain Jack Sparrow works his way out of a blood debt with the ghostly Davey Jones, he also attempts to avoid eternal damnation.', 'en', 145.847379, 7, 'Adventure Fantasy Action', 'Gore Verbinski', 'Johnny Depp Orlando Bloom Keira Knightley'),
(59, 'robbery double life dual identity small town indiana distrust fight self-defense marriage family relationships mistaken identity diner lawyer mobster violence attempted robbery', 'A History of Violence', 'An average family is thrust into the spotlight after the father commits a seemingly self-defense murder at his diner.', 'en', 34.628738, 6.9, 'Drama Thriller Crime', 'David Cronenberg', 'Viggo Mortensen Maria Bello Heidi Hayes'),
(62, 'moon jupiter artificial intelligence man vs machine technology super computer human being space travel space mission moon base astronaut evolution monolith space station', '2001: A Space Odyssey', 'Humanity finds a mysterious object buried beneath the lunar surface and sets off to find its origins with the help of HAL 9000, the world\'s most advanced super computer.', 'en', 86.201184, 7.9, 'Science Fiction Mystery Adventure', 'Stanley Kubrick', 'Keir Dullea Gary Lockwood William Sylvester'),
(65, 'individual street gang adolescence rap music hip-hop rhyme battle trailer park ethnic stereotype single detroit eminem', '8 Mile', 'The setting is Detroit in 1995. The city is divided by 8 Mile, a road that splits the town in half along racial lines. A young white rapper, Jimmy \"B-Rabbit\" Smith Jr. summons strength within himself to cross over these arbitrary boundaries to fulfill his dream of success in hip hop. With his pal Future and the three one third in place, all he has to do is not choke.', 'en', 32.798571, 6.8, 'Drama', 'Curtis Hanson', 'Eminem Mekhi Phifer Brittany Murphy'),
(66, 'corruption assassination washington d.c. rape white house usa president daughter government suspense secret service secret service agent', 'Absolute Power', 'A master thief coincidentally is robbing a house where a murder in which the President of The United States is involved occurs in front of his eyes. He is forced to run yet may hold evidence that could convict the President. A political thriller from and starring Clint Eastwood and based on a novel by David Baldacci.', 'en', 13.576765, 6.4, 'Crime Drama Thriller', 'Clint Eastwood', 'Clint Eastwood Gene Hackman Ed Harris'),
(69, 'germany prison music record adultery country music guitar loss of brother concert marriage single accident 1960s', 'Walk the Line', 'A chronicle of country music legend Johnny Cash\'s life, from his early days on an Arkansas cotton farm to his rise to fame with Sun Records in Memphis, where he recorded alongside Elvis Presley, Jerry Lee Lewis and Carl Perkins.', 'en', 35.580032, 7.3, 'Drama Music Romance', 'James Mangold', 'Joaquin Phoenix Reese Witherspoon Ginnifer Goodwin'),
(70, 'transporter suicide attempt strong woman boxer dying and death stroke of fate training advancement sport female protagonist boxing trainer determination', 'Million Dollar Baby', 'Despondent over a painful estrangement from his daughter, trainer Frankie Dunn isn\'t prepared for boxer Maggie Fitzgerald to enter his life. But Maggie\'s determined to go pro and to convince Dunn and his cohort to help her.', 'en', 70.456012, 7.7, 'Drama', 'Clint Eastwood', 'Clint Eastwood Hilary Swank Morgan Freeman'),
(71, 'workers\' quarter dancing class strike northern england scholarship ballet', 'Billy Elliot', 'Set against the background of the 1984 Miner\'s Strike, Billy Elliot is an 11 year old boy who stumbles out of the boxing ring and onto the ballet floor. He faces many trials and triumphs as he strives to conquer his family\'s set ways, inner conflict, and standing on his toes!', 'en', 20.428237, 7.4, 'Drama Comedy Music', '', 'Jamie Bell Julie Walters Jean Heywood'),
(73, 'usa neo-nazi prison skinhead brother brother relationship rape fascism brother basketball jail school swastika los angeles family hate neo nazism xenophobia interracial friendship nazism prison rape', 'American History X', 'Derek Vineyard is paroled after serving 3 years in prison for killing two thugs who tried to break into/steal his truck. Through his brother, Danny Vineyard\'s narration, we learn that before going to prison, Derek was a skinhead and the leader of a violent white supremacist gang that committed acts of racial crime throughout L.A. and his actions greatly influenced Danny. Reformed and fresh out of prison, Derek severs contact with the gang and becomes determined to keep Danny from going down the same violent path as he did.', 'en', 73.567232, 8.2, 'Drama', 'Tony Kaye', 'Edward Norton Edward Furlong Beverly D\'Angelo'),
(74, 'post traumatic stress  disorder new jersey airplane dystopia daughter apocalypse alien invasion human subjugation', 'War of the Worlds', 'Ray Ferrier is a divorced dockworker and less-than-perfect father. Soon after his ex-wife and her new husband drop of his teenage son and young daughter for a rare weekend visit, a strange and powerful lightning storm touches down.', 'en', 48.572726, 6.2, 'Adventure Thriller Science Fiction', 'Steven Spielberg', 'Tom Cruise Dakota Fanning Miranda Otto'),
(75, 'saving the world total destruction white house mars usa president cataclysm lasergun ambassador congress pest flying saucer', 'Mars Attacks!', '\'We come in peace\' is not what those green men from Mars mean when they invade our planet, armed with irresistible weapons and a cruel sense of humor.  This star studded cast must play victim to the alien’s fun and games in this comedy homage to science fiction films of the \'50s and \'60s.', 'en', 44.090535, 6.1, 'Comedy Fantasy Science Fiction', 'Tim Burton', 'Jack Nicholson Glenn Close Annette Bening'),
(76, 'dialogue sunrise talking soulmates walking austria traveller danube bittersweet romantic vienna', 'Before Sunrise', 'A dialogue marathon of a film, this fairytale love story of an American boy and French girl. During a day and a night together in Vienna their two hearts collide.', 'en', 23.672571, 7.7, 'Drama Romance', 'Richard Linklater', 'Ethan Hawke Julie Delpy Andrea Eckert'),
(77, 'individual insulin tattoo waitress amnesia motel insurance salesman revenge memory loss polaroid flashback neo-noir', 'Memento', 'Suffering short-term memory loss after a head injury, Leonard Shelby embarks on a grim quest to find the lowlife who murdered his wife in this gritty, complex thriller that packs more knots than a hangman\'s noose. To carry out his plan, Shelby snaps Polaroids of people and places, jotting down contextual notes on the backs of photos to aid in his search and jog his memory. He even tattoos his own body in a desperate bid to remember.', 'en', 60.715151, 8.1, 'Mystery Thriller', 'Christopher Nolan', 'Guy Pearce Carrie-Anne Moss Joe Pantoliano'),
(78, 'artificial intelligence man vs machine cyborg bounty hunter android dystopia genetics fugitive cyberpunk los angeles tech noir neo-noir', 'Blade Runner', 'In the smog-choked dystopian Los Angeles of 2019, blade runner Rick Deckard is called out of retirement to terminate a quartet of replicants who have escaped to Earth seeking their creator for a way to extend their short life spans.', 'en', 94.056131, 7.9, 'Science Fiction Drama Thriller', 'Ridley Scott', 'Harrison Ford Rutger Hauer Sean Young'),
(79, 'countryside loss of lover right and justice patriot', 'Hero', 'One man defeated three assassins who sought to murder the most powerful warlord in pre-unified China.', 'zh', 23.607392, 7.2, 'Drama Adventure Action History', 'Zhang Yimou', 'Jet Li Tony Leung Chiu-Wai Maggie Cheung'),
(80, 'paris journalist dialogue talking soulmates walking bookshop love of one\'s life author', 'Before Sunset', 'Nine years ago two strangers met by chance and spent a night in Vienna that ended before sunrise. They are about to meet for the first time since. Now they have one afternoon to find out if they belong together.', 'en', 14.799323, 7.6, 'Drama Romance', 'Richard Linklater', 'Ethan Hawke Julie Delpy Vernon Dobtcheff'),
(83, 'diving cataclysm nightmare panic red sea primal fear scuba diving shark scuba', 'Open Water', 'Two divers are left out at sea without a boat. There’s nothing but water for miles, unless they look at what’s underneath them...', 'en', 15.611857, 5.4, 'Drama Thriller', 'Chris Kentis', 'Blanchard Ryan Daniel Travis Saul Stein'),
(85, 'saving the world riddle nepal himalaya cairo moses egypt whip treasure medallion leather jacket nazis hat mediterranean ark of the covenant ten commandments treasure hunt excavation swastika archaeologist indiana jones archeology ', 'Raiders of the Lost Ark', 'When Dr. Indiana Jones – the tweed-suited professor who just happens to be a celebrated archaeologist – is hired by the government to locate the legendary Ark of the Covenant, he finds himself up against the entire Nazi regime.', 'en', 68.159596, 7.7, 'Adventure Action', '', 'Harrison Ford Karen Allen Paul Freeman'),
(87, 'riddle treasure heart skeleton treasure hunt torture violence monkey cult film archaeologist thuggee conveyor belt mine car rope bridge belching child driving a car eating brains splits indiana jones archeology ', 'Indiana Jones and the Temple of Doom', 'After arriving in India, Indiana Jones is asked by a desperate village to find a mystical stone. He agrees – and stumbles upon a secret cult plotting a terrible plan in the catacombs of an ancient palace.', 'en', 66.976776, 7.1, 'Adventure Action', '', 'Harrison Ford Kate Capshaw Jonathan Ke Quan'),
(89, 'saving the world venice holy grail library riddle father son relationship whip treasure nazis entrapment crusader treasure hunt escape panzer order of the templars archaeologist indiana jones archeology ', 'Indiana Jones and the Last Crusade', 'When Dr. Henry Jones Sr. suddenly goes missing while pursuing the Holy Grail, eminent archaeologist Indiana must team up with Marcus Brody, Sallah and Elsa Schneider to follow in his father\'s footsteps and stop the Nazis from recovering the power of eternal life.', 'en', 80.972475, 7.6, 'Adventure Action', '', 'Harrison Ford Sean Connery Denholm Elliott'),
(90, 'california showdown undercover strip club investigation weapon police smuggling swimming pool gunfight mansion los angeles foot chase art gallery car chase warehouse beverly hills buddy comedy country club maverick cop detroit michigan damsel in distress bar fight', 'Beverly Hills Cop', 'Tough-talking Detroit cop Axel Foley heads to the rarified world of Beverly Hills in his beat-up Chevy Nova to investigate a friend\'s murder. But soon, he realizes he\'s stumbled onto something much more complicated. Bungling rookie detective Billy Rosewood joins the fish-out-of-water Axel and shows him the West Los Angeles ropes.', 'en', 29.843818, 6.8, 'Action Comedy Crime', 'Martin Brest', 'Eddie Murphy Judge Reinhold John Ashton'),
(95, 'saving the world paris moon cataclysm asteroid self sacrifice nasa space marine loss of father daughter space wedding astronaut eiffel tower paris duringcreditsstinger disaster movie space centre', 'Armageddon', 'When an asteroid threatens to collide with Earth, NASA honcho Dan Truman determines the only way to stop it is to drill into its surface and detonate a nuclear bomb. This leads him to renowned driller Harry Stamper, who agrees to helm the dangerous space mission provided he can bring along his own hotshot crew. Among them is the cocksure A.J. who Harry thinks isn\'t good enough for his daughter, until the mission proves otherwise.', 'en', 58.485967, 6.4, 'Action Thriller Science Fiction Adventure', '', 'Bruce Willis Billy Bob Thornton Ben Affleck'),
(96, 'smuggling of arms detective intensive care undercover strip club armored car investigation police swimming pool sequel shootout gunfight los angeles explosion violence car chase detroit horse track beverly hills buddy cop oil field cement truck playboy mansion shooting range', 'Beverly Hills Cop II', 'Detroit cop, Axel Foley heads for the land of sunshine and palm trees to find out who shot police Captain Andrew Bogomil. Thanks to a couple of old friends, Axel\'s investigation uncovers a series of robberies masterminded by a heartless weapons kingpin – and the chase is on.', 'en', 25.28436, 6.1, 'Action Comedy Crime', '', 'Eddie Murphy Judge Reinhold John Ashton'),
(98, 'rome gladiator arena senate roman empire emperor slavery battlefield blood ancient world father daughter relationship combat mother son relationship dream sequence chariot philosopher barbarian horde 2nd century successor', 'Gladiator', 'In the year 180, the death of emperor Marcus Aurelius throws the Roman Empire into chaos. Maximus is one of the Roman army\'s most capable and trusted generals and a key advisor to the emperor. As Marcus\' devious son Commodus ascends to the throne, Maximus is set to be executed. He escapes, but is captured by slave traders. Renamed Spaniard and forced to become a gladiator, Maximus must battle to the death with other men for the amusement of paying audiences. His battle skills serve him well, and he becomes one of the most famous and admired men to fight in the Colosseum. Determined to avenge himself against the man who took away his freedom and laid waste to his family, Maximus believes that he can use his fame and skill in the ring to avenge the loss of his family and former glory. As the gladiator begins to challenge his rule, Commodus decides to put his own fighting mettle to the test by squaring off with Maximus in a battle to the death.', 'en', 95.301296, 7.9, 'Action Drama Adventure', 'Ridley Scott', 'Russell Crowe Joaquin Phoenix Connie Nielsen'),
(103, 'vietnam veteran taxi obsession drug dealer night shift vigilante alienation misanthrope shot to death illegal prostitution loner', 'Taxi Driver', 'A mentally unstable Vietnam War veteran works as a night-time taxi driver in New York City where the perceived decadence and sleaze feeds his urge for violent action, attempting to save a preadolescent prostitute in the process.', 'en', 58.845025, 8, 'Crime Drama', 'Martin Scorsese', 'Robert De Niro Cybill Shepherd Harvey Keitel'),
(105, 'clock tower car race terrorist delorean lightning guitar plutonium sports car inventor journey in the past time travel race against time partner misfit mad scientist fish out of water teenage love destiny hidden identity odd couple escapade disorder chases and races love and romance teenage life misfit partners changing the past or future getting home inventions and discoveries', 'Back to the Future', 'Eighties teenager Marty McFly is accidentally sent back in time to 1955, inadvertently disrupting his parents\' first meeting and attracting his mother\'s romantic interest. Marty must repair the damage to history by rekindling his parents\' romance and - with the help of his eccentric inventor friend Doc Brown - return to 1985.', 'en', 76.603233, 8, 'Adventure Comedy Science Fiction Family', 'Robert Zemeckis', 'Michael J. Fox Christopher Lloyd Lea Thompson'),
(106, 'central and south america predator alien stalking invisible commando 3d', 'Predator', 'Dutch and his group of commandos are hired by the CIA to rescue downed airmen from guerillas in a Central American jungle. The mission goes well but as they return they find that something is hunting them. Nearly invisible, it blends in with the forest, taking trophies from the bodies of its victims as it goes along. Occasionally seeing through its eyes, the audience sees it is an intelligent alien hunter, hunting them for sport, killing them off one at a time.', 'en', 50.009408, 7.3, 'Science Fiction Action Adventure Thriller', '', 'Arnold Schwarzenegger Carl Weathers Elpidia Carrillo'),
(107, 'gypsy bare knuckle boxing slang trailer park pig sport receiving of stolen goods cockney accent diamond pikey', 'Snatch', 'The second film from British director Guy Ritchie. Snatch tells an obscure story similar to his first fast-paced crazy character-colliding filled film “Lock, Stock and Two Smoking Barrels.” There are two overlapping stories here – one is the search for a stolen diamond, and the other about a boxing promoter who’s having trouble with a psychotic gangster.', 'en', 53.595686, 7.7, 'Thriller Crime', '', 'Jason Statham Brad Pitt Vinnie Jones'),
(111, 'miami corruption capitalism cuba prohibition brother sister relationship loss of sister cocaine cult film bitterness', 'Scarface', 'After getting a green card in exchange for assassinating a Cuban government official, Tony Montana stakes a claim on the drug trade in Miami. Viciously murdering anyone who stands in his way, Tony eventually becomes the biggest drug lord in the state, controlling nearly all the cocaine that comes through Miami. But increased pressure from the police, wars with Colombian drug cartels and his own drug-fueled paranoia serve to fuel the flames of his eventual downfall.', 'en', 70.105981, 8, 'Action Crime Drama Thriller', 'Brian De Palma', 'Al Pacino Steven Bauer Michelle Pfeiffer'),
(116, 'love triangle london england upper class adultery tennis river thames love wealth lust instructor gold digger social climbing actress', 'Match Point', 'Match Point is Woody Allen’s satire of the British High Society and the ambition of a young tennis instructor to enter into it. Yet when he must decide between two women - one assuring him his place in high society, and the other that would bring him far from it - palms start to sweat and a dark psychological match in his head begins.', 'en', 30.669913, 7.3, 'Drama Thriller Crime Romance', 'Woody Allen', 'Jonathan Rhys Meyers Scarlett Johansson Emily Mortimer'),
(117, 'white suit al capone tough cop treasury agent untouchable tax evasion jury tampering rule of law rooftop chase cutting face while shaving 1930s', 'The Untouchables', 'Young Treasury Agent Elliot Ness arrives in Chicago and is determined to take down Al Capone, but it\'s not going to be easy because Capone has the police in his pocket. Ness meets Jimmy Malone, a veteran patrolman and probably the most honorable one on the force. He asks Malone to help him get Capone, but Malone warns him that if he goes after Capone, he is going to war.', 'en', 38.272889, 7.6, 'Crime Drama History Thriller', 'Brian De Palma', 'Kevin Costner Sean Connery Charles Martin Smith'),
(118, 'london england father son relationship chocolate factory worker based on novel parents kids relationship candy overweight child grandfather grandson relationship teacher', 'Charlie and the Chocolate Factory', 'A young boy wins a tour through the most magnificent chocolate factory in the world, led by the world\'s most unusual candy maker.', 'en', 53.905592, 6.7, 'Adventure Comedy Family Fantasy', 'Tim Burton', 'Johnny Depp Freddie Highmore David Kelly'),
(120, 'elves dwarves orcs middle-earth (tolkien) hobbit based on novel mountains fireworks castle volcano password death of a friend uncle mirror wizard sword and sorcery', 'The Lord of the Rings: The Fellowship of the Ring', 'Young hobbit Frodo Baggins, after inheriting a mysterious ring from his uncle Bilbo, must leave his home in order to keep it from falling into the hands of its evil creator. Along the way, a fellowship is formed to protect the ringbearer and make sure that the ring arrives at its final destination: Mt. Doom, the only place where it can be destroyed.', 'en', 138.049577, 8, 'Adventure Fantasy Action', '', 'Elijah Wood Ian McKellen Cate Blanchett'),
(121, 'elves orcs middle-earth (tolkien) hobbit based on novel explosive cave fort army mission attack guide wizard ring sword and sorcery', 'The Lord of the Rings: The Two Towers', 'Frodo and Sam are trekking to Mordor to destroy the One Ring of Power while Gimli, Legolas and Aragorn search for the orc-captured Merry and Pippin. All along, nefarious wizard Saruman awaits the Fellowship members at the Orthanc Tower in Isengard.', 'en', 106.914973, 8, 'Adventure Fantasy Action', '', 'Elijah Wood Ian McKellen Viggo Mortensen'),
(122, 'elves orcs middle-earth (tolkien) based on novel suspicion bravery war honor troll brutality violence ghost end of trilogy quest sword and sorcery', 'The Lord of the Rings: The Return of the King', 'Aragorn is revealed as the heir to the ancient kings as he, Gandalf and the other members of the broken fellowship struggle to save Gondor from Sauron\'s forces. Meanwhile, Frodo and Sam bring the ring closer to the heart of Mordor, the dark lord\'s realm.', 'en', 123.630332, 8.1, 'Adventure Fantasy Action', 'Peter Jackson', 'Elijah Wood Ian McKellen Viggo Mortensen'),
(128, 'fight wolf village and town iron pan wild boar territory friendship princess good vs evil anime', 'Princess Mononoke', 'Ashitaka, a prince of the disappearing Ainu tribe, is cursed by a demonized boar god and must journey to the west to find a cure. Along the way, he encounters San, a young human woman fighting to protect the forest, and Lady Eboshi, who is trying to destroy it. Ashitaka must find a way to bring balance to this conflict.', 'ja', 60.732738, 8.2, 'Adventure Fantasy Animation', 'Hayao Miyazaki', 'Yōji Matsuda Yuriko Ishida Yūko Tanaka'),
(129, 'witch parents kids relationship magic twilight darkness village and town bath house pig ghost world biology train amusement park yokai japanese mythology anime', 'Spirited Away', 'A ten year old girl who wanders away from her parents along a path that leads to a world ruled by strange and unusual monster-like animals. Her parents have been changed into pigs along with others inside a bathhouse full of these creatures. Will she ever see the world how it once was?', 'ja', 118.968562, 8.3, 'Fantasy Adventure Animation Family', 'Hayao Miyazaki', 'Rumi Hiiragi Miyu Irino Mari Natsuki'),
(134, 'prophecy southern usa music record country music mississippi seduction musical fraud', 'O Brother, Where Art Thou?', 'In the deep south during the 1930s, three escaped convicts search for hidden treasure while a relentless lawman pursues them. On their journey they come across many comical characters and incredible situations. Based upon Homer\'s \'Odyssey\'.', 'en', 39.742009, 7.3, 'Action Adventure Comedy', '', 'George Clooney John Turturro Tim Blake Nelson'),
(141, 'parents kids relationship airplane time travel school presentation school performance suburbia vision morality teenager', 'Donnie Darko', 'After narrowly escaping a bizarre accident, a troubled teenager is plagued by visions of a large bunny rabbit that manipulates him to commit a series of crimes.', 'en', 61.210016, 7.7, 'Fantasy Drama Mystery', 'Richard Kelly', 'Jake Gyllenhaal Jena Malone Patrick Swayze'),
(142, 'gay countryside homophobia loss of lover wyoming rodeo father murder horseback riding intolerance daughter marriage crisis secret love cowboy star crossed lovers', 'Brokeback Mountain', 'Brokeback Mountain is an Ang Lee film about two modern day cowboys who meet on a shepherding job in the summer of ’63. The two share a raw and powerful summer together that turns into a life long relationship conflicting with the lives they are supposed to live.', 'en', 44.135568, 7.5, 'Drama Romance', '', 'Heath Ledger Jake Gyllenhaal Randy Quaid'),
(146, 'flying martial arts taskmaster comb tiger desert thief theft female martial artist', 'Crouching Tiger, Hidden Dragon', 'Two warriors in pursuit of a stolen sword and a notorious fugitive are led to an impetuous, physically-skilled, teenage nobleman\'s daughter, who is at a crossroads in her life.', 'zh', 45.742254, 7.2, 'Adventure Drama Action Romance', 'Ang Lee', 'Chow Yun-fat Michelle Yeoh Zhang Ziyi'),
(149, 'saving the world total destruction megacity street gang underground general stadium experiment atomic bomb mutation dystopia army cyberpunk anime motorcycle gangs', 'Akira', 'Childhood friends Tetsuo and Kaneda are pulled into the post-apocalyptic underworld of Neo-Tokyo and forced to fight for their very survival. Kaneda is a bike gang leader, and Tetsuo is a member of a tough motorcycle crew who becomes involved in a covert government project called Akira. But a bloody battle ensues when Kaneda sets out to save his friend.', 'ja', 39.338097, 7.8, 'Science Fiction Animation', 'Katsuhiro Ōtomo', 'Mitsuo Iwata Nozomu Sasaki Mami Koyama'),
(152, 'artificial intelligence uss enterprise starfleet san francisco self sacrifice spacecraft klingon vulcan space opera', 'Star Trek: The Motion Picture', 'When a destructive space entity is spotted approaching Earth, Admiral Kirk resumes command of the Starship Enterprise in order to intercept, examine, and hopefully stop it.', 'en', 24.616634, 6.2, 'Science Fiction Adventure Mystery', 'Robert Wise', 'William Shatner Leonard Nimoy DeForest Kelley'),
(153, 'upper class hotel room age difference commercial karaoke homesickness culture clash jet lag pop star unsociability aftercreditsstinger woman director', 'Lost in Translation', 'Two lost souls visiting Tokyo -- the young, neglected wife of a photographer and a washed-up movie star shooting a TV commercial -- find an odd solace and pensive freedom to be real in each other\'s company, away from their lives in America.', 'en', 45.66662, 7.3, 'Drama', '', 'Bill Murray Scarlett Johansson Anna Faris'),
(155, 'dc comics crime fighter secret identity scarecrow sadism chaos gotham city vigilante joker superhero based on comic book tragic hero organized crime criminal mastermind district attorney imax super villain super powers batman', 'The Dark Knight', 'Batman raises the stakes in his war on crime. With the help of Lt. Jim Gordon and District Attorney Harvey Dent, Batman sets out to dismantle the remaining criminal organizations that plague the streets. The partnership proves to be effective, but they soon find themselves prey to a reign of chaos unleashed by a rising criminal mastermind known to the terrified citizens of Gotham as the Joker.', 'en', 187.322927, 8.2, 'Drama Action Crime Thriller', '', 'Christian Bale Heath Ledger Aaron Eckhart'),
(157, '', 'Star Trek III: The Search for Spock', 'Admiral Kirk and his bridge crew risk their careers stealing the decommissioned Enterprise to return to the restricted Genesis planet to recover Spock\'s body.', 'en', 15.314027, 6.4, 'Science Fiction Action Adventure Thriller', 'Leonard Nimoy', 'William Shatner Leonard Nimoy DeForest Kelley'),
(161, 'prison pickpocket strip club con artist atlantic city cockney accent las vegas card dealer explosives expert black and white scene male salt lake city utah', 'Ocean\'s Eleven', 'Less than 24 hours into his parole, charismatic thief Danny Ocean is already rolling out his next plan: In one night, Danny\'s hand-picked crew of specialists will attempt to steal more than $150 million from three Las Vegas casinos. But to score the cash, Danny risks his chances of reconciling with ex-wife, Tess.', 'en', 60.929352, 7.2, 'Thriller Crime', '', 'George Clooney Brad Pitt Matt Damon'),
(162, 'underdog love at first sight hairdresser small town scissors inventor burglar unsociability', 'Edward Scissorhands', 'A small suburban town receives a visit from a castaway unfinished science experiment named Edward.', 'en', 47.51363, 7.5, 'Fantasy Drama Romance', 'Tim Burton', 'Johnny Depp Winona Ryder Dianne Wiest'),
(163, 'sequel fabergé egg dutch eastindian company second part golden egg goon', 'Ocean\'s Twelve', 'Danny Ocean reunites with his old flame and the rest of his merry band of thieves in carrying out three huge heists in Rome, Paris and Amsterdam – but a Europol agent is hot on their heels.', 'en', 76.840712, 6.4, 'Thriller Crime', 'Steven Soderbergh', 'George Clooney Brad Pitt Catherine Zeta-Jones'),
(165, 'skateboarding flying car car race delorean lightning almanac inventor time travel sequel diner alternate history teenager electric guitar walking cane high school dance hoverboard video phone', 'Back to the Future Part II', 'Marty and Doc are at it again in this wacky sequel to the 1985 blockbuster as the time-traveling duo head to 2015 to nip some McFly family woes in the bud. But things go awry thanks to bully Biff Tannen and a pesky sports almanac. In a last-ditch attempt to set things straight, Marty finds himself bound for 1955 and face to face with his teenage parents -- again.', 'en', 43.345252, 7.4, 'Adventure Comedy Family Science Fiction', 'Robert Zemeckis', 'Michael J. Fox Christopher Lloyd Lea Thompson'),
(167, 'robbery dream hypnosis investigation murder alien hospital planet patient medication psychiatrist science claim doubt mental help', 'K-PAX', 'Prot is a patient at a mental hospital who claims to be from a far away Planet. His psychiatrist tries to help him, only to begin to doubt his own explanations.', 'en', 30.920075, 7.1, 'Drama Science Fiction', '', 'Jeff Bridges Kevin Spacey Mary McCormack'),
(168, 'saving the world san francisco uss enterprise-a time travel whale marine biologist vulcan space opera', 'Star Trek IV: The Voyage Home', 'Fugitives of the Federation for their daring rescue of Spock from the doomed Genesis Planet, Admiral Kirk (William Shatner) and his crew begin their journey home to face justice for their actions. But as they near Earth, they find it at the mercy of a mysterious alien presence whose signals are slowly destroying the planet. In a desperate attempt to answer the call of the probe, Kirk and his crew race back to the late twentieth century. However they soon find the world they once knew to be more alien than anything they\'ve encountered in the far reaches of the galaxy!', 'en', 22.258428, 6.9, 'Science Fiction Adventure', 'Leonard Nimoy', 'William Shatner Leonard Nimoy DeForest Kelley'),
(169, 'predator war on drugs extraterrestrial technology los angeles invisible', 'Predator 2', 'Ten years after a band of mercenaries first battled a vicious alien, the invisible creature from another world has returned to Earth -- and this time, it\'s drawn to the gang-ruled and ravaged city of Los Angeles. When it starts murdering drug dealers, detective-lieutenant Mike Harrigan and his police force set out to capture the creature, ignoring warnings from a mysterious government agent to stay away.', 'en', 27.934978, 5.9, 'Science Fiction Action Thriller', 'Stephen Hopkins', 'Kevin Peter Hall Danny Glover Gary Busey'),
(170, 'london england manchester city submachine gun gas station survivor daughter zombie virus', '28 Days Later', 'Twenty-eight days after a killer virus was accidentally unleashed from a British research facility, a small group of London survivors are caught in a desperate struggle to protect themselves from the infected. Carried by animals and humans, the virus turns those it infects into homicidal maniacs -- and it\'s absolutely impossible to contain.', 'en', 45.490374, 7.1, 'Horror Thriller Science Fiction', '', 'Cillian Murphy Naomie Harris Noah Huntley'),
(172, 'federation starfleet uss enterprise-a sha-ka-ree loss of brother self sacrifice hostage liberation of hostage romulans klingon vulcan space opera', 'Star Trek V: The Final Frontier', 'Capt. Kirk and his crew must deal with Mr. Spock\'s half brother who kidnaps three diplomats and hijacks the Enterprise in his obsessive search for God.', 'en', 19.578249, 5.6, 'Science Fiction Action Adventure Thriller', 'William Shatner', 'William Shatner Leonard Nimoy DeForest Kelley'),
(173, 'diving ocean submarine jules verne captain atlantis deep sea war ship diving suit harpoon ship war scuba diving underwater scuba captain nemo giant  squid', '20,000 Leagues Under the Sea', 'A ship sent to investigate a wave of mysterious sinkings encounters the advanced submarine, the Nautilus, commanded by Captain Nemo.', 'en', 9.358197, 6.8, 'Adventure Drama Science Fiction', 'Richard Fleischer', 'Kirk Douglas James Mason Paul Lukas'),
(174, 'farewell federation starfleet peace conference uss enterprise-a rura penthe court case peace contract plan klingon space opera', 'Star Trek VI: The Undiscovered Country', 'On the eve of retirement, Kirk and McCoy are charged with assassinating the Klingon High Chancellor and imprisoned. The Enterprise crew must help them escape to thwart a conspiracy aimed at sabotaging the last best hope for peace.', 'en', 16.188572, 6.7, 'Science Fiction Action Adventure Thriller', 'Nicholas Meyer', 'William Shatner Leonard Nimoy DeForest Kelley'),
(177, 'holy grail homeless person loss of lover mental disease sense of guilt suppressed past yuppie cynic fantasy self-discovery housebreaking forgiveness gun rampage talk show legend unsociability person running amok', 'The Fisher King', 'Two troubled men face their terrible destinies and events of their past as they join together on a mission to find the Holy Grail and thus to save themselves.', 'en', 16.146572, 7.2, 'Comedy Drama', 'Terry Gilliam', 'Jeff Bridges Robin Williams Mercedes Ruehl'),
(179, 'new york dictator africa destruction of a civilization assassination resistance revenge murder united nations witness to murder fbi agent resistance fighter', 'The Interpreter', 'After Silvia Broome, an interpreter at United Nations headquarters, overhears plans of an assassination, an American Secret Service agent is sent to investigate.', 'en', 18.69984, 6.2, 'Crime Thriller', '', 'Nicole Kidman Sean Penn Catherine Keener'),
(180, 'self-fulfilling prophecy washington d.c. evidence future hologram dystopia murder neo-noir future noir', 'Minority Report', 'John Anderton is a top \'Precrime\' cop in the late-21st century, when technology can predict crimes before they\'re committed. But Anderton becomes the quarry when another investigator targets him for a murder charge.', 'en', 65.948959, 7.1, 'Action Thriller Science Fiction Mystery', 'Steven Spielberg', 'Tom Cruise Colin Farrell Samantha Morton'),
(182, 'berlin corruption nazi background love of one\'s life chauffeur black market missile postwar period war correspondent allied truth murder humanity', 'The Good German', 'An American journalist played by George Clooney arrives in Berlin just after the end of World War Two. He becomes involved in a murder mystery surrounding a dead GI who washes up at a lakeside mansion during the Potsdam negotiations between the Allied powers. Soon his investigation connects with his search for his married pre-war German lover played by Cate Blanchett.', 'en', 5.347936, 5.9, 'War Crime Drama Mystery Romance Thriller', '', 'George Clooney Cate Blanchett Tobey Maguire'),
(186, 'assassination assassin identity sniper mistake in person jew gangster boss gambling debts boss murder sniper rifle fbi agent horse racing gambler slevin caso hoodlum black men', 'Lucky Number Slevin', 'Slevin is mistakenly put in the middle of a personal war between the city’s biggest criminal bosses. Under constant watch, Slevin must try not to get killed by an infamous assassin and come up with an idea of how to get out of his current dilemma. A film with many twists and turns.', 'en', 36.921445, 7.4, 'Drama Thriller Crime Mystery', 'Paul McGuigan', 'Josh Hartnett Bruce Willis Lucy Liu'),
(187, 'dystopia based on comic book held captive based on graphic novel black and white and color black and white scene black and white to color mysterious killer doing the right thing mercedes silhouette neo-noir', 'Sin City', 'Welcome to Sin City. This town beckons to the tough, the corrupt, the brokenhearted. Some call it dark… Hard-boiled. Then there are those who call it home — Crooked cops, sexy dames, desperate vigilantes. Some are seeking revenge, others lust after redemption, and then there are those hoping for a little of both. A universe of unlikely and reluctant heroes still trying to do the right thing in a city that refuses to care.', 'en', 66.003433, 7.2, 'Action Thriller Crime', 'Robert Rodriguez', 'Jessica Alba Devon Aoki Clive Owen'),
(189, 'detective dystopia dominatrix murder suspense twins based on graphic novel dark horse comics neo-noir 3d', 'Sin City: A Dame to Kill For', 'Some of Sin City\'s most hard-boiled citizens cross paths with a few of its more reviled inhabitants.', 'en', 85.428395, 6.3, 'Crime Thriller', 'Robert Rodriguez', 'Mickey Rourke Jessica Alba Josh Brolin'),
(193, 'based on tv series death exploding planet mountain cabin solar system', 'Star Trek: Generations', 'Captain Jean-Luc Picard and the crew of the Enterprise-D find themselves at odds with the renegade scientist Soran who is destroying entire star systems. Only one man can help Picard stop Soran\'s scheme...and he\'s been dead for seventy-eight years.', 'en', 14.779041, 6.4, 'Science Fiction Action Adventure Thriller', '', 'Patrick Stewart Jonathan Frakes Brent Spiner'),
(194, 'paris love triangle ghost train sex-shop shyness montmartre daughter garden gnome journey round the world photography', 'Amélie', 'At a tiny Parisian café, the adorable yet painfully shy Amélie (Audrey Tautou) accidentally discovers a gift for helping others. Soon Amelie is spending her days as a matchmaker, guardian angel, and all-around do-gooder. But when she bumps into a handsome stranger, will she find the courage to become the star of her very own love story?', 'fr', 73.720244, 7.8, 'Comedy Romance', '', 'Audrey Tautou Mathieu Kassovitz Rufus'),
(196, 'railroad robber california delorean indian territory sports car inventor locomotive saloon horseback riding time travel outlaw sequel mad scientist native american western shootout gunfight train wild west cavalry', 'Back to the Future Part III', 'The final installment of the Back to the Future trilogy finds Marty digging the trusty DeLorean out of a mineshaft and looking up Doc in the Wild West of 1885. But when their time machine breaks down, the travelers are stranded in a land of spurs. More problems arise when Doc falls for pretty schoolteacher Clara Clayton, and Marty tangles with Buford Tannen.', 'en', 45.769562, 7.1, 'Adventure Comedy Family Science Fiction', 'Robert Zemeckis', 'Michael J. Fox Christopher Lloyd Mary Steenburgen'),
(197, 'individual scotland in love with enemy legend independence idealism revolt tyranny', 'Braveheart', 'Enraged at the slaughter of Murron, his new bride and childhood love, Scottish warrior William Wallace slays a platoon of the local English lord\'s soldiers. This leads the village to revolt and, eventually, the entire country to rise up against English rule.', 'en', 60.722162, 7.7, 'Action Drama History War', '', 'Mel Gibson Catherine McCormack Sophie Marceau'),
(199, 'federation starfleet borg enterprise-e cyborg montana resistance inventor repayment obsession business start-up space opera', 'Star Trek: First Contact', 'The Borg, a relentless race of cyborgs, are on a direct course for Earth. Violating orders to stay away from the battle, Captain Picard and the crew of the newly-commissioned USS Enterprise E pursue the Borg back in time to prevent the invaders from changing Federation history and assimilating the galaxy.', 'en', 25.6713, 7, 'Science Fiction Action Adventure Thriller', '', 'Patrick Stewart Jonathan Frakes Brent Spiner'),
(200, 'space opera retribution spacecraft officer exploding ship', 'Star Trek: Insurrection', 'When an alien race and factions within Starfleet attempt to take over a planet that has \"regenerative\" properties, it falls upon Captain Picard and the crew of the Enterprise to defend the planet\'s people as well as the very ideals upon which the Federation itself was founded.', 'en', 19.711951, 6.3, 'Science Fiction Action Adventure Thriller', '', 'Patrick Stewart Jonathan Frakes Brent Spiner'),
(201, 'clone assassination ambush federation starfleet enterprise-e romulus android senate self sacrifice telepathy weapon romulans space opera', 'Star Trek: Nemesis', 'En route to the honeymoon of William Riker to Deanna Troi on her home planet of Betazed, Captain Jean-Luc Picard and the crew of the U.S.S. Enterprise receives word from Starfleet that a coup has resulted in the installation of a new Romulan political leader, Shinzon, who claims to seek peace with the human-backed United Federation of Planets. Once in enemy territory, the captain and his crew make a startling discovery: Shinzon is human, a slave from the Romulan sister planet of Remus, and has a secret, shocking relationship to Picard himself.', 'en', 21.605533, 6.1, 'Science Fiction Action Adventure Thriller', '', 'Patrick Stewart Jonathan Frakes Brent Spiner'),
(203, 'epilepsy protection money secret love money redemption', 'Mean Streets', 'A small-time hood must choose from among love, friendship and the chance to rise within the mob.', 'en', 17.002096, 7.2, 'Drama Crime', 'Martin Scorsese', 'Harvey Keitel Robert De Niro David Proval');
INSERT INTO `movies` (`movie_id`, `tags`, `title`, `overview`, `original_language`, `popularity`, `vote_average`, `genres`, `directeur`, `acteurs`) VALUES
(205, 'rwanda refugee refugee camp militia murder slaughter dead body atrocity african cruelty violence united nations genocide in rwanda death', 'Hotel Rwanda', 'Inspired by true events, this film takes place in Rwanda in the 1990s when more than a million Tutsis were killed in a genocide that went mostly unnoticed by the rest of the world. Hotel owner Paul Rusesabagina houses over a thousand refuges in his hotel in attempt to save their lives.', 'en', 28.60542, 7.5, 'Drama History War', 'Terry George', 'Don Cheadle Sophie Okonedo Nick Nolte'),
(207, 'individual philosophy poetry shakespeare professor literature friendship filmes focados em um professor', 'Dead Poets Society', 'At an elite, old-fashioned boarding school in New England, a passionate English teacher inspires his students to rebel against convention and seize the potential of every day, courting the disdain of the stern headmaster.', 'en', 55.458584, 8.1, 'Drama', 'Peter Weir', 'Robin Williams Ethan Hawke Robert Sean Leonard'),
(214, 'brain tumor nudity suffocation mutilation severed foot famous theme shot in the face', 'Saw III', 'Jigsaw has disappeared. Along with his new apprentice Amanda, the puppet-master behind the cruel, intricate games that have terrified a community and baffled police has once again eluded capture and vanished. While city detective scramble to locate him, Doctor Lynn Denlon and Jeff Reinhart are unaware that they are about to become the latest pawns on his vicious chessboard.', 'en', 33.124871, 6.1, 'Horror Thriller Crime', '', 'Tobin Bell Shawnee Smith Angus Macfadyen'),
(215, 'riddle serial killer', 'Saw II', 'When a new murder victim is discovered with all the signs of Jigsaw\'s hand, Detective Eric Matthews begins a full investigation and apprehends Jigsaw with little effort. But for Jigsaw, getting caught is just another part of his plan. Eight more of his victims are already fighting for their lives and now it\'s time for Matthews to join the game...', 'en', 42.187986, 6.3, 'Horror', '', 'Tobin Bell Shawnee Smith Donnie Wahlberg'),
(217, 'saving the world riddle whip treasure mexico city leather jacket machinegun alien phenomenons maya civilization peru treasure hunt nuclear explosion refrigerator archaeologist indiana jones archeology ', 'Indiana Jones and the Kingdom of the Crystal Skull', 'Set during the Cold War, the Soviets – led by sword-wielding Irina Spalko – are in search of a crystal skull which has supernatural powers related to a mystical Lost City of Gold. After being captured and then escaping from them, Indy is coerced to head to Peru at the behest of a young man whose friend – and Indy\'s colleague – Professor Oxley has been captured for his knowledge of the skull\'s whereabouts.', 'en', 75.674458, 5.7, 'Adventure Action', '', 'Harrison Ford Cate Blanchett Shia LaBeouf'),
(218, 'saving the world artificial intelligence rebel cyborg shotgun killer robot sun glasses dystopia car chase laser gun urban setting future war', 'The Terminator', 'In the post-apocalyptic future, reigning tyrannical supercomputers teleport a cyborg assassin known as the \"Terminator\" back to 1984 to kill Sarah Connor, whose unborn son is destined to lead insurgents against 21st century mechanical hegemony. Meanwhile, the human-resistance movement dispatches a lone warrior to safeguard Sarah. Can he stop the virtually indestructible killing machine?', 'en', 74.234793, 7.3, 'Action Thriller Science Fiction', '', 'Arnold Schwarzenegger Michael Biehn Linda Hamilton'),
(219, 'child abuse rape fire sexual abuse madrid secret return solidarity village superstition crime death ghost abusive father', 'Volver', 'Raimunda (Penélope Cruz) works and lives Madrid with her husband Paco and daughter Paula. Her sister Sole (Lola Dueñas) lives nearby and they both miss their mother Irene (Carmen Maura), who died several years ago in a house fire along with their father. A former neighbor from their hometown reports that she has seen the ghost of Irene and both daughters do not believe her. After a murder and a family tragedy, Irene\'s spirit materializes around her daughters to help comfort them.', 'es', 19.747809, 7.3, 'Comedy Drama Romance', 'Pedro Almodóvar', 'Penélope Cruz Carmen Maura Lola Dueñas'),
(226, 'rape sex identity small town love friends murder romance true transgender anger woman director nebraska small town murder transphobia gender identity', 'Boys Don\'t Cry', 'Female born, Teena Brandon adopts his male identity of Brandon Teena and attempts to find himself and love in Nebraska.', 'en', 15.557144, 7.2, 'Crime Drama', 'Kimberly Peirce', 'Hilary Swank Chloë Sevigny Peter Sarsgaard'),
(227, 'street gang children\'s home coming of age gang juvenile delinquent based on young adult novel', 'The Outsiders', 'When two poor greasers, Johnny, and Ponyboy are assaulted by a vicious gang, the socs, and Johnny kills one of the attackers, tension begins to mount between the two rival gangs, setting off a turbulent chain of events.', 'en', 13.455373, 6.9, 'Crime Drama', 'Francis Ford Coppola', 'Matt Dillon Ralph Macchio C. Thomas Howell'),
(231, 'anti terror bomb assassination middle east lebanon cia capitalism globalization loss of son persia war against terror energy policy petrol', 'Syriana', 'The Middle Eastern oil industry is the backdrop of this tense drama, which weaves together numerous story lines. Bennett Holiday is an American lawyer in charge of facilitating a dubious merger of oil companies, while Bryan Woodman, a Switzerland-based energy analyst, experiences both personal tragedy and opportunity during a visit with Arabian royalty. Meanwhile, veteran CIA agent Bob Barnes uncovers an assassination plot with unsettling origins.', 'en', 16.871194, 6.3, 'Drama Thriller', '', 'George Clooney Matt Damon Jeffrey Wright'),
(235, 'based on novel friendship coming of age railroad track story within the story  flipping coin campfire story reference to superman normandy beach child 1950s boys', 'Stand by Me', 'After the death of a friend, a writer recounts a boyhood journey to find the body of a missing boy.', 'en', 51.109279, 7.8, 'Crime Drama', 'Rob Reiner', 'Wil Wheaton River Phoenix Corey Feldman'),
(238, 'italy love at first sight loss of father patriarch organized crime mafia lawyer italian american crime family rise to power mob boss 1940s', 'The Godfather', 'Spanning the years 1945 to 1955, a chronicle of the fictional Italian-American Corleone crime family. When organized crime family patriarch, Vito Corleone barely survives an attempt on his life, his youngest son, Michael steps in to take care of the would-be killers, launching a campaign of bloody revenge.', 'en', 143.659698, 8.4, 'Drama Crime', 'Francis Ford Coppola', 'Marlon Brando Al Pacino James Caan'),
(239, 'chicago witness musician mafia cross dressing band spats all girl band st. valentine\'s day massacre sugar valentine\'s day dressing', 'Some Like It Hot', 'Two musicians witness a mob hit and struggle to find a way out of the city before they are found by the gangsters. Their only opportunity is to join an all-girl band as they leave on a tour. To make their getaway they must first disguise themselves as women, then keep their identities secret and deal with the problems this brings - such as an attractive bandmate and a very determined suitor.', 'en', 39.30982, 8, 'Comedy Romance', 'Billy Wilder', 'Marilyn Monroe Tony Curtis Jack Lemmon'),
(240, 'italo-american cuba vororte melancholy praise revenge mafia lawyer blood corrupt politician bloody body of child man punches woman', 'The Godfather: Part II', 'In the continuing saga of the Corleone crime family, a young Vito Corleone grows up in Sicily and in 1910s New York. In the 1950s, Michael Corleone attempts to expand the family business into Las Vegas, Hollywood and Cuba.', 'en', 105.792936, 8.3, 'Drama Crime', 'Francis Ford Coppola', 'Al Pacino Robert Duvall Diane Keaton'),
(242, 'italy christianity new york assassination italo-american vatican pope confession helicopter daughter lawyer', 'The Godfather: Part III', 'In the midst of trying to legitimize his business dealings in 1979 New York and Italy, aging mafia don, Michael Corleone seeks forgiveness for his sins while taking a young protege under his wing.', 'en', 59.194915, 7.1, 'Crime Drama Thriller', 'Francis Ford Coppola', 'Al Pacino Diane Keaton Andy García'),
(243, 'chicago music record rock and roll record store soul disc jockey pop bruce frederick joseph springsteen record collection', 'High Fidelity', 'When record store owner Rob Gordon gets dumped by his girlfriend, Laura, because he hasn\'t changed since they met, he revisits his top five breakups of all time in an attempt to figure out what went wrong. As Rob seeks out his former lovers to find out why they left, he keeps up his efforts to win Laura back.', 'en', 23.982956, 7, 'Comedy Drama Romance Music', '', 'John Cusack Iben Hjejle Todd Louiso'),
(245, 'london england rock and roll single parent rap music bachelor becoming an adult friendship single', 'About a Boy', 'Will Freeman is a hip Londoner who one day realizes that his friends are all involved with the responsibilities of married life and that leaves him alone in the cold. Passing himself off as a single father, he starts to meet a string of single mums, confident in his ability to leave them behind when they start to ask for a commitment. But Will\'s hope of a continued bachelorhood is interrupted when he meets 12-year old Marcus, in many ways his complete opposite.', 'en', 28.227984, 6.6, 'Drama Comedy Romance', '', 'Hugh Grant Nicholas Hoult Toni Collette'),
