(1989, 'usa kaffeehaus poker lovesickness waitress bar night life night melancholy approach loneliness', 'My Blueberry Nights', 'Elizabeth has just been through a particularly nasty breakup, and now she\'s ready to leave her friends and memories behind as she chases her dreams across the country. In order to support herself on her journey, Elizabeth picks up a series of waitress jobs along the way. As Elizabeth crosses paths with a series of lost souls.', 'en', 10.733761, 6, 'Drama Romance', '', 'Norah Jones Jude Law Natalie Portman'),
(1995, 'treasure buddhist monk planetary configuration angkor wat illuminati william blake treasure hunt archaeologist based on video game archeology ', 'Lara Croft: Tomb Raider', 'English aristocrat Lara Croft is skilled in hand-to-hand combat and in the middle of a battle with a secret society. The shapely archaeologist moonlights as a tomb raider to recover lost antiquities and meets her match in the evil Powell, who\'s in search of a powerful relic.', 'en', 41.498631, 5.7, 'Adventure Fantasy Action Thriller', '', 'Angelina Jolie Jon Voight Iain Glen'),
(1996, 'riddle treasure medallion kenia alexander the great pandora\'s box chinese mafia treasure hunt hong kong archaeologist based on video game archeology ', 'Lara Croft Tomb Raider: The Cradle of Life', 'Lara Croft ventures to an underwater temple in search of the mythological Pandora\'s Box but, after securing it, it is promptly stolen by the villainous leader of a Chinese crime syndicate. Lara must recover the box before the syndicate\'s evil mastermind uses it to construct a weapon of catastrophic capabilities.', 'en', 56.811056, 5.5, 'Action Adventure Fantasy Thriller', '', 'Angelina Jolie Gerard Butler Noah Taylor'),
(1997, 'brother brother relationship loss of brother cambodia chase tiger governor royalty travelling circus archaeologist', 'Two Brothers', 'Two tigers are separated as cubs and taken into captivity, only to be reunited years later as enemies by an explorer (Pearce) who inadvertently forces them to fight each other.', 'en', 8.884318, 6.9, 'Adventure Drama Family', 'Jean-Jacques Annaud', 'Maï Anh Le Guy Pearce Oanh Nguyen'),
(2001, 'new york father son relationship nightclub gangster', 'We Own the Night', 'A New York nightclub manager tries to save his brother and father from Russian mafia hitmen.', 'en', 14.518708, 6.5, 'Drama Crime Thriller', '', 'Joaquin Phoenix Eva Mendes Alex Veadov');
INSERT INTO `movies` (`movie_id`, `tags`, `title`, `overview`, `original_language`, `popularity`, `vote_average`, `genres`, `directeur`, `acteurs`) VALUES
(2008, 'servant emperor battle assignment', 'The Promise', 'An orphaned girl, driven by poverty at such a young age, makes a promise with an enchantress. In return for beauty and the admiration of every man, she will never be with the man she loves. This spell cannot be broken unless the impossible happens: snow falling in spring and the dead coming back to life. Now a grown and beautiful princess, she regrets her promise, for all of the men she\'s loved has always been met with tragedy. In love again with a man behind a red armor and a golden mask who rescues her from death, she is tormented by their inevitable parting. Meanwhile, Kunlun, the slave of a great general, is searching for the lost memories of a family he once had. Soon the fate of these two intertwine when the princess believes the general to be her hero, thus pulling him into this web of fate. What end will befallen our three characters? Are their fates already sealed by a higher power, or can they still choose a life they want?', 'zh', 3.866026, 5, 'Fantasy Drama Action Thriller Romance', '', 'Cecilia Cheung Liu Ye Hong Chen'),
(2011, 'civil war parents kids relationship 1970s puberty totalitarian regime cutting the cord punk bomb alarm war adult animation punk band woman director', 'Persepolis', 'In 1970s Iran, Marjane \'Marji\' Statrapi watches events through her young eyes and her idealistic family of a long dream being fulfilled of the hated Shah\'s defeat in the Iranian Revolution of 1979. However as Marji grows up, she witnesses first hand how the new Iran, now ruled by Islamic fundamentalists, has become a repressive tyranny on its own.', 'fr', 24.281951, 7.7, 'Animation Drama', 'Vincent Paronnaud', 'Chiara Mastroianni Danielle Darrieux Catherine Deneuve'),
(2013, 'writing lover (female) psychological stress dying and death editor-in-chief french independent film patient disabled', 'The Diving Bell and the Butterfly', 'Elle France editor Jean-Dominique Bauby, who, in 1995 at the age of 43, suffered a stroke that paralyzed his entire body, except his left eye. Using that eye to blink out his memoir, Bauby eloquently described the aspects of his interior world, from the psychological torment of being trapped inside his body to his imagined stories from lands he\'d only visited in his mind.', 'fr', 13.65494, 7.4, 'Drama', '', 'Mathieu Amalric Emmanuelle Seigner Marie-Josée Croze'),
(2018, 'san francisco marriage proposal love of one\'s life wedding planer man of one\'s dreams wine garden wedding sicilian star crossed lovers wedding day meant for each other', 'The Wedding Planner', 'Mary Fiore, San Francisco\'s premiere wedding planner is rescued from an accident by the man of her dreams, pediatrician Steve Edison, only to find he is the fiancé of her latest client, wealthy Fran Donnolly. As Mary continues making the wedding arrangements, she and Steve are put into a string of uncomfortable situations that force them to face their mutual attraction.', 'en', 14.949395, 5.5, 'Comedy', '', 'Jennifer Lopez Matthew McConaughey Justin Chambers'),
(2022, 'love letter new hampshire ferrari liar city country contrast inheritance billionaire new york city kindness fable apple tree corporate take over chrysler building', 'Mr. Deeds', 'When Longfellow Deeds, a small-town pizzeria owner and poet, inherits $40 billion from his deceased uncle, he quickly begins rolling in a different kind of dough. Moving to the big city, Deeds finds himself besieged by opportunists all gunning for their piece of the pie. Babe, a television tabloid reporter, poses as an innocent small-town girl to do an exposé on Deeds.', 'en', 18.121404, 5.6, 'Comedy Romance', '', 'Adam Sandler Winona Ryder John Turturro'),
(2023, 'horse race horse racehorse', 'Hidalgo', 'Set in 1890, this is the story of a Pony Express courier who travels to Arabia to compete with his horse, Hidalgo, in a dangerous race for a massive contest prize, in an adventure that sends the pair around the world...', 'en', 16.759252, 6.5, 'Western Adventure', 'Joe Johnston', 'Viggo Mortensen Zuleikha Robinson Omar Sharif'),
(2024, 'rebel southern usa loss of son martial arts general loss of family passion insurgence french daughter south carolina british based on true story gore mission', 'The Patriot', 'After proving himself on the field of battle in the French and Indian War, Benjamin Martin wants nothing more to do with such things, preferring the simple life of a farmer. But when his son Gabriel enlists in the army to defend their new nation, America, against the British, Benjamin reluctantly returns to his old life to protect his son.', 'en', 23.657284, 6.8, 'Drama History War Action', '', 'Mel Gibson Heath Ledger Joely Richardson'),
(2026, 'fbi kidnapping police operation home invasion hostage situation hostage negotiator', 'Hostage', 'When a mafia accountant is taken hostage on his beat, a police officer – wracked by guilt from a prior stint as a negotiator – must negotiate the standoff, even as his own family is held captive by the mob.', 'en', 23.663713, 6.2, 'Mystery Drama Thriller Crime', '', 'Bruce Willis Kevin Pollak Jimmy Bennett'),
(2034, 'police brutality war on drugs drug traffic drug dealer los angeles gang member mexican american barrio cholo', 'Training Day', 'On his first day on the job as a narcotics officer, a rookie cop works with a rogue detective who isn\'t what he appears.', 'en', 52.081131, 7.3, 'Action Crime Drama Thriller', '', 'Denzel Washington Ethan Hawke Scott Glenn'),
(2043, 'psychology police operation police psychologist', 'Along Came a Spider', 'When a teacher kidnaps a girl from a prestigious school, homicide detective, Alex Cross takes the case and teams up with young security agent, Jezzie Flannigan in hope of finding the girl and stopping the brutal psychopath. Every second counts as Alex and Jezzie attempt to track down the kidnapper before the spider claims another victim for its web.', 'en', 21.252797, 6.1, 'Crime Mystery Thriller Action', '', 'Morgan Freeman Monica Potter Michael Wincott'),
(2044, 'chicago writing architect future time architecture mysterious letter near future first kiss romantic drama passage of time', 'The Lake House', 'A lonely doctor who once occupied an unusual lakeside home begins exchanging love letters with its former resident, a frustrated architect. They must try to unravel the mystery behind their extraordinary romance before it\'s too late.', 'en', 29.88736, 6.5, 'Romance Drama Mystery', '', 'Keanu Reeves Sandra Bullock Shohreh Aghdashloo'),
(2048, 'suicide artificial intelligence man vs machine chicago based on novel hero future law dystopia police murder robot 3d humanoid robot', 'I, Robot', 'In 2035, where robots are common-place and abide by the three laws of robotics, a techno-phobic cop investigates an apparent suicide. Suspecting that a robot may be responsible for the death, his investigation leads him to believe that humanity may be in danger.', 'en', 95.914473, 6.7, 'Action Science Fiction', '', 'Will Smith Bridget Moynahan Alan Tudyk'),
(2054, 'composer mentor deaf-mute musical apprentice private life music disabled', 'Mr. Holland\'s Opus', 'In 1965, passionate musician Glenn Holland takes a day job as a high school music teacher, convinced it\'s just a small obstacle on the road to his true calling: writing a historic opus. As the decades roll by with the composition unwritten but generations of students inspired through his teaching, Holland must redefine his life\'s purpose.', 'en', 6.775294, 6.9, 'Music Drama Family', '', 'Richard Dreyfuss Glenne Headly Jay Thomas'),
(2055, 'horse beef ranger', 'Open Range', 'A former gunslinger is forced to take up arms again when he and his cattle crew are threatened by a corrupt lawman.', 'en', 19.068175, 7, 'Western', 'Kevin Costner', 'Kevin Costner Robert Duvall Michael Gambon'),
(2056, 'train station new jersey small person friendship newfoundland', 'The Station Agent', 'When his only friend dies, a man born with dwarfism moves to rural New Jersey to live a life of solitude, only to meet a chatty hot dog vendor and a woman dealing with her own personal loss.', 'en', 11.578545, 7.4, 'Drama Comedy', '', 'Peter Dinklage Patricia Clarkson Bobby Cannavale'),
(2057, 'women sex cuba eroticism lover (female) passion coffee grower sin denunciation', 'Original Sin', 'A young man is plunged into a life of subterfuge, deceit and mistaken identity in pursuit of a femme fatale whose heart is never quite within his grasp', 'en', 14.831402, 5.8, 'Drama Thriller Mystery Romance', '', 'Angelina Jolie Antonio Banderas Gregory Itzin'),
(2059, 'riddle treasure treasure hunt archaeologist archeology ', 'National Treasure', 'Modern treasure hunters, led by archaeologist Ben Gates, search for a chest of riches rumored to have been stashed away by George Washington, Thomas Jefferson and Benjamin Franklin during the Revolutionary War. The chest\'s whereabouts may lie in secret clues embedded in the Constitution and the Declaration of Independence, and Gates is in a race to find the gold before his enemies do.', 'en', 58.849256, 6.4, 'Adventure Action Thriller Mystery', '', 'Nicolas Cage Diane Kruger Justin Bartha'),
(2062, 'paris brother brother relationship expensive restaurant river cook mouse confidence roof window leaving one\'s family work restaurant critic kitchen spice court cookbook family chef rat', 'Ratatouille', 'A rat named Remy dreams of becoming a great French chef despite his family\'s wishes and the obvious problem of being a rat in a decidedly rodent-phobic profession. When fate places Remy in the sewers of Paris, he finds himself ideally situated beneath a restaurant made famous by his culinary hero, Auguste Gusteau. Despite the apparent dangers of being an unlikely - and certainly unwanted - visitor in the kitchen of a fine French restaurant, Remy\'s passion for cooking soon sets into motion a hilarious and exciting rat race that turns the culinary world of Paris upside down.', 'en', 65.677399, 7.5, 'Animation Comedy Family Fantasy', '', 'Patton Oswalt Ian Holm Lou Romano'),
(2067, 'mars spacecraft space travel alien long take outer space astronaut dismemberment alien contact trapped in space', 'Mission to Mars', 'When contact is lost with the crew of the first Mars expedition, a rescue mission is launched to discover their fate.', 'en', 16.058284, 5.7, 'Science Fiction', '', 'Gary Sinise Tim Robbins Don Cheadle'),
(2069, 'bounty gangster boss montreal gangster dentist hoodlum', 'The Whole Nine Yards', 'A mobster named Jimmy the Tulip agrees to cooperate with an FBI investigation in order to stay out of prison; he\'s relocated by the authorities to a life of suburban anonymity as part of a witness protection program. It\'s not long before a couple of his new neighbors figure out his true identity and come knocking to see if he\'d be up for one more hit, suburban style.', 'en', 23.441135, 6.2, 'Comedy Crime', '', 'Bruce Willis Matthew Perry Rosanna Arquette'),
(2074, 'lsd looking for  birth parents half-brother independent film', 'Flirting with Disaster', 'Adopted as a child, new father Mel Colpin (Ben Stiller) decides he cannot name his son until he knows his birth parents, and determines to make a cross-country quest to find them. Accompanied by his wife, Nancy (Patricia Arquette), and an inept yet gorgeous adoption agent, Tina (Tea Leoni), he departs on an epic road trip that quickly devolves into a farce of mistaken identities, wrong turns, and overzealous and love-struck ATF agents (Josh Brolin, Richard Jenkins).', 'en', 5.500324, 6.3, 'Comedy Romance', '', 'Ben Stiller Patricia Arquette Téa Leoni'),
(2080, 'corruption mutant boxer army marvel comic superhero aftercreditsstinger duringcreditsstinger', 'X-Men Origins: Wolverine', 'After seeking to live a normal life, Logan sets out to avenge the death of his girlfriend by undergoing the mutant Weapon X program and becoming Wolverine.', 'en', 5.954334, 6.2, 'Adventure Action Thriller Science Fiction', '', 'Hugh Jackman Liev Schreiber Danny Huston'),
(2084, 'female nudity robbery mail order bride bank clerk', 'Birthday Girl', 'A shy bank clerk orders a Russian mail order bride, and finds his life turned upside down.', 'en', 5.831302, 6.1, 'Comedy Crime Thriller', '', 'Nicole Kidman Ben Chaplin Vincent Cassel'),
(2085, 'martial arts hip-hop oakland asian asian man asian lead', 'Romeo Must Die', 'Two warring gang families (one African-American, the other Chinese) maneuver for bragging rights to the Oakland, California, docks. Hang SIng and Trish O\'Day uncover a trail of deceit that leaves most of the warring factions dead … or worse!', 'en', 19.750059, 6, 'Action Crime Thriller', 'Andrzej Bartkowiak', 'Jet Li Aaliyah Isaiah Washington'),
(2088, 'police operation sex addiction police mafia boss suspense bad cop hitwoman', 'Romeo Is Bleeding', 'A corrupt cop gets in over his head when he tries to assassinate a beautiful Russian hit-woman.', 'en', 4.850402, 5.7, 'Action Crime Drama Thriller', '', 'Gary Oldman Lena Olin Annabella Sciorra'),
(2100, 'prison general', 'The Last Castle', 'A Court Martialed general rallies together 1200 inmates to rise against the system that put him away.', 'en', 15.433244, 7, 'Action Drama Thriller', '', 'Robert Redford James Gandolfini Mark Ruffalo'),
(2110, 'handcuffs hitman love letter police operation japanese mafia golf club brutal cop', 'Wasabi', 'Hubert is a French policeman with very sharp methods. After being forced to take 2 months off by his boss, who doesn\'t share his view on working methods, he goes back to Japan, where he used to work 19 years ago, to settle the probate of his girlfriend who left him shortly after marriage without a trace.', 'fr', 18.20957, 6.2, 'Drama Action Comedy', '', 'Jean Reno Ryoko Hirosue Michel Muller'),
(2112, 'new york heroin money criminal', 'Payback', 'With friends like these, who needs enemies? That\'s the question bad guy Porter is left asking after his wife and partner steal his heist money and leave him for dead -- or so they think. Five months and an endless reservoir of bitterness later, Porter\'s partners and the crooked cops on his tail learn how bad payback can be.', 'en', 17.457947, 6.7, 'Drama Action Thriller Crime', 'Brian Helgeland', 'Mel Gibson Kris Kristofferson Gregg Henry'),
(2114, 'battle assignment dystopia alien downfall scientist based on video game', 'Final Fantasy: The Spirits Within', 'Led by a strange dream, scientist Aki Ross struggles to collect the eight spirits in the hope of creating a force powerful enough to protect the planet. With the aid of the Deep Eyes Squadron and her mentor, Dr. Sid, Aki must save the Earth from its darkest hate and unleash the spirits within.', 'en', 26.074908, 5.9, 'Adventure Action Animation Fantasy Science Fiction Thriller', '', 'Donald Sutherland Ming-Na Wen Alec Baldwin'),
(2116, 'miami florida double murder divorce', 'Out of Time', 'Matt Lee Whitlock, respected chief of police in small Banyan Key, Florida, must solve a vicious double homicide before he himself falls under suspicion. Matt Lee has to stay a few steps ahead of his own police force and everyone he\'s trusted in order to find out the truth.', 'en', 14.993459, 6.1, 'Thriller Crime Drama', '', 'Denzel Washington Eva Mendes Sanaa Lathan'),
(2118, 'corruption detective shotgun morgue f word domestic violence corpse crime district attorney bandage movie star man with glasses knife in thigh good cop bad cop switchblade call girl 1950s falsifying', 'L.A. Confidential', 'Three detectives in the corrupt and brutal L.A. police force of the 1950s use differing methods to uncover a conspiracy behind the shotgun slayings of the patrons at an all-night diner.', 'en', 24.860326, 7.7, 'Crime Drama Mystery Thriller', 'Curtis Hanson', 'Kevin Spacey Guy Pearce Danny DeVito'),
(2119, 'stock-car-race daytona car crash', 'Days of Thunder', 'Talented but unproven stock car driver Cole Trickle gets a break and with the guidance of veteran Harry Hogge turns heads on the track. The young hotshot develops a rivalry with a fellow racer that threatens his career when the two smash their cars. But with the help of his doctor, Cole just might overcome his injuries-- and his fear.', 'en', 16.278022, 5.9, 'Adventure', '', 'Tom Cruise Robert Duvall Nicole Kidman'),
(2122, 'hitman', 'The Whole Ten Yards', 'Jimmy \'The Tulip\' Tudeski now spends his days compulsively cleaning his house and perfecting his culinary skills with his wife, Jill, a purported assassin who has yet to pull off a clean hit. Suddenly, an uninvited and unwelcome connection to their past unexpectedly shows up on Jimmy and Jill\'s doorstep; it\'s Oz, and he\'s begging them to help him rescue his wife, Cynthia.', 'en', 14.729386, 5.5, 'Comedy Thriller Crime', '', 'Bruce Willis Matthew Perry Amanda Peet'),
(2123, 'schizophrenia ex-cop aftercreditsstinger duringcreditsstinger', 'Me, Myself & Irene', 'Rhode Island State Trooper Charlie Baileygates has a multiple personality disorder. One personality is crazy and aggressive, while the other is more friendly and laid back. Both of these personalities fall in love with the same woman named Irene after Charlie loses his medication.', 'en', 39.001682, 6.1, 'Comedy', '', 'Jim Carrey Renée Zellweger Anthony Anderson'),
(2133, 'u.s. air force grocery jamaican meteorologist rescue boat marina city hall the flemish cap male camaraderie storm at sea', 'The Perfect Storm', 'In October 1991, a confluence of weather conditions combined to form a killer storm in the North Atlantic. Caught in the storm was the sword-fishing boat Andrea Gail. Magnificent foreshadowing and anticipation fill this true-life drama while minute details of the fishing boats, their gear and the weather are juxtaposed with the sea adventure.', 'en', 25.752118, 6.2, 'Drama', '', 'George Clooney Mark Wahlberg Diane Lane'),
(2135, 'future time machine', 'The Time Machine', 'Hoping to alter the events of the past, a 19th century inventor instead travels 800,000 years into the future, where he finds humankind divided into two warring races.', 'en', 25.978555, 5.8, 'Science Fiction Adventure Action', '', 'Guy Pearce Mark Addy Phyllida Law'),
(2140, 'paris prostitute drug', 'Kiss of the Dragon', 'Liu Jian, an elite Chinese police officer, comes to Paris to arrest a Chinese drug lord. When Jian is betrayed by a French officer and framed for murder, he must go into hiding and find new allies.', 'en', 16.936576, 6.4, 'Action Crime Thriller', '', 'Jet Li Bridget Fonda Tchéky Karyo'),
(2142, 'corruption new jersey handcuffs fbi bridge police burned alive murder car crash independent film bad cop arson dirty cop internal affairs car accident new york city violence nypd world trade center jumping off a bridge corrupt cop', 'Cop Land', 'Freddy Heflin is the sheriff of a place everyone calls “Cop Land” — a small and seemingly peaceful town populated by the big city police officers he’s long admired. Yet something ugly is taking place behind the town’s peaceful facade. And when Freddy uncovers a massive, deadly conspiracy among these local residents, he is forced to take action and make a dangerous choice between protecting his idols and upholding the law.', 'en', 19.284129, 6.6, 'Action Crime Drama', 'James Mangold', 'Sylvester Stallone Harvey Keitel Ray Liotta'),
(2148, 'jazz jazz musician musical mafia', 'The Cotton Club', 'The story of the people that frequented Harlem\'s famous nightclubs, \'The Cotton Club\', and those that ran it.', 'en', 8.59075, 6.6, 'Music Drama Crime Romance', 'Francis Ford Coppola', 'Richard Gere Gregory Hines Diane Lane'),
(2155, 'prison robbery role reversal extramarital affair', 'Reindeer Games', 'After assuming his dead cellmate\'s identity to get with his girlfriend, an ex-con finds himself the reluctant participant in a casino heist.', 'en', 11.470135, 5.4, 'Thriller', '', 'Ben Affleck Gary Sinise Charlize Theron'),
(2157, 'time travel sabotage deep space explorer', 'Lost in Space', 'The prospects for continuing life on Earth in the year 2058 are grim. So the Robinsons are launched into space to colonize Alpha Prime, the only other inhabitable planet in the galaxy. But when a stowaway sabotages the mission, the Robinsons find themselves hurtling through uncharted space.', 'en', 17.455024, 5, 'Adventure Family Science Fiction', 'Stephen Hopkins', 'Gary Oldman William Hurt Matt LeBlanc'),
(2162, '', 'Chill Factor', 'A store clerk and an ice cream truck driver are thrown together when a dying scientist entrusts them with a deadly chemical kept in ice. This chemical will kill every living thing once it melts. They have to take the chemical codenamed \'Elvis\' to the next nearest military base while being chased by terrorists who want it to hold the country for ransom.', 'en', 3.276912, 5.3, 'Action Comedy Thriller', '', 'Cuba Gooding Jr. Skeet Ulrich Peter Firth'),
(2163, 'california bank ransom car breakdown kidnapping donut highway barn vacation stranded deception murder suspense redneck diner extortion captive car chase desert moving trucker', 'Breakdown', 'When his SUV breaks down on a remote Southwestern road, Jeff Taylor lets his wife, Amy, hitch a ride with a trucker to get help. When she doesn\'t return, Jeff fixes his SUV and tracks down the trucker -- who tells the police he\'s never seen Amy. Johnathan Mostow\'s tense thriller then follows Jeff\'s desperate search for his wife, which eventually uncovers a small town\'s murderous secret.', 'en', 9.176339, 6.6, 'Drama Action Thriller', 'Jonathan Mostow', 'Kurt Russell J. T. Walsh Kathleen Quinlan'),
(2176, 'california brother sister relationship loss of parents suspense psychological thriller orphan car accident', 'The Glass House', 'After the parents of Ruby and her younger brother, Rhett, are killed in a car crash, their parents\' best friends, Erin and Terry Glass, become their guardians. The children hear promises of a world of opulence and California fun -- all they have to do is move into the Glasses\' gated house. Before very long, though, Ruby suspects that Erin and Terry may not be the ideal guardians they seemed to be.', 'en', 9.448517, 5.4, 'Drama Thriller', '', 'Leelee Sobieski Diane Lane Stellan Skarsgård'),
(2185, 'gadfly', 'Big Trouble', 'The story of how a mysterious suitcase brings together, and changes, the lives of a divorced dad, an unhappy housewife, two hitmen, a pair of street thugs, two love struck teens, two FBI men and a psychedelic toad. Based on Pulitzer Prize-winning humorist Dave Barry\'s best-selling first novel, \"Big Trouble.\"', 'en', 5.201688, 6.3, 'Action Comedy Thriller', 'Barry Sonnenfeld', 'Tim Allen Rene Russo Patrick Warburton'),
(2196, 'brother brother relationship farewell father son relationship age difference parents kids relationship secret sadness coffin funeral gathering surprise lsd studies hallucinogen drug trip arrogance female corpse', 'Death at a Funeral', 'Chaos ensues when a man tries to expose a dark secret regarding a recently deceased patriarch of a dysfunctional British family.', 'en', 20.410354, 6.9, 'Comedy Drama', 'Frank Oz', 'Matthew Macfadyen Keeley Hawes Andy Nyman'),
(2207, 'mission of murder male bonding doing the right thing people change', '16 Blocks', 'An aging cop is assigned the ordinary task of escorting a fast-talking witness from police custody to a courthouse, but they find themselves running the gauntlet as other forces try to prevent them from getting there.', 'en', 32.31022, 6.2, 'Action Adventure Crime Thriller', 'Richard Donner', 'Bruce Willis Yasiin Bey David Morse'),
(2211, 'berlin jew forbidden love lesbian relationship homosexuality lesbian interest', 'Aimee & Jaguar', 'Berlin 1943/44 (\"The Battle of Berlin\"). Felice, an intelligent and courageous Jewish woman who lives under a false name, belongs to an underground organization. Lilly, a devoted mother of four, though an occasional unfaithful wife, is desperate for love. An unusual and passionate love between them blossoms despite the danger of persecution and nightly bombing raids. The Gestapo is on Felice\'s trail. Her friends flee, she decides to sit out the war with Lilly. One hot day in August 1944, the Gestapo is waiting in Lilly\'s flat...', 'de', 2.832628, 6.3, 'Drama History Romance', '', 'Maria Schrader Juliane Köhler Johanna Wokalek'),
(2251, 'adultery infidelity eroticism literature lover new york city erotic thriller', 'Unfaithful', 'Connie is a wife and mother whose 11-year marriage to Edward has lost its sexual spark. When Connie literally runs into handsome book collector Paul, he sweeps her into an all-consuming affair. But Edward soon becomes suspicious and decides to confront the other man.', 'en', 14.382253, 6.3, 'Thriller Drama', '', 'Richard Gere Diane Lane Olivier Martinez'),
(2252, 'london england gay male nudity female nudity father son relationship sex jealousy underworld undercover hitman russian diary human trafficking midwife murder mother daughter relationship orphan gangster motorcycle bathhouse', 'Eastern Promises', 'A Russian teenager living in London who dies during childbirth leaves clues to a midwife in her journal that could tie her child to a rape involving a violent Russian mob family.', 'en', 35.481169, 7.2, 'Thriller Crime Mystery', 'David Cronenberg', 'Naomi Watts Viggo Mortensen Vincent Cassel'),
(2253, 'berlin suicide bomb assassination resistance wife husband relationship world war ii adolf hitler plan friendship deception treason colonel military officer plot german officer piano wire medal violence', 'Valkyrie', 'Wounded in Africa during World War II, Nazi Col. Claus von Stauffenberg returns to his native Germany and joins the Resistance in a daring plan to create a shadow government and assassinate Adolf Hitler. When events unfold so that he becomes a central player, he finds himself tasked with both leading the coup and personally killing the Führer.', 'en', 38.832842, 6.7, 'Drama Thriller History War', '', 'Tom Cruise Carice van Houten Kenneth Branagh'),
(2255, 'new jersey coming out love of one\'s life bisexuality menage a trois comic book comic-strip artist independent film lesbian best friend', 'Chasing Amy', 'Holden and Banky are comic book artists. Everything is going good for them until they meet Alyssa, also a comic book artist. Holden falls for her, but his hopes are crushed when he finds out she\'s a lesbian.', 'en', 20.601483, 6.7, 'Comedy Drama Romance', 'Kevin Smith', 'Ben Affleck Joey Lauren Adams Jason Lee'),
(2266, 'paris city portrait jazz subway new love immigration nanny tourist woman director', 'Paris, je t\'aime', 'Olivier Assayas, Gus Van Sant, Wes Craven and Alfonso Cuaron are among the 20 distinguished directors who contribute to this collection of 18 stories, each exploring a different aspect of Parisian life. The colourful characters in this drama include a pair of mimes, a husband trying to chose between his wife and his lover, and a married man who turns to a prostitute for advice.', 'fr', 10.573191, 6.8, 'Drama Romance', 'Isabel Coixet', 'Steve Buscemi Natalie Portman Willem Dafoe'),
(2268, 'england compass experiment lordship uncle polar bear orphan animal based on young adult novel', 'The Golden Compass', 'After overhearing a shocking secret, precocious orphan Lyra Belacqua trades her carefree existence roaming the halls of Jordan College for an otherworldly adventure in the far North, unaware that it\'s part of her destiny.', 'en', 42.990906, 5.8, 'Adventure Fantasy', '', 'Dakota Blue Richards Nicole Kidman Daniel Craig'),
(2270, 'witch based on novel new love prince beauty star kingdom wall falling star royalty unrequited love good vs evil fratricide', 'Stardust', 'In a countryside town bordering on a magical land, a young man makes a promise to his beloved that he\'ll retrieve a fallen star by venturing into the magical realm. His journey takes him into a world beyond his wildest dreams and reveals his true identity.', 'en', 48.032734, 7.1, 'Adventure Fantasy Romance Family', 'Matthew Vaughn', 'Claire Danes Charlie Cox Michelle Pfeiffer'),
(2275, 'suicide detective based on novel bondage general paranoia nudity u.s. army investigation politics cover-up murder betrayal conspiracy gang rape father daughter relationship videotape military law', 'The General\'s Daughter', 'When the body of Army Capt. Elizabeth Campbell is found on a Georgia military base, two investigators, Warrant Officers Paul Brenner and Sara Sunhill, are ordered to solve her murder. What they uncover is anything but clear-cut. Unseemly details emerge about Campbell\'s life, leading to allegations of a possible military coverup of her death and the involvement of her father, Lt. Gen. Joseph Campbell.', 'en', 18.345613, 6.1, 'Crime Drama Mystery Thriller', '', 'John Travolta Madeleine Stowe James Cromwell'),
(2277, 'android hologram freedom futuristic robot', 'Bicentennial Man', 'Richard Martin buys a gift, a new NDR-114 robot. The product is named Andrew by the youngest of the family\'s children. \"Bicentennial Man\" follows the life and times of Andrew, a robot purchased as a household appliance programmed to perform menial tasks. As Andrew begins to experience emotions and creative thought, the Martin family soon discovers they don\'t have an ordinary robot.', 'en', 24.939295, 6.9, 'Comedy Science Fiction', '', 'Robin Williams Sam Neill Embeth Davidtz'),
(2280, 'baseball co-worker bronx pinball machine toy maker duet job promotion homesick new toy quarter unplugged electronic works yankee stadium bronx new york city walking on piano keys wish fulfillment bunk bed woman director', 'Big', 'A young boy, Josh Baskin makes a wish at a carnival machine to be big. He wakes up the following morning to find that it has been granted and his body has grown older overnight. But he is still the same 13-year-old boy inside. Now he must learn how to cope with the unfamiliar world of grown-ups including getting a job and having his first romantic encounter with a woman. What will he find out about this strange world?', 'en', 20.716023, 6.9, 'Fantasy Drama Comedy Romance Family', '', 'Tom Hanks Elizabeth Perkins Robert Loggia'),
(2288, 'father son relationship love at first sight photographer loss of lover cheating lie forbidden love tea lover kiss photography secret love times square liar sexchat based on play death of father falling in love', 'Closer', 'A witty, romantic, and very dangerous love story about chance meetings, instant attractions, and casual betrayals. Two couples disintegrate when they begin destructive adulterous affairs with each other.', 'en', 22.636908, 6.7, 'Drama Romance', 'Mike Nichols', 'Julia Roberts Jude Law Natalie Portman'),
(2289, 'loss of lover loss of family deserter loss of father love of one\'s life', 'Cold Mountain', 'In this classic story of love and devotion set against the backdrop of the American Civil War, a wounded Confederate soldier named W.P. Inman deserts his unit and travels across the South, aiming to return to his young wife, Ada, who he left behind to tend their farm. As Inman makes his perilous journey home, Ada struggles to keep their home intact with the assistance of Ruby, a mysterious drifter sent to help her by a kindly neighbor.', 'en', 24.598479, 6.7, 'Drama', '', 'Jude Law Nicole Kidman Renée Zellweger'),
(2292, 'salesclerk loser aftercreditsstinger', 'Clerks', 'Convenience and video store clerks Dante and Randal are sharp-witted, potty-mouthed and bored out of their minds. So in between needling customers, the counter jockeys play hockey on the roof, visit a funeral home and deal with their love lives.', 'en', 19.748658, 7.4, 'Comedy', 'Kevin Smith', 'Brian O\'Halloran Jeff Anderson Jason Mewes'),
(2293, 'sex game show slacker shopping mall ex-boyfriend ex-girlfriend relationship jay and silent bob silent man coke bandleader aftercreditsstinger', 'Mallrats', 'Both dumped by their girlfriends, two best friends seek refuge in the local mall.', 'en', 16.139771, 6.8, 'Romance Comedy', 'Kevin Smith', 'Jason Lee Jeremy London Shannen Doherty'),
(2294, 'film making jay and silent bob self mocking character is subject of comic reference to prince valiant indiana jones spoof scene monkey actor view askew gigantic hand animal experimentation', 'Jay and Silent Bob Strike Back', 'When Jay and Silent Bob learn that their comic-book alter egos, Bluntman and Chronic, have been sold to Hollywood as part of a big-screen movie that leaves them out of any royalties, the pair travels to Tinseltown to sabotage the production.', 'en', 21.865021, 6.4, 'Comedy', '', 'Kevin Smith Jason Mewes Ben Affleck'),
(2295, 'independent film aftercreditsstinger duringcreditsstinger', 'Clerks II', 'A calamity at Dante and Randall\'s shops sends them looking for new horizons - but they ultimately settle at Mooby\'s, a fictional Disney-McDonald\'s-style fast-food empire.', 'en', 18.077963, 6.9, 'Comedy', 'Kevin Smith', 'Brian O\'Halloran Jeff Anderson Jason Mewes'),
(2300, 'sport basketball doctor basketball team basketball game referee basketball court tweety bird speedy gonzales cartoon chicken sylvester the cat cartoon reality crossover basketball hoop cartoon skunk', 'Space Jam', 'In a desperate attempt to win a basketball match and earn their freedom, the Looney Tunes seek the aid of retired basketball champion, Michael Jordan.', 'en', 36.125715, 6.5, 'Animation Comedy Drama Family Fantasy', '', 'Michael Jordan Wayne Knight Billy West'),
(2309, 'book fairy tale eavesdropping adventure writer\'s block', 'Inkheart', 'The adventures of a father and his young daughter, in their search for a long lost book that will help reunite a missing, close relative.', 'en', 27.018886, 6, 'Adventure Family Fantasy', '', 'Brendan Fraser Sienna Guillory Andy Serkis'),
(2310, 'denmark nordic mythology lie pride and vanity folk hero human weakness viking alienation festival hall sin royalty curse battle ancient world adult animation motion capture', 'Beowulf', '6th-century Scandinavian warrior, Beowulf embarks on a mission to slay the manlike ogre Grendel, a descendant of Cain.', 'en', 35.601665, 5.5, 'Adventure Action Animation', 'Robert Zemeckis', 'Ray Winstone Angelina Jolie Anthony Hopkins'),
(2312, 'fictional place monster loss of family new love hero love of one\'s life magic fairy tale villain kingdom enchantment bad power son heir to the throne motherly love wizardry revenge royalty family based on video game medieval', 'In the Name of the King: A Dungeon Siege Tale', 'A man named Farmer sets out to rescue his kidnapped wife and avenge the death of his son -- two acts committed by the Krugs, a race of animal-warriors who are controlled by the evil Gallian.', 'en', 15.406173, 4.1, 'Adventure Fantasy Action Drama', 'Uwe Boll', 'Jason Statham John Rhys-Davies Ray Liotta'),
(2320, 'bomb ransom hostage airplane hijacking terror cell special unit deception rescue covert operation disaster shootout terrorism explosion violence surveillance night vision goggles flight attendant intelligence agent flashback hand to hand combat nerve gas', 'Executive Decision', 'Terrorists hijack a 747 inbound to Washington D.C., demanding the the release of their imprisoned leader. Intelligence expert David Grant (Kurt Russell) suspects another reason and he is soon the reluctant member of a special assault team that is assigned to intercept the plane and hijackers.', 'en', 17.231675, 5.8, 'Action Adventure Drama Thriller', '', 'Kurt Russell Steven Seagal Halle Berry'),
(2355, 'confidence trauma leaving one\'s family childhood memory airplane war on terror music loss of daughter alone cowardliness family', 'Reign Over Me', 'A man who lost his family in the September 11 attack on New York City runs into his old college roommate. Rekindling the friendship is the one thing that appears able to help the man recover from his grief.', 'en', 20.82778, 7.1, 'Drama', '', 'Adam Sandler Don Cheadle Jada Pinkett Smith'),
(2359, 'bureaucracy usa corruption cuba medicine guantanamo bay assurance health care money hospital doctor illness existence', 'Sicko', 'Sicko is a Michael Moore documentary about the corrupt health care system in The United States who\'s main goal is to make profit even if it means losing peoples lives. \"The more people you deny health insurance the more money we make\" is the business model for health care providers in America.', 'en', 14.098952, 7.3, 'Documentary', '', 'Michael Moore George W. Bush Bill Clinton'),
(2370, 'new york cia cuba cold war suspense', 'Topaz', 'A French intelligence agent becomes embroiled in the Cold War politics first with uncovering the events leading up to the 1962 Cuban Missle Crisis, and then back to France to break up an international Russian spy ring.', 'en', 5.975604, 6.1, 'Action Drama Mystery Thriller', 'Alfred Hitchcock', 'Frederick Stafford Dany Robin Claude Jade'),
(2395, 'competition greece colosseum olympic games emperor magic horse roman wild boar governance galier', 'Asterix at the Olympic Games', 'Astérix and Obélix have to win the Olympic Games in order to help their friend Alafolix marry Princess Irina (portrayed by supermodel Vanessa Hessler). Brutus (Benoît Poelvoorde) uses every trick in the book to have his own team win the game, and get rid of his father Julius Caesar (Alain Delon) in the process.', 'fr', 20.344364, 5, 'Fantasy Adventure Comedy Family', '', 'Clovis Cornillac Gérard Depardieu Franck Dubosc'),
(2428, 'jesus christ biography epic', 'The Greatest Story Ever Told', 'All-star epic retelling of Christ\'s life.', 'en', 3.011205, 6.5, 'Drama History', '', 'Max von Sydow Michael Anderson Jr. Carroll Baker'),
(2447, 'jesus christ bible three kings archangel gabriel christian blessed hope wise men woman director', 'The Nativity Story', 'Mary and Joseph make the hard journey to Bethlehem for a blessed event in this retelling of the Nativity story. This meticulously researched and visually lush adaptation of the biblical tale follows the pair on their arduous path to their arrival in a small village, where they find shelter in a quiet manger and Jesus is born.', 'en', 3.721272, 6.4, 'Drama History', '', 'Keisha Castle-Hughes Oscar Isaac Hiam Abbass'),
(2453, 'corruption harley davidson drug dealer los angeles las vegas', 'Harley Davidson and the Marlboro Man', 'It\'s the lawless future, and renegade biker Harley Davidson (Mickey Rourke) and his surly cowboy buddy, Marlboro (Don Johnson), learn that a corrupt bank is about to foreclose on their friend\'s bar to further an expanding empire. Harley and Marlboro decide to help by robbing the crooked bank. But when they accidentally filch a drug shipment, they find themselves on the run from criminal financiers and the mob in this rugged action adventure.', 'en', 12.869436, 6.1, 'Action Thriller', 'Simon Wincer', 'Mickey Rourke Don Johnson Chelsea Field'),
(2454, 'based on novel fictional place brother sister relationship lion human being wretch leap in time matter of life and death faith uncle narnia fantasy world', 'The Chronicles of Narnia: Prince Caspian', 'One year after their incredible adventures in the Lion, the Witch and the Wardrobe, Peter, Edmund, Lucy and Susan Pevensie return to Narnia to aid a young prince whose life has been threatened by the evil King Miraz. Now, with the help of a colorful cast of new characters, including Trufflehunter the badger and Nikabrik the dwarf, the Pevensie clan embarks on an incredible quest to ensure that Narnia is returned to its rightful heir.', 'en', 53.978602, 6.3, 'Adventure Family Fantasy', '', 'Ben Barnes William Moseley Anna Popplewell'),
(2486, 'based on novel mythical creature dragon fantasy world teenage hero based on young adult novel', 'Eragon', 'In his homeland of Alagaesia, a farm boy happens upon a dragon\'s egg -- a discovery that leads him on a predestined journey where he realized he\'s the one person who can defend his home against an evil king.', 'en', 30.863434, 4.9, 'Fantasy Action Adventure Family', '', 'Ed Speleers Jeremy Irons Sienna Guillory'),
(2493, 'swashbuckler evil prince reference to socrates reference to plato screwball impersonation', 'The Princess Bride', 'In this enchantingly cracked fairy tale, the beautiful Princess Buttercup and the dashing Westley must overcome staggering odds to find happiness amid six-fingered swordsmen, murderous princes, Sicilians and rodents of unusual size. But even death can\'t stop these true lovebirds from triumphing.', 'en', 44.533612, 7.6, 'Adventure Family Fantasy Comedy Romance', '', 'Cary Elwes Robin Wright Mandy Patinkin'),
(2501, 'paris barcelona spain assassin based on novel secret identity amnesia sniper passport mission of murder lovers escape shootout foot chase cell phone car chase multiple identities surveillance camera hamburg germany fishing boat langley virginia safe deposit box flashback hand to hand combat', 'The Bourne Identity', 'Wounded to the brink of death and suffering from amnesia, Jason Bourne is rescued at sea by a fisherman. With nothing to go on but a Swiss bank account number, he starts to reconstruct his life, but finds that many people he encounters want him dead. However, Bourne realizes that he has the combat and mental skills of a world-class spy – but who does he work for?', 'en', 86.476817, 7.3, 'Action Drama Mystery Thriller', '', 'Matt Damon Franka Potente Chris Cooper'),
(2502, 'berlin assassin based on novel amnesia sniper lie sequel suspense on the run shootout espionage violence foot chase car chase exploding house though guy one against many rail car dark past moscow hand to hand combat', 'The Bourne Supremacy', 'When a CIA operation to purchase classified Russian documents is blown by a rival agent, who then shows up in the sleepy seaside village where Bourne and Marie have been living. The pair run for their lives and Bourne, who promised retaliation should anyone from his former life attempt contact, is forced to once again take up his life as a trained assassin to survive.', 'en', 53.213931, 7.2, 'Action Drama Thriller', '', 'Matt Damon Franka Potente Brian Cox'),
(2503, 'paris corruption madrid assassin based on novel europe prosecution dangerous false identity revelation government weapon interpol sequel conspiracy shootout espionage motorcycle violence foot chase moskow dark past langley virginia flashback chase on the roof security leak', 'The Bourne Ultimatum', 'Bourne is brought out of hiding once again by reporter Simon Ross who is trying to unveil Operation Blackbriar, an upgrade to Project Treadstone, in a series of newspaper columns. Information from the reporter stirs a new set of memories, and Bourne must finally uncover his dark past while dodging The Company\'s best efforts to eradicate him.', 'en', 45.381501, 7.3, 'Action Drama Mystery Thriller', '', 'Matt Damon Julia Stiles David Strathairn'),
(2539, 'upper class mother single parent parents kids relationship wife husband relationship cook milieu illegal immigration immigrant language barrier family\'s daily life platonic love deceived husband class society hysteria biography united states–mexico barrier relationship problems class language course single mother daughter relationship american mexican father figure', 'Spanglish', 'Mexican immigrant and single mother Flor Moreno finds housekeeping work with Deborah and John Clasky, a well-off couple with two children of their own. When Flor admits she can\'t handle the schedule because of her daughter, Cristina, Deborah decides they should move into the Clasky home. Cultures clash and tensions run high as Flor and the Claskys struggle to share space while raising their children on their own, and very different, terms.', 'en', 14.209329, 5.8, 'Comedy', 'James L. Brooks', 'Adam Sandler Téa Leoni Paz Vega'),
(2567, 'ladykiller pilot biography womanizer aviation phobia u.s. congress flying boat test flight', 'The Aviator', 'A biopic depicting the life of filmmaker and aviation pioneer Howard Hughes from 1927 to 1947, during which time he became a successful film producer and an aviation magnate, while simultaneously growing more unstable due to severe obsessive-compulsive disorder.', 'en', 45.616098, 7, 'Drama', '', 'Leonardo DiCaprio Cate Blanchett Kate Beckinsale'),
(2575, 'dancing spy birthday map fireworks bridge secret agent president children independent film debt swimming political band', 'The Tailor of Panama', 'A British spy is banished to Panama after having an affair with an ambassador\'s mistress. Once there he makes connection with a local tailor with a nefarious past and connections to all of the top political and gangster figures in Panama. The tailor also has a wife, who works for the Panamanian president and a huge debt. The mission is to learn what the President intends to do with the Canal.', 'en', 7.047975, 6.2, 'Drama Thriller', '', 'Pierce Brosnan Geoffrey Rush Jamie Lee Curtis'),
(2577, 'seattle shanghai future insurance salesman dystopia', 'Code 46', 'A futuristic \'Brief Encounter\', a love story in which the romance is doomed by genetic incompatibility.', 'en', 8.859657, 6.2, 'Drama Romance Science Fiction Thriller', 'Michael Winterbottom', 'Tim Robbins Samantha Morton Nabil Elouahabi'),
(2610, 'salesclerk', 'Shopgirl', 'Mirabelle is a disenchanted salesgirl and aspiring artist who sells gloves and accessories at a department store. She has two men in her life: wealthy divorcée Ray Porter and struggling musician Jeremy. Mirabelle falls in love with the glamorous Ray, and her life takes a magical turn, but eventually she realizes that she must empower herself and make a choice between them.', 'en', 4.820166, 5.7, 'Comedy Drama Romance', '', 'Steve Martin Claire Danes Jason Schwartzman'),
(2619, 'bachelor mermaid', 'Splash', 'A successful businessman falls in love with the girl of his dreams. There\'s one big complication though; he\'s fallen hook, line and sinker for a mermaid.', 'en', 21.735068, 6.1, 'Comedy Fantasy Romance', '', 'Tom Hanks Daryl Hannah Eugene Levy'),
(2621, 'transplantation love of one\'s life veterinarian woman director', 'Return to Me', 'It took a lot of cajoling to get Bob (Duchovny), a recently widowed architect, to go on a blind date at a quirky Irish-Italian eatery. Once there, he\'s smitten instantly not with his date but with the sharp-witted waitress, Grace (Driver). Everything seems to be going great until an unbelievable truth is revealed, one that could easily break both of their hearts for good.', 'en', 5.771479, 6.1, 'Romance Comedy Drama', 'Bonnie Hunt', 'David Duchovny Minnie Driver Carroll O\'Connor'),
(2636, 'explosive revenge explosives expert', 'The Specialist', 'May Munro is a woman obsessed with getting revenge on the people who murdered her parents when she was still a girl. She hires Ray Quick, a retired explosives expert to kill her parent\'s killers. When Ned Trent, embittered ex-partner of Quick\'s is assigned to protect one of Quick\'s potential victims, a deadly game of cat and mouse ensues.', 'en', 16.582709, 5.5, 'Action Thriller', '', 'Sylvester Stallone Sharon Stone James Woods'),
(2637, 'based on novel small town dream motel hallucination bridge alien life-form warning tumor west virginia urban legend premonition telephone call hospital reporter psychic car wreck death of wife mothman mysterious events chemical plant', 'The Mothman Prophecies', 'Reporter John Klein is plunged into a world of impossible terror and unthinkable chaos when fate draws him to a sleepy West Virginia town whose residents are being visited by a great winged shape that sows hideous nightmares and fevered visions.', 'en', 14.733513, 6.1, 'Drama Horror Mystery', '', 'Richard Gere Laura Linney Will Patton'),
(2639, 'new york writer\'s block insanity independent film author', 'Deconstructing Harry', 'This film tells the story of a successful writer called Harry Block, played by Allen himself, who draws inspiration from people he knows in real-life, and from events that happened to him, sometimes causing these people to become alienated from him as a result.', 'en', 11.352693, 7.3, 'Comedy Drama', 'Woody Allen', 'Woody Allen Kirstie Alley Billy Crystal'),
(2642, 'new york parish hall romantic comedy lawyer billionaire environmental law', 'Two Weeks Notice', 'Dedicated environmental lawyer Lucy Kelson goes to work for billionaire George Wade as part of a deal to preserve a community center. Indecisive and weak-willed George grows dependent on Lucy\'s guidance on everything from legal matters to clothing. Exasperated, Lucy gives notice and picks Harvard graduate June Carter as her replacement. As Lucy\'s time at the firm nears an end, she grows jealous of June and has second thoughts about leaving George.', 'en', 24.153567, 5.9, 'Romance Comedy', '', 'Sandra Bullock Hugh Grant Alicia Witt'),
(2649, 'brother brother relationship birthday danger of life birthday party surprising', 'The Game', 'In honor of his birthday, San Francisco banker Nicholas Van Orton, a financial genius and a coldhearted loner, receives an unusual present from his younger brother, Conrad -- a gift certificate to play a unique kind of game. In nearly a nanosecond, Nicholas finds himself consumed by a dangerous set of ever-changing rules, unable to distinguish where the charade ends and reality begins.', 'en', 62.925175, 7.5, 'Drama Thriller Mystery', '', 'Michael Douglas Sean Penn Deborah Kara Unger'),
(2655, 'secret haunted house ouija board haunting missing girl ghost', 'What Lies Beneath', 'When Claire Spencer starts hearing ghostly voices and seeing spooky images, she wonders if an otherworldly spirit is trying to contact her. All the while, her husband tries to reassure her by telling her it\'s all in her head. But as Claire investigates, she discovers that the man she loves might know more than he\'s letting on.', 'en', 15.835672, 6.3, 'Drama Horror Mystery Thriller', 'Robert Zemeckis', 'Harrison Ford Michelle Pfeiffer Diana Scarwid');
INSERT INTO `movies` (`movie_id`, `tags`, `title`, `overview`, `original_language`, `popularity`, `vote_average`, `genres`, `directeur`, `acteurs`) VALUES
(2661, 'double life dc comics dual identity chemical crime fighter fictional place gotham city superhero super powers', 'Batman', 'The Dark Knight of Gotham City begins his war on crime with his first major enemy being the clownishly homicidal Joker, who has seized control of Gotham\'s underworld.', 'en', 44.104469, 7, 'Fantasy Action', '', 'Adam West Burt Ward Lee Meriwether'),
(2662, 'upper class halloween psychopath urban legend youth satanic ritual', 'House of 1000 Corpses', 'Two teenage couples traveling across the backwoods of Texas searching for urban legends of serial killers end up as prisoners of a bizarre and sadistic backwater family of serial killers.', 'en', 19.301432, 6, 'Horror', '', 'Sid Haig Bill Moseley Sheri Moon Zombie'),
(2666, 'soul sleep manipulation future dystopia chaos memory duel parallel world tech noir matrix neo-noir retrofuturism', 'Dark City', 'A man struggles with memories of his past, including a wife he cannot remember, in a nightmarish world with no sun and run by beings with telekinetic powers who seek the souls of humans.', 'en', 39.324831, 7.2, 'Mystery Science Fiction', '', 'Rufus Sewell William Hurt Kiefer Sutherland'),
(2667, 'witch voodoo legend sorcery maryland forest footage horror true student lost found footage film', 'The Blair Witch Project', 'In October of 1994 three student filmmakers disappeared in the woods near Burkittsville, Maryland, while shooting a documentary. A year later their footage was found.', 'en', 41.690578, 6.3, 'Horror Mystery', 'Daniel Myrick', 'Michael C. Williams Heather Donahue Joshua Leonard'),
(2669, 'female nudity exotic island mutiny lake nudity sailing ship adventure tahiti murder pregnancy great barrier reef sailor native peoples storm at sea whipping british sailor based on true events fiji', 'The Bounty', 'The familiar story of Lieutenant Bligh, whose cruelty leads to a mutiny on his ship. This version follows both the efforts of Fletcher Christian to get his men beyond the reach of British retribution, and the epic voyage of Lieutenant Bligh to get his loyalists safely to East Timor in a tiny lifeboat.', 'en', 7.436491, 6.5, 'Action Drama History', '', 'Mel Gibson Anthony Hopkins Laurence Olivier'),
(2675, 'symbolism water farm faith alien family relationships rural setting alien invasion rural crop circle alien attack rural pennsylvania rural america rural farm loss of faith alien encounter', 'Signs', 'A family living on a farm finds mysterious crop circles in their fields which suggests something more frightening to come.', 'en', 28.848187, 6.4, 'Drama Thriller Science Fiction Mystery', '', 'Mel Gibson Joaquin Phoenix Rory Culkin'),
(2687, 'invisible man', 'Memoirs of an Invisible Man', 'After a freak accident, an invisible yuppie runs for his life from a treacherous CIA official while trying to cope with his new life.', 'en', 7.222985, 5.7, 'Comedy Fantasy Science Fiction', '', 'Chevy Chase Daryl Hannah Sam Neill'),
(2698, 'father son relationship daily life married couple support father marriage faith baustelle rescue animal nature duringcreditsstinger noah\'s ark', 'Evan Almighty', 'God contacts Congressman Evan Baxter and tells him to build an ark in preparation for a great flood.', 'en', 27.082182, 5.3, 'Fantasy Comedy Family', '', 'Steve Carell Lauren Graham John Goodman'),
(2749, 'new york female nudity prison prostitute rape robbery fire detective airport shotgun prisoner ex-detainee attempted murder paranoia russian eastern europe video knife fistfight police thief revenge video camera escape breast dead body lawyer shot to death torture fear new york city urination violence home invasion criminal police detective death drunk nypd news report gun violence graveyard death of boyfriend', '15 Minutes', 'When Eastern European criminals Oleg and Emil come to New York City to pick up their share of a heist score, Oleg steals a video camera and starts filming their activities, both legal and illegal. When they learn how the American media circus can make a remorseless killer look like the victim and make them rich, they target media-savvy NYPD Homicide Detective Eddie Flemming and media-naive FDNY Fire Marshal Jordy Warsaw, the cops investigating their murder and torching of their former criminal partner, filming everything to sell to the local tabloid TV show \"Top Story.\"', 'en', 15.205371, 5.7, 'Action Crime Thriller', '', 'Robert De Niro Charlize Theron Edward Burns'),
(2752, 'sex addiction laundromat', '40 Days and 40 Nights', 'Matt Sullivan\'s last big relationship ended in disaster and ever since his heart\'s been aching and his commitment\'s been lacking. Then came Lent, that time of year when everybody gives something up. That\'s when Matt decides to go where no man\'s gone before and make a vow: No sex. Whatsoever. For 40 straight days. At first he has everything under control. That is until the woman of his dreams, Erica, walks into his life.', 'en', 14.18136, 5.2, 'Comedy Romance', 'Michael Lehmann', 'Josh Hartnett Shannyn Sossamon Adam Trese'),
(2755, 'wife husband relationship channel surfing mullet spiritual journey life changing pioneer village family gathering', 'About Schmidt', '66-year-old Warren Schmidt is a retired insurance salesman and has no particular plans other than to drive around in the motor home his wife insisted they buy. He\'s not altogether bitter, but not happy either, as everything his wife does annoys him, and he disapproves of the man his daughter is about to marry. When his wife suddenly dies, he sets out to postpone the imminent marriage of his daughter to a man he doesn\'t like, while coping with discoveries about his late wife and himself in the process.', 'en', 19.925026, 6.7, 'Drama Comedy', 'Alexander Payne', 'Jack Nicholson Kathy Bates Hope Davis'),
(2756, 'ocean sea diving suit flying saucer nuclear missile alien life-form insanity scuba diving underwater scuba deepsea trapped underwater  thalassophobia', 'The Abyss', 'A civilian oil rig crew is recruited to conduct a search and rescue effort when a nuclear submarine mysteriously sinks. One diver soon finds himself on a spectacular odyssey 25,000 feet below the ocean\'s surface where he confronts a mysterious force that has the power to change the world or destroy it.', 'en', 24.961625, 7.1, 'Adventure Action Thriller Science Fiction', '', 'Ed Harris Mary Elizabeth Mastrantonio Michael Biehn'),
(2757, 'alligator marriage crisis writer\'s block orchid', 'Adaptation.', 'A love-lorn script writer grows increasingly desperate in his quest to adapt the book \'The Orchid Thief\'.', 'en', 26.441669, 7.3, 'Comedy Crime Drama', '', 'Nicolas Cage Meryl Streep Chris Cooper'),
(2770, 'sex party summer beach house group of friends gross out comedy tantra mistaken for a special education student superglue sex comedy', 'American Pie 2', 'The whole gang are back and as close as ever. They decide to get even closer by spending the summer together at a beach house. They decide to hold the biggest party ever to be seen, even if the preparation doesn\'t always go to plan. Especially when Stifler, Finch and Jim become more close to each other than they ever want to be and when Jim mistakes super glue for lubricant...', 'en', 36.432598, 6, 'Comedy Romance', '', 'Jason Biggs Thomas Ian Nicholas Chris Klein'),
(2771, 'biography independent film v.a. hospital junk sale jellybean greeting card file clerk garage sale comic book art neurotic woman director', 'American Splendor', 'An original mix of fiction and reality illuminates the life of comic book hero everyman Harvey Pekar.', 'en', 7.792851, 7.1, 'Comedy Drama', 'Shari Springer Berman', 'Paul Giamatti Hope Davis Judah Friedlander'),
(2779, 'hypnosis independent film', 'The Curse of the Jade Scorpion', 'CW Briggs is a veteran insurance investigator, with many successes. Betty Ann Fitzgerald is a new employee in the company he works for, with the task of reorganizing the office. They don\'t like each other - or at least that\'s what they think. During a night out with the rest of the office employees, they go to watch Voltan, a magician who secretly hypnotizes both of them.', 'en', 9.317265, 6.5, 'Comedy Crime Mystery Romance Thriller', 'Woody Allen', 'Dan Aykroyd Helen Hunt Woody Allen'),
(2786, 'paris painting independent film money bombing bullet dock french noir', 'Pierrot le Fou', 'Pierrot escapes his boring society and travels from Paris to the Mediterranean Sea with Marianne, a girl chased by hit-men from Algeria. They lead an unorthodox life, always on the run.', 'fr', 7.791898, 7.6, 'Drama Thriller', '', 'Jean-Paul Belmondo Anna Karina Graziella Galvani'),
(2787, 'darkness dystopia comet alien life-form survival eclipse flask corps', 'Pitch Black', 'When their ship crash-lands on a remote planet, the marooned passengers soon learn that escaped convict Riddick isn\'t the only thing they have to fear. Deadly creatures lurk in the shadows, waiting to attack in the dark, and the planet is rapidly plunging into the utter blackness of a total eclipse. With the body count rising, the doomed survivors are forced to turn to Riddick with his eerie eyes to guide them through the darkness to safety. With time running out, there\'s only one rule: Stay in the light.', 'en', 18.493202, 6.7, 'Thriller Science Fiction Action', '', 'Vin Diesel Radha Mitchell Cole Hauser'),
(2789, 'prison dystopia matter of life and death outer space intergalactic travel', 'The Chronicles of Riddick', 'After years of outrunning ruthless bounty hunters, escaped convict Riddick suddenly finds himself caught between opposing forces in a fight for the future of the human race. Now, waging incredible battles on fantastic and deadly worlds, this lone, reluctant hero will emerge as humanity\'s champion - and the last hope for a universe on the edge of annihilation.', 'en', 27.835436, 6.3, 'Action Science Fiction', '', 'Vin Diesel Thandie Newton Karl Urban'),
(2832, 'weather multiple character scream convict psychopathy rainstorm', 'Identity', 'Complete strangers stranded at a remote desert motel during a raging storm soon find themselves the target of a deranged murderer. As their numbers thin out, the travelers begin to turn on each other, as each tries to figure out who the killer is.', 'en', 45.915165, 7.1, 'Mystery Thriller', 'James Mangold', 'John Cusack Ray Liotta Amanda Peet'),
(2841, 'paris prostitute loss of lover amnesia bodily disabled person world war i wheelchair brittany lighthouse verdun lighthouse keeper    teenage crush disappearance soldier illegal prostitution private detective missing person polio trenches', 'A Very Long Engagement', 'In 1919, Mathilde was 19 years old. Two years earlier, her fiancé Manech left for the front at the Somme. Like millions of others he was \"killed on the field of battle.\" It\'s written in black and white on the official notice. But Mathilde refuses to believe it. If Manech had died, she would know. She hangs on to her intuition as tightly as she would onto the last thread of hope linking her to her lover. A former sergeant tells her in vain that Manech died in the no man\'s land of a trench named Bingo Crepescule, in the company of four other men condemned to die for self-inflicted wounds. Her path ahead is full of obstacles but Mathilde is not frightened. Anything is possible to someone who is willing to challenge fate...', 'fr', 23.05451, 7.1, 'Drama', 'Jean-Pierre Jeunet', 'Audrey Tautou Gaspard Ulliel Dominique Pinon'),
(2895, 'christianity coma jealousy radio station texas apostle minister louisiana forgiveness independent film preacher', 'The Apostle', 'After his happy life spins out of control, a preacher from Texas changes his name, goes to Louisiana and starts preaching on the radio.', 'en', 4.227807, 6.1, 'Drama', 'Robert Duvall', 'Robert Duvall Billy Bob Thornton June Carter Cash'),
(2898, 'single parent waitress lone wolf friendship neighbor author cowardliness writer dog rude obnoxious unlikely friendship noodle salad', 'As Good as It Gets', 'New York City. Melvin Udall, a cranky, bigoted, obsessive-compulsive writer, finds his life turned upside down when neighboring gay artist Simon is hospitalized and his dog is entrusted to Melvin. In addition, Carol, the only waitress who will tolerate him, must leave work to care for her sick son, making it impossible for Melvin to eat breakfast.', 'en', 37.885022, 7.2, 'Comedy Romance', 'James L. Brooks', 'Jack Nicholson Helen Hunt Greg Kinnear'),
(2900, 'wife husband relationship space travel space mission pregnancy astronaut', 'The Astronaut\'s Wife', 'When astronaut Spencer Armacost returns to Earth after a mission that nearly cost him his life, he decides to take a desk job in order to see his beautiful wife, Jillian, more often. Gradually, Jillian notices that Spencer\'s personality seems to have changed, but her concerns fade when she discovers that she\'s pregnant. As Jillian grows closer to becoming a mother, her suspicions about Spencer return. Why does it seem as if he\'s a different person?', 'en', 20.697556, 5.4, 'Drama Science Fiction Thriller', '', 'Johnny Depp Charlize Theron Joe Morton'),
(2907, 'dead wish vampire black humor uncle eccentric werewolf macabre loan shark accountant', 'The Addams Family', 'Uncle Fester has been missing for 25 years. An evil doctor finds out and introduces a fake Fester in an attempt to get the Adams Family\'s money. The youngest daughter has some doubts about the new uncle Fester, but the fake uncle adapts very well to the strange family. Can the doctor carry out her evil plans and take over the Adams Family\'s fortune?', 'en', 37.179547, 6.7, 'Horror Comedy Fantasy', 'Barry Sonnenfeld', 'Raúl Juliá Anjelica Huston Christopher Lloyd'),
