(63006, 'goa drug bust rave party', 'Dum Maaro Dum', 'We hurtle into the bylanes, beach shacks and raves of Goa with Lorry as his life spirals out of control, with Joki as he tries to redeem the past and with Kamath as he goes no-holds-barred after the mysterious shadow figure behind it all... Punctuated with a soundtrack that moves from pulsating dance tracks to haunting Konkani songs, shot right in the midst of the teeming international tourist hotspots, Dum Maaro Dum takes you on a dramatic, thrilling trip filled with twists, turns, suspense... and a shocking finale!', 'hi', 0.075817, 5.4, 'Drama Action Crime Foreign', 'Rohan Sippy', 'Abhishek Bachchan Bipasha Basu Deepika Padukone'),
(63020, 'immigration independent film woman director political prisoner cuban refugees', 'The Perez Family', 'In the midst of the Mariel boat lift -- a hurried exodus of refugees from Cuba going to America -- an immigration clerk accidentally presumes that dissident Juan Raul Perez and Dorita Evita Perez are married. United by their last name and a mutual resolve to emigrate, Dorita and Juan agree to play along. But it gets complicated when the two begin falling for each other just as Juan reunites with his wife, Carmela, whom he hasn\'t seen in decades.', 'en', 1.187671, 6.6, 'Comedy Drama Romance', '', 'Marisa Tomei Alfred Molina Anjelica Huston'),
(63492, 'based on novel loser magazine womanizer mission search boyfriend husband fired past relationship', 'What\'s Your Number?', 'Ally Darling (Anna Faris) is realizing she\'s a little lost in life. Her latest romance has just fizzled out, and she\'s just been fired from her marketing job. Then she reads an eye-opening magazine article that warns that 96 percent of women who\'ve been with 20 or more lovers are unlikely to find a husband. Determined to turn her life around and prove the article wrong, Ally embarks on a mission to find the perfect mate from among her numerous ex-boyfriends.', 'en', 19.220789, 6.2, 'Comedy Romance', '', 'Chris Evans Anna Faris Martin Freeman'),
(63574, '', 'Joyful Noise', 'G.G. Sparrow faces off with her choir\'s newly appointed director, Vi Rose Hill, over the group\'s direction as they head into a national competition.', 'en', 5.753705, 6.7, 'Comedy Music', '', 'Queen Latifah Dolly Parton Keke Palmer'),
(64328, 'musical the muppets robot oil tycoon studio tour duringcreditsstinger', 'The Muppets', 'When Kermit the Frog and the Muppets learn that their beloved theater is slated for demolition, a sympathetic human, Gary, and his puppet roommate, Walter, swoop in to help the gang put on a show and raise the $10 million they need to save the day.', 'en', 17.047276, 6.5, 'Comedy Family Music', 'James Bobin', 'Amy Adams Jason Segel Emily Blunt'),
(64499, '', 'Quinceañera', 'As Magdalena\'s 15th birthday approaches, her simple, blissful life is complicated by the discovery that she\'s pregnant. Kicked out of her house, she finds a new family with her great-granduncle and gay cousin.', 'it', 0.034135, 7, 'Drama', '', 'Emily Rios Jesse Garcia Chalo González'),
(64559, '', 'The Swindle', 'Betty and Victor are a pair of scam artists. One day Betty brings in Maurice, a treasurer of a multinational company. Maurice is due to transfer 5 millions francs out of Switzerland, and Betty is convinced he plans to steal that money.', 'fr', 0.627964, 6.4, 'Comedy Crime Thriller', '', 'Michel Serrault Isabelle Huppert François Cluzet'),
(64639, 'southern usa rape bar wife husband relationship barn machismo rifle home invasion', 'Straw Dogs', 'L.A. screenwriter David Sumner relocates with his wife, Amy, to her hometown in the deep South. There, while tensions build between them, a brewing conflict with locals becomes a threat to them both.', 'en', 7.473455, 5.5, 'Drama Thriller', '', 'James Marsden Kate Bosworth Alexander Skarsgård'),
(64678, 'philosophy mentor artist painting friendship teen movie teenager sketching rebellious youth', 'The Art of Getting By', 'George, a lonely and fatalistic teen who\'s made it all the way to his senior year without ever having done a real day of work, is befriended by Sally, a popular but complicated girl who recognizes in him a kindred spirit.', 'en', 12.690224, 6.5, 'Drama Romance', '', 'Freddie Highmore Emma Roberts Michael Angarano'),
(64682, 'based on novel infidelity obsession hope 3d', 'The Great Gatsby', 'An adaptation of F. Scott Fitzgerald\'s Long Island-set novel, where Midwesterner Nick Carraway is lured into the lavish world of his neighbor, Jay Gatsby. Soon enough, however, Carraway will see through the cracks of Gatsby\'s nouveau riche existence, where obsession, madness, and tragedy await.', 'en', 61.196071, 7.3, 'Drama Romance', '', 'Leonardo DiCaprio Tobey Maguire Carey Mulligan'),
(64685, 'based on novel autism key scavenger hunt death of father young boy new york city tambourine lock grieving post 9/11', 'Extremely Loud & Incredibly Close', 'A year after his father\'s death, Oskar, a troubled young boy, discovers a mysterious key he believes was left for him by his father and embarks on a scavenger hunt to find the matching lock.', 'en', 31.066874, 6.9, 'Drama', 'Stephen Daldry', 'Thomas Horn Tom Hanks Sandra Bullock');
INSERT INTO `movies` (`movie_id`, `tags`, `title`, `overview`, `original_language`, `popularity`, `vote_average`, `genres`, `directeur`, `acteurs`) VALUES
(64686, 'japan suicide samurai based on true story samurai sword ronin shogun half breed 3d', '47 Ronin', 'Based on the original 1941 movie from Japan, and from ancient Japan’s most enduring tale, the epic 3D fantasy-adventure 47 Ronin is born.  Keanu Reeves leads the cast as Kai, an outcast who joins Oishi (Hiroyuki Sanada), the leader of the 47 outcast samurai.  Together they seek vengeance upon the treacherous overlord who killed their master and banished their kind.  To restore honor to their homeland, the warriors embark upon a quest that challenges them with a series of trials that would destroy ordinary warriors.', 'en', 41.796339, 5.9, 'Drama Action Adventure Fantasy', '', 'Keanu Reeves Hiroyuki Sanada Kou Shibasaki'),
(64688, 'male friendship high school parody crude humor based on tv series undercover cop buddy cop buddy comedy duringcreditsstinger', '21 Jump Street', 'In high school, Schmidt was a dork and Jenko was the popular jock. After graduation, both of them joined the police force and ended up as partners riding bicycles in the city park. Since they are young and look like high school students, they are assigned to an undercover unit to infiltrate a drug ring that is supplying high school students synthetic drugs.', 'en', 62.714026, 6.7, 'Action Comedy Crime', '', 'Channing Tatum Jonah Hill Brie Larson'),
(64689, 'poker gambling robbery based on novel hitman economy murder blood hit mobster gangster criminal', 'Killing Them Softly', 'Jackie Cogan is an enforcer hired to restore order after three dumb guys rob a Mob protected card game, causing the local criminal economy to collapse.', 'en', 24.612603, 5.8, 'Crime Thriller', '', 'Brad Pitt Scoot McNairy Ben Mendelsohn'),
(64690, 'stuntman blood splatter independent film police chase extreme violence violence car chase bullet head stomp getaway crime lord existentialism silent protagonist great soundtrack', 'Drive', 'A Hollywood stunt performer who moonlights as a wheelman for criminals discovers that a contract has been put on him after a heist gone wrong.', 'en', 49.294864, 7.4, 'Drama Action Thriller Crime', '', 'Ryan Gosling Carey Mulligan Bryan Cranston'),
(64807, 'father son relationship sport rivalry elderly elderly man', 'Grudge Match', 'A pair of aging boxing rivals are coaxed out of retirement to fight one final bout -- 30 years after their last match.', 'en', 21.362949, 6, 'Comedy', '', 'Robert De Niro Sylvester Stallone Alan Arkin'),
(64973, '', 'Peace, Propaganda & the Promised Land', 'This video shows how the foreign policy interests of American political elites-working in combination with Israeli public relations stratgies-influence US news reporting about the Middle East conflict. Combining American and British TV news clips with observations of analysts, journalists and political activists, Peace, Propaganda &amp; the Promised Land provides a brief historical overview, a striking media comparison, and an examination of factors that have distorted U.S. media coverage and, in turn, American public opinion.', 'en', 0.020168, 6.4, 'Documentary', 'Sut Jhally', ''),
(65055, 'shark attack louisiana dirty cop shark aftercreditsstinger', 'Shark Night', 'A weekend at a lake house in the Louisiana Gulf turns into a nightmare for seven vacationers as they are subjected to fresh-water shark attacks.', 'en', 8.363702, 4.9, 'Horror Thriller', 'David R. Ellis', 'Sara Paxton Chris Carmack Joel David Moore'),
(65057, 'hawaii father-in-law daughter cheating wife beach house boating accident estate dying mother beautiful girl teenage daughter trustee trust fund wild girl wild child realtor', 'The Descendants', 'With his wife Elizabeth on life support after a boating accident, Hawaiian land baron, Matt King takes his daughters on a trip from Oahu to Kauai to confront the young real estate broker, who was having an affair with Elizabeth before her misfortune.', 'en', 40.903931, 6.7, 'Comedy Drama', '', 'George Clooney Shailene Woodley Amara Miller'),
(65086, 'london england secret remake revenge lawyer photograph gothic horror hammer horror estate ghost supernatural power', 'The Woman in Black', 'The story follows a young lawyer, Arthur Kipps, who is ordered to travel to a remote village and sort out a recently deceased client’s papers. As he works alone in the client’s isolated house, Kipps begins to uncover tragic secrets, his unease growing when he glimpses a mysterious woman dressed only in black. Receiving only silence from the locals, Kipps is forced to uncover the true identity of the Woman in Black on his own, leading to a desperate race against time when he discovers her true identity.', 'en', 43.675191, 6.1, 'Drama Horror Thriller', '', 'Daniel Radcliffe Ciarán Hinds Sidney Johnston'),
(65203, 'musical singer pre-code wisecrack humor early sound film partially lost film', 'The Broadway Melody', 'Harriet and Queenie Mahoney, a vaudeville act, come to Broadway, where their friend Eddie Kerns needs them for his number in one of Francis Zanfield\'s shows. Eddie was in love with Harriet, but when he meets Queenie, he falls in love to her, but she is courted by Jock Warriner, a member of the New Yorker high society. It takes a while till Queenie recognizes, that she is for Jock nothing more than a toy, and it also takes a while till Harriet recognizes, that Eddie is in love with Queenie', 'en', 0.968865, 5, 'Drama Music Romance', '', 'Charles King Anita Page Bessie Love'),
(65448, 'prison boxing', 'Penitentiary', 'A hitchhiker named Martel Gordone gets in a fight with two bikers over a prostitute, and one of the bikers is killed. Gordone is arrested and sent to prison, where he joins the prison\'s boxing team in an effort to secure an early parole and to establish his dominance over the prison\'s toughest gang.', 'en', 0.001117, 4.9, 'Action Drama', 'Jamaa Fanaka', 'Wilbur \'Hi-Fi\' White Leon Isaac Kennedy Thommy Pollard '),
(65749, 'dancer tango musical love', 'Tango', 'A dangerous love affair inspires a director to create the most spectacular and bodly seductive dance film ever made. 1998 Oscar Nominee Best Foreign Language Film.', 'es', 0.425551, 6.8, 'Drama Foreign Romance', 'Carlos Saura', 'Miguel Ángel Solá Cecilia Narova Mía Maestro'),
(65754, 'rape journalist based on novel journalism hacker nazis punk investigation remake antisocial personality disorder serial killer disappearance hacking computer hacker bible quote scandinavian abuse', 'The Girl with the Dragon Tattoo', 'This English-language adaptation of the Swedish novel by Stieg Larsson follows a disgraced journalist, Mikael Blomkvist, as he investigates the disappearance of a weary patriarch\'s niece from 40 years ago. He is aided by the pierced, tattooed, punk computer hacker named Lisbeth Salander. As they work together in the investigation, Blomkvist and Salander uncover immense corruption beyond anything they have ever imagined.', 'en', 47.651083, 7.2, 'Thriller Crime Mystery Drama', '', 'Daniel Craig Rooney Mara Christopher Plummer'),
(65759, 'penguin musical aftercreditsstinger 3d', 'Happy Feet Two', 'Mumble the penguin has a problem: his son Erik, who is reluctant to dance, encounters The Mighty Sven, a penguin who can fly! Things get worse for Mumble when the world is shaken by powerful forces, causing him to brings together the penguin nations and their allies to set things right.', 'en', 17.7735, 5.8, 'Animation Comedy Family', '', 'Elijah Wood Robin Williams Pink'),
(66125, '1970s human animal relationship australia grief search dog death mourning based on true events australian outback dog missing', 'Red Dog', 'Based on the legendary true story of the Red Dog who united a disparate local community while roaming the Australian outback in search of his long lost master.', 'en', 5.499412, 7.1, 'Drama Comedy Family', '', 'Josh Lucas Rachael Taylor Rohan Nichol'),
(66195, 'swimming pool tea kettle conga line spit in the face convenience store robbery', 'The Perfect Host', 'A criminal on the run cons his way into the wrong dinner party where the host is anything but ordinary.', 'en', 6.507094, 6.2, 'Comedy Thriller Crime', 'Nick Tomnay', 'David Hyde Pierce Clayne Crawford Nathaniel Parker'),
(66607, '', 'Saving Private Perez', 'La vida ha llevado a Julián Pérez por caminos equivocados, pero el destino le presentará a este hombre la oportunidad de encontrar su redención cuando es enviado a la misión más peligrosa y noble de toda su vida, una misión ordenada por la única autoridad que todavía respeta, su madre, Doña Elvira. Julián debe viajar hasta el otro extremo del mundo, a un lugar llamado Irak, a traer de vuelta vivo, a su hermano menor el soldado de infantería Juan Pérez. Con la promesa hecha, Julián Pérez regresa a su natal Sinaloa donde reclutará a un comando de elite, destinado a cumplir una misión suicida: viajar a Irak y salvar al soldado Pérez.', 'en', 0.177356, 6.1, 'Action Comedy Foreign', 'Beto Gómez', 'Joaquín Cosio Gerardo Taracena Jaime Camil'),
(66767, 'sporting event', 'Beat the World', 'Three dance crews – one Latin American, one European and one Canadian – prepare to battle at the International Beat the World competition in Detroit. Along the way, they struggle with gambling debt, bad break-ups and their own egos. In the final showdown to become world champions they find that their lifelong hopes, dreams and even lives, are at stake.', 'en', 2.873796, 4.3, 'Music Drama', 'Robert Adetuyi', 'Tyrone Brown Mishael Morgan Nikki Grant'),
(66942, 'love superhero independent film comedy', 'Griff the Invisible', 'Griff, office worker by day, superhero by night, has his world turned upside down when he meets Melody, a beautiful young scientist who shares his passion for the impossible.', 'en', 1.35088, 6.1, 'Romance Comedy Drama', 'Leon Ford', 'Ryan Kwanten Maeve Dermody Marshall Napier'),
(67238, '', 'Cavite', 'Adam, a security guard, travels from California to the Philippines, his native land, for his father\'s funeral. He arrives in Manila. As he waits, a phone rings in his backpack; he answers it, and a male voice tells him that his mother and sister are captives and will be killed if Adam doesn\'t cooperate. Over the next hour, the voice sends Adam by bus, taxi, motorized tricycle, and on foot through an urban landscape of busy streets, cramped apartments, a fetid squatters\' camp, a bank, a cockfighting arena, and a church. Adam\'s conversations with the voice cover murder, Islam, jihad, rebellion in Mindanao, and his family. What is it Adam will be commanded to do?', 'en', 0.022173, 7.5, 'Foreign Thriller', 'Neill Dela Llana', ''),
(67675, 'concert live performance duringcreditsstinger', 'Glee: The Concert Movie', 'A concert documentary shot during the Glee Live! In Concert! summer 2011 tour, featuring song performances and Glee fans\' life stories and how the show influenced them.', 'en', 9.933926, 6.8, 'Documentary Music Family', '', 'Dianna Agron Lea Michele Gwyneth Paltrow'),
(67911, 'porno star hollywood', 'Bucky Larson: Born to Be a Star', 'A kid from the Midwest moves out to Hollywood in order to follow in his parents footsteps -- and become a porn star.', 'en', 3.919057, 4.4, 'Comedy', 'Tom Brady', 'Nick Swardson Christina Ricci Stephen Dorff'),
(67913, 'prostitute blackmail drug smuggle rural ireland dry humour', 'The Guard', 'Two policemen must join forces to take on an international drug- smuggling gang - one, an unorthodox Irish policeman and the other, a straitlaced FBI agent. Sergeant Gerry Boyle is an eccentric small-town cop with a confrontational and crass personality and a subversive sense of humor. A longtime policeman in County Galway, Boyle is a maverick with his own moral code. He has seen enough of the world to know there isn\'t much to it and has had plenty of time to think about it. When a fellow police officer disappears and Boyle\'s small town becomes key to a large drug trafficking investigation, he is forced to at least feign interest when dealing with the humorless FBI agent Wendell Everett assigned to the case.', 'en', 19.411141, 6.8, 'Action Comedy Thriller Crime', '', 'Brendan Gleeson Don Cheadle Liam Cunningham'),
(68179, 'spaceship alien rescue escape planet astronaut Γη mission control', 'Escape from Planet Earth', 'Astronaut Scorch Supernova finds himself caught in a trap when he responds to an SOS from a notoriously dangerous alien planet.', 'en', 18.14218, 5.7, 'Animation Comedy Adventure Family Science Fiction', '', 'Brendan Fraser Rob Corddry Ricky Gervais'),
(68412, 'independent film', '3 Backyards', 'The story of three people from the same suburban town during the course of one curious autumn day.', 'en', 0.17817, 4.8, 'Drama', 'Eric Mendelsohn', 'Edie Falco Embeth Davidtz Elias Koteas'),
(68684, 'high school murder slasher horror spoof', 'Detention', 'As a killer named Cinderhella stalks the student body at the high school in Grizzly Lake, a group of co-eds band together to survive while they\'re all serving detention.', 'en', 10.424596, 5.7, 'Horror Comedy Science Fiction', 'Joseph Kahn', 'Shanley Caswell Josh Hutcherson Spencer Locke'),
(68718, 'bounty hunter hero plantation society friendship friends revenge rivalry rescue shootout racism danger dentist django dual role aftercreditsstinger odd couple black slave deadly chases and races 19th century', 'Django Unchained', 'With the help of a German bounty hunter, a freed slave sets out to rescue his wife from a brutal Mississippi plantation owner.', 'en', 82.121691, 7.8, 'Drama Western', 'Quentin Tarantino', 'Jamie Foxx Christoph Waltz Leonardo DiCaprio'),
(68721, 'terrorist war on terror tennessee malibu marvel comic superhero based on comic book tony stark iron man aftercreditsstinger marvel cinematic universe mandarin 3d war machine iron patriot extremis', 'Iron Man 3', 'When Tony Stark\'s world is torn apart by a formidable terrorist called the Mandarin, he starts an odyssey of rebuilding and retribution.', 'en', 77.68208, 6.8, 'Action Adventure Science Fiction', 'Shane Black', 'Robert Downey Jr. Gwyneth Paltrow Don Cheadle'),
(68722, 'post traumatic stress  disorder sexual obsession postwar period drifter alcoholic cult leader scientology religious cult charismatic leader right hand man', 'The Master', 'Freddie, a volatile, heavy-drinking veteran who suffers from post-traumatic stress disorder, finds some semblance of a family when he stumbles onto the ship of Lancaster Dodd, the charismatic leader of a new \"religion\" he forms after World War II.', 'en', 25.682509, 7, 'Drama', 'Paul Thomas Anderson', 'Joaquin Phoenix Philip Seymour Hoffman Amy Adams'),
(68724, 'dystopia space station class conflict', 'Elysium', 'In the year 2159, two classes of people exist: the very wealthy who live on a pristine man-made space station called Elysium, and the rest, who live on an overpopulated, ruined Earth. Secretary Rhodes (Jodie Foster), a hard line government ofﬁcial, will stop at nothing to enforce anti-immigration laws and preserve the luxurious lifestyle of the citizens of Elysium. That doesn’t stop the people of Earth from trying to get in, by any means they can. When unlucky Max (Matt Damon) is backed into a corner, he agrees to take on a daunting mission that, if successful, will not only save his life, but could bring equality to these polarized worlds.', 'en', 67.33767, 6.4, 'Science Fiction Action Drama Thriller', '', 'Matt Damon Jodie Foster Sharlto Copley'),
(68726, 'dystopia giant robot giant monster apocalypse imax duringcreditsstinger 3d', 'Pacific Rim', 'When legions of monstrous creatures, known as Kaiju, started rising from the sea, a war began that would take millions of lives and consume humanity\'s resources for years on end. To combat the giant Kaiju, a special type of weapon was devised: massive robots, called Jaegers, which are controlled simultaneously by two pilots whose minds are locked in a neural bridge. But even the Jaegers are proving nearly defenseless in the face of the relentless Kaiju. On the verge of defeat, the forces defending mankind have no choice but to turn to two unlikely heroes—a washed-up former pilot (Charlie Hunnam) and an untested trainee (Rinko Kikuchi)—who are teamed to drive a legendary but seemingly obsolete Jaeger from the past. Together, they stand as mankind\'s last hope against the mounting apocalypse.', 'en', 56.523205, 6.7, 'Action Science Fiction Adventure', 'Guillermo del Toro', 'Idris Elba Charlie Hunnam Charlie Day'),
(68727, 'amnesia art thief hypnotism heist movie duringcreditsstinger', 'Trance', 'A fine art auctioneer mixed up with a gang, joins forces with a hypnotherapist to recover a lost painting. As boundaries between desire, reality and hypnotic suggestion begin to blur, the stakes rise faster than anyone could have anticipated.', 'en', 38.802415, 6.5, 'Thriller Crime Drama Mystery', 'Danny Boyle', 'James McAvoy Vincent Cassel Rosario Dawson'),
(68728, 'circus witch magic hope illusion lost magic trick wizard 3d', 'Oz: The Great and Powerful', 'Oscar Diggs, a small-time circus illusionist and con-artist, is whisked from Kansas to the Land of Oz where the inhabitants assume he\'s the great wizard of prophecy, there to save Oz from the clutches of evil.', 'en', 46.985445, 5.7, 'Fantasy Adventure Family', '', 'James Franco Mila Kunis Rachel Weisz'),
(68734, 'cia wife husband relationship document revolution hiding place canadian press conference biography hanged man american abroad crane subtitled scene movie poster based on article extraction iran hostage crisis sweatshop intelligence agent film studio langley virginia 1980s', 'Argo', 'As the Iranian revolution reaches a boiling point, a CIA \'exfiltration\' specialist concocts a risky plan to free six Americans who have found shelter at the home of the Canadian ambassador.', 'en', 62.01056, 7.1, 'Drama Thriller', 'Ben Affleck', 'Ben Affleck Bryan Cranston Alan Arkin'),
(68735, 'video game elves orcs magic chase based on comic book sorcerer fictional war based on video game wizard fictional language muscles orc sword and sorcery', 'Warcraft', 'The peaceful realm of Azeroth stands on the brink of war as its civilization faces a fearsome race of invaders: orc warriors fleeing their dying home to colonize another. As a portal opens to connect the two worlds, one army faces destruction and the other faces extinction. From opposing sides, two heroes are set on a collision course that will decide the fate of their family, their people, and their home.', 'en', 63.148529, 6.3, 'Action Adventure Fantasy', '', 'Paula Patton Travis Fimmel Ben Foster'),
(68737, 'magic chosen one dark fantasy witch hunter evil witch based on young adult novel sword and sorcery', 'Seventh Son', 'John Gregory, who is a seventh son of a seventh son and also the local spook, has protected the country from witches, boggarts, ghouls and all manner of things that go bump in the night. However John is not young anymore, and has been seeking an apprentice to carry on his trade. Most have failed to survive. The last hope is a young farmer\'s son named Thomas Ward. Will he survive the training to become the spook that so many others couldn\'t?', 'en', 63.628459, 5.2, 'Adventure Fantasy', '', 'Jeff Bridges Julianne Moore Ben Barnes'),
(68812, 'new jersey restaurant hitman van arrest psychopath based on true story jail serial murder stabbing crime family bombing ice cream man   drug deal contract killer crime syndicate poisoning', 'The Iceman', 'The true story of Richard Kuklinski, the notorious contract killer and family man.', 'en', 19.494703, 6.4, 'Thriller Crime Drama', '', 'Michael Shannon Winona Ryder Ray Liotta'),
(68818, 'robbery miner treachery sundance kid native peoples butch cassidy', 'Blackthorn', 'In Bolivia, Butch Cassidy (now calling himself James Blackthorne) pines for one last sight of home, an adventure that aligns him with a young robber and makes the duo a target for gangs and lawmen alike.', 'en', 5.223096, 6.6, 'Adventure Action Western', 'Mateo Gil', 'Sam Shepard Magaly Solier Eduardo Noriega'),
(68924, 'based on novel 1970s thanksgiving dysfunctional family independent film', 'The Ice Storm', 'In the weekend after thanksgiving 1973 the Hoods are skidding out of control. Benjamin Hood reels from drink to drink, trying not to think about his trouble at the office. His wife, Elena, is reading self help books and losing patience with her husband\'s lies. Their son, Paul, home for the holidays, escapes to the city to pursue an alluring rich girl from his prep school. Young, budding nymphomaniac, Wendy Hood roams the neighborhood, innocently exploring liquor cabinets and lingerie drawers of her friends\' parents, looking for something new. Then an ice storm hits, the worst in a century.', 'en', 14.916264, 6.9, 'Drama', 'Ang Lee', 'Kevin Kline Joan Allen Sigourney Weaver'),
(69270, '', 'Super Hybrid', 'Late one night, a mysterious car is brought into the Chicago police impound garage after a deadly traffic accident. The on-call mechanics soon discover the car has a mind of its own. With hundreds of horsepower and two tons of reinforced steel at its command, it\'s a seemingly unstoppable killing machine capable of outrunning -- and outwitting -- humans.', 'en', 4.009379, 4.6, 'Horror', 'Eric Valette', 'Shannon Beckner Oded Fehr Ryan Kennedy'),
(69382, '', 'The Legend of God\'s Gun', 'A gun-slinging preacher returns to the debaucherous town of Playa Diablo seeking revenge from the notorious scorpion-venom drinking bandito El Sobero - lead outlaw and number one bad guy. El Sobero and his band of bad banditos are also returning to Playa Diablo seeking their own revenge against the town sheriff. With the Bounty Hunter dragging up slowly behind there is sure to be a confrontation of Biblical proportions as they all meet in the circle of death.', 'en', 0.003582, 0, 'Action Western', 'Mike Bruce', 'Robert Bones Kirpatrick Thomas Dave Koenig'),
(69640, 'suicide family secrets blind woman director', 'Lies in Plain Sight', '“Lies in Plain Sight” tells the story of Eva and her blind cousin Sofia (Martha Higareda), who were inseparable as children, with Eva the loyal companion who helped Sofia through her tough adolescent years. When Eva suddenly commits suicide, Sofia rushes home to her father, Hector (Benito Martinez), and Eva’s parents, Marisol (Rosie Perez) and Rafael (Yul Vásquez), to find answers. But the more she delves into Eva’s life, questioning her past boyfriends Ethan (Chad Michael Murray) and Christian (Christoph Sanders), the more Sofia realizes that their childhood was actually filled with dark, disturbing secrets.', 'en', 0.47909, 4.5, 'Drama Mystery Thriller', 'Patricia Cardoso', 'Martha Higareda Chad Michael Murray Yul Vazquez'),
(69668, 'house fire extension ladder last day on job', 'Dream House', 'Publisher, Will Atenton quits a lucrative job in New York to relocate his wife, Libby and their daughters to a quaint town in New England. However, as they settle into their home the Atentons discover that a woman and her children were murdered there, and the surviving husband is the town\'s prime suspect. With help from a neighbor who was close to the murdered family, Will pieces together a horrifying chain of events.', 'en', 19.267479, 5.8, 'Drama Thriller Mystery', '', 'Daniel Craig Naomi Watts Rachel Weisz'),
(69848, 'war army battlefield chivalry', 'One Man\'s Hero', 'One Man\'s Hero tells the little-known story of the \"St. Patrick\'s Battalion\" or \"San Patricios,\" a group of mostly Irish and other immigrants of the Catholic faith who deserted to Mexico after encountering religious and ethnic prejudice in the U.S. Army during the Mexican-American War. The plot centers around the personal story of John Riley, an Irishman who had been a sergeant in the American Army who is commissioned as a captain in the Mexican army and commands the battalion, as he leads his men in battle and struggles with authorities on both sides of the border', 'en', 0.910529, 9.3, 'Western Action Drama History', '', 'Tom Berenger Joaquim de Almeida Daniela Romo'),
(70006, 'male nudity cage kiss fistfight sport cage fighting kickboxer martial arts tournament beefcake martial arts training', 'Never Back Down 2: The Beatdown', 'Four fighters different backgrounds come together to train under an ex MMA rising star and then ultimately have to fight each other and the traitor in heir midst.', 'en', 9.249229, 5.8, 'Drama Action', '', 'Stacey Asaro Gralen Bryant Banks Rus Blackwell'),
(70074, '', 'Bullet to the Head', 'After watching their respective partners die, a cop and a hitman form an alliance in order to bring down their common enemy.', 'en', 22.503935, 5.2, 'Action Crime Thriller', 'Walter Hill', 'Sylvester Stallone Sung Kang Sarah Shahi'),
(70160, 'hallucination dystopia female protagonist bow and arrow knife throwing knife fight game archery blindness glamour roasted pig sponsor chariot fictional tv show mine explosion based on young adult novel', 'The Hunger Games', 'Every year in the ruins of what was once North America, the nation of Panem forces each of its twelve districts to send a teenage boy and girl to compete in the Hunger Games.  Part twisted entertainment, part government intimidation tactic, the Hunger Games are a nationally televised event in which “Tributes” must fight with one another until one survivor remains.  Pitted against highly-trained Tributes who have prepared for these Games their entire lives, Katniss is forced to rely upon her sharp instincts as well as the mentorship of drunken former victor Haymitch Abernathy.  If she’s ever to return home to District 12, Katniss must make impossible choices in the arena that weigh survival against humanity and life against love. The world will be watching.', 'en', 68.550698, 6.9, 'Science Fiction Adventure Fantasy', '', 'Jennifer Lawrence Josh Hutcherson Liam Hemsworth'),
(70435, 'mercenary secret agent rescue foot chase spanish', 'Haywire', 'Mallory Kane is a highly trained operative who works for a government security contractor in the dirtiest, most dangerous corners of the world. After successfully freeing a Chinese journalist held hostage, she is double crossed and left for dead by someone close to her in her own agency. Suddenly the target of skilled assassins who know her every move, Mallory must find the truth in order to stay alive.', 'en', 26.257951, 5.6, 'Action Thriller', 'Steven Soderbergh', 'Gina Carano Ewan McGregor Michael Fassbender'),
(70436, 'poison blackmail masked ball historical figure buried alive serial killer deadline edgar allan poe newspaper review baltimore maryland newspaper office hard times life imitates art pendulum', 'The Raven', 'A fictionalized account of the last days of Edgar Allan Poe\'s life, in which the poet is in pursuit of a serial killer whose murders mirror those in the writer\'s stories.', 'en', 22.520842, 6.1, 'Crime Thriller Mystery', '', 'John Cusack Luke Evans Alice Eve'),
(70478, 'female nudity lesbian erotic movie', 'The Stewardesses', 'The Stewardesses is a 1969 Softcore 3-D film. Produced on a budget of just over $100,000, the film grossed over $27,000,000 (USD) in 1970 dollars, becoming the most profitable 3-D film ever released. This has now been passed by James Camerons Avatar.', 'en', 1.183892, 4.3, 'Comedy', 'Al Silliman Jr.', 'Christina Hart Ronald South William Condos'),
(70670, 'death of lover art thief art gallery police investigation', 'Headhunters', 'An accomplished headhunter risks everything to obtain a valuable painting owned by a former mercenary..', 'en', 20.821846, 7.1, 'Thriller Crime', '', 'Aksel Hennie Nikolaj Coster-Waldau Synnøve Macody Lund'),
(70687, 'future bisexuality time travel woman director', 'The Sticky Fingers of Time', 'A 1950s author (Terumi Matthews) is transported to 1990s Brooklyn, where she meets a woman (Nicole Zaray) who reads about her life.', 'en', 0.130169, 4.8, 'Science Fiction Drama', 'Hilary Brougher', 'Terumi Matthews Nicole Zaray Belinda Becker'),
(70829, '', 'The Last Godfather', 'Young-goo the son of mafia boss Don Carini, is too foolish to be part of the mafia elite. One day, Young-goo comes to his father and is trained by Tony V to be his father\'s successor. A few days later, Young-goo accidentally rescues Nancy, the only daughter of Don Bonfante, the boss of a rival mafia family. But Vinnie, an under-boss of the Bonfante family kidnapped her and fabricates that Young-goo has taken her. Vinnie\'s behavior provokes an armed conflict between the two families.', 'en', 0.680753, 4.7, 'Action Comedy Thriller', 'Shim Hyung-Rae', 'Harvey Keitel Jason Mewes Blake Clark'),
(70868, 'pregnancy family vacation widower working mum in-laws', 'I Don\'t Know How She Does It', 'A comedy centered on the life of Kate Reddy, a finance executive who is the breadwinner for her husband and two kids.', 'en', 8.630825, 5, 'Romance Comedy', 'Douglas McGrath', 'Sarah Jessica Parker Pierce Brosnan Sarah Shahi'),
(70875, 'migration immigration agriculture food human rights pesticide environment children\'s rights migrant farmworker labor latino child labor', 'The Harvest (La Cosecha)', 'The story of the children who work 12-14 hour days in the fields without the protection of child labor laws. These children are not toiling in the fields in some far away land. They are working in America.', 'en', 0.010909, 0, 'Documentary', 'U. Roberto Romano', ''),
(70981, 'android dystopia alien spin off creation emergency surgery aftercreditsstinger stasis archeological dig god complex cave drawing genetic mutation origins of life', 'Prometheus', 'A team of explorers discover a clue to the origins of mankind on Earth, leading them on a journey to the darkest corners of the universe. There, they must fight a terrifying battle to save the future of the human race.', 'en', 68.889395, 6.3, 'Science Fiction Adventure Mystery', 'Ridley Scott', 'Noomi Rapace Michael Fassbender Guy Pearce'),
(71157, 'woman director', 'Polisse', 'The daily grind for the cops of the Police Department\'s Juvenile Protection Unit - taking in child molesters, busting underage pickpockets, interrogating abusive parents, confronting the excesses of teen sexuality, enjoying solidarity with colleagues and laughing uncontrollably at the most unthinkable moments. Knowing the worst exists and living with it. How do these cops balance their private lives and the reality they confront every working day? Fred, the group\'s hypersensitive wild card, is going to have a hard time facing the scrutiny of Melissa, a photographer on a Ministry of the Interior assignment to document the unit.', 'fr', 14.038703, 7.9, 'Drama', '', 'Karin Viard JoeyStarr Marina Foïs'),
(71469, 'alien invasion american abroad moscow unlikely heroes failed business', 'The Darkest Hour', 'In Moscow, five young people lead the charge against an alien race which has attacked Earth via our power supply.', 'en', 23.328823, 4.8, 'Horror Action Thriller Science Fiction', '', 'Emile Hirsch Rachael Taylor Olivia Thirlby'),
(71552, 'wife husband relationship sequel family reunion masturbation scat high school reunion quitting a job milf duringcreditsstinger', 'American Reunion', 'The characters we met a little more than a decade ago are returning to East Great Falls for their high-school reunion. In one long-overdue weekend, they will discover what has changed, who hasn’t and that time and distance can’t break the bonds of friendship. It was summer 1999 when four small-town Michigan boys began a quest to lose their virginity. In the years that have passed, Jim and Michelle married while Kevin and Vicky said goodbye. Oz and Heather grew apart, but Finch still longs for Stifler’s mom. Now these lifelong friends have come home as adults to reminisce about – and get inspired by – the hormonal teens who launched a comedy legend.', 'en', 39.920035, 6.1, 'Comedy', '', 'Jason Biggs Alyson Hannigan Seann William Scott'),
(71676, 'monk eastern europe skeleton biker marvel comic superhero motorcycle devil dark hero ghost rider', 'Ghost Rider: Spirit of Vengeance', 'When the devil resurfaces with aims to take over the world in human form, Johnny Blaze reluctantly comes out of hiding to transform into the flame-spewing supernatural hero Ghost Rider -- and rescue a 10-year-old boy from an unsavory end.', 'en', 48.622278, 4.7, 'Action Fantasy Thriller', '', 'Nicolas Cage Ciarán Hinds Violante Placido'),
(71679, 'mutant dystopia sequel conspiracy tokyo japan zombie based on video game moscow hand to hand combat virus plague pandemic mega corporation', 'Resident Evil: Retribution', 'The Umbrella Corporation’s deadly T-virus continues to ravage the Earth, transforming the global population into legions of the flesh eating Undead. The human race’s last and only hope, Alice, awakens in the heart of Umbrella’s most clandestine operations facility and unveils more of her mysterious past as she delves further into the complex. Without a safe haven, Alice continues to hunt those responsible for the outbreak; a chase that takes her from Tokyo to New York, Washington, D.C. and Moscow, culminating in a mind-blowing revelation that will force her to rethink everything that she once thought to be true. Aided by new found allies and familiar friends, Alice must fight to survive long enough to escape a hostile world on the brink of oblivion. The countdown has begun.', 'en', 6.227675, 5.6, 'Action Horror Science Fiction', 'Paul W.S. Anderson', 'Milla Jovovich Sienna Guillory Michelle Rodriguez'),
(71805, 'island ship pirate sailor cabin boy 19th century', 'Shipwrecked', 'A young Norwegian boy in 1850s England goes to work as a cabin boy and discovers some of his shipmates are actually pirates.', 'en', 0.702971, 6.1, 'Adventure Family', '', 'Stian Smestad Gabriel Byrne Louisa Milwood-Haigh'),
(71859, 'suburb violence killing spree prison visit guinea pig broken arm potty training woman director', 'We Need to Talk About Kevin', 'The mother of a teenage sociopath who went on a high-school killing spree recalls her son\'s deranged behavior during childhood, as she deals with her grief.', 'en', 21.276864, 7.4, 'Drama Thriller', '', 'John C. Reilly Tilda Swinton Ezra Miller'),
(71864, 'green dodgeball incredibile timothy', 'The Odd Life of Timothy Green', 'A childless couple bury a box in their backyard, containing all of their wishes for an infant. Soon, a child is born, though Timothy Green is not all that he appears.', 'en', 16.394452, 6.5, 'Fantasy Drama Comedy Family', 'Peter Hedges', 'Jennifer Garner Joel Edgerton Ron Livingston'),
(71866, 'boarding school woman director', 'Tanner Hall', 'Tanner Hall is a vivid peek into the private world of an all-girls boarding school. In a cozy, but run down New England, the knot of adolescent complexity is unraveled through the coming of age stories of four teen-age girls.', 'en', 2.015525, 5.4, 'Drama', 'Francesca Gregorini', 'Rooney Mara Georgia King Brie Larson'),
(71880, 'duringcreditsstinger', 'Jack and Jill', 'Jack Sadelstein, a successful advertising executive in Los Angeles with a beautiful wife and kids, dreads one event each year: the Thanksgiving visit of his twin sister Jill. Jill\'s neediness and passive-aggressiveness is maddening to Jack, turning his normally tranquil life upside down.', 'en', 22.132418, 4.1, 'Comedy', '', 'Adam Sandler Katie Holmes Al Pacino'),
(72086, 'revenge escape from prison suspense', 'The Night Visitor', 'An insane Swedish farmer escapes from an asylum to get revenge on his sister, her husband and others.', 'en', 0.074005, 7.3, 'Crime Horror', 'László Benedek', 'Max von Sydow Trevor Howard Liv Ullmann'),
(72105, 'friendship love teddy bear toy comes to life wishes come true', 'Ted', 'John Bennett, a man whose childhood wish of bringing his teddy bear to life came true, now must decide between keeping the relationship with the bear or his girlfriend, Lori.', 'en', 68.87691, 6.3, 'Comedy Fantasy', '', 'Mark Wahlberg Mila Kunis Seth MacFarlane'),
(72113, 'flat mobile phone hamster insult dark comedy writer tulips meeting puke pants liberal', 'Carnage', 'After 11-year-old Zachary Cowan strikes his classmate across the face with a stick after an argument, the victim\'s parents invite Zachary\'s parents to their Brooklyn apartment to deal with the incident in a civilized manner.', 'en', 20.011435, 7, 'Comedy Drama', '', 'Kate Winslet Jodie Foster Christoph Waltz'),
(72190, 'dystopia apocalypse zombie nuclear weapons multiple perspectives zombie apocalypse', 'World War Z', 'Life for former United Nations investigator Gerry Lane and his family seems content. Suddenly, the world is plagued by a mysterious infection turning whole human populations into rampaging mindless zombies. After barely escaping the chaos, Lane is persuaded to go on a mission to investigate this disease. What follows is a perilous trek around the world where Lane must brave horrific dangers and long odds to find answers before human civilization falls.', 'en', 81.834855, 6.7, 'Action Drama Horror Science Fiction Thriller', '', 'Brad Pitt Mireille Enos Abigail Hargrove'),
(72197, 'rivalry stop motion pirate aftercreditsstinger duringcreditsstinger', 'The Pirates! In an Adventure with Scientists!', 'The luxuriantly bearded Pirate Captain is a boundlessly enthusiastic, if somewhat less-than-successful, terror of the High Seas. With a rag-tag crew at his side, and seemingly blind to the impossible odds stacked against him, the Captain has one dream: to beat his bitter rivals Black Bellamy and Cutlass Liz to the much coveted Pirate of the Year Award. It’s a quest that takes our heroes from the shores of exotic Blood Island to the foggy streets of Victorian London. Along the way they battle a diabolical queen and team up with a haplessly smitten young scientist, but never lose sight of what a pirate loves best: adventure!', 'en', 23.700759, 6.4, 'Animation Adventure Family Comedy', 'Peter Lord', 'Hugh Grant Brendan Gleeson Jeremy Piven'),
(72207, 'sex san francisco restaurant frustration chase offer engagement love psychologist wedding proposal chef ceremony englishwoman ring unemployed', 'The Five-Year Engagement', 'Exactly one year after Tom meets Violet, he surprises her with a wedding ring. By all accounts, Tom and Violet are destined for their happily ever after. However, this engaged couple just keep getting tripped up on the long walk down the aisle.', 'en', 27.71063, 5.7, 'Comedy', '', 'Jason Segel Emily Blunt Chris Pratt'),
(72213, 'father faith', 'Courageous', 'As law enforcement officers, Adam Mitchell, Nathan Hayes, and their partners are confident and focused. They willingly stand up to the worst the streets have to offer. Yet at the end of the day, they face a challenge that none of them are truly prepared to tackle: fatherhood. They know that God desires to turn the hearts of fathers to their children, but their children are beginning to drift further and further away from them. When tragedy hits home, these men are left wrestling with their hopes, their fears, their faith, and their fathering. Can a new found urgency help these dads draw closer to God ... and to their children? COURAGEOUS is the fourth release of Sherwood Pictures, the movie making ministry of Sherwood Church in Albany, Georgia.', 'en', 5.961119, 6.8, 'Drama', 'Alex Kendrick', 'Alex Kendrick Ken Bevel Ben Davies'),
(72331, 'usa president vampire steam locomotive american civil war 19th century abraham lincoln 3d', 'Abraham Lincoln: Vampire Hunter', 'President Lincoln\'s mother is killed by a supernatural creature, which fuels his passion to crush vampires and their slave-owning helpers.', 'en', 38.634767, 5.5, 'Action Fantasy Horror', '', 'Benjamin Walker Dominic Cooper Anthony Mackie'),
(72358, 'liar literary agent', 'A Thousand Words', 'Jack McCall is a fast-talking literary agent, who can close any deal, any time, any way. He has set his sights on New Age guru Dr. Sinja (Cliff Curtis) for his own selfish purposes. But Dr. Sinja is on to him, and Jack’s life comes unglued after a magical Bodhi tree mysteriously appears in his backyard. With every word Jack speaks, a leaf falls from the tree and he realizes that when the last leaf falls, both he and the tree are toast. Words have never failed Jack McCall, but now he’s got to stop talking and conjure up some outrageous ways to communicate or he’s a goner.', 'en', 13.119133, 6, 'Drama Comedy', '', 'Eddie Murphy Allison Janney Cliff Curtis'),
(72387, 'broken trachea', 'Safe', 'After a former elite agent rescues a 12-year-old Chinese girl who\'s been abducted, they find themselves in the middle of a standoff between Triads, the Russian Mafia and high-level corrupt New York City politicians and police.', 'en', 31.92695, 6.3, 'Action Crime Thriller', '', 'Jason Statham Chris Sarandon James Hong'),
(72431, 'world war ii fighter pilot fighter plane', 'Red Tails', 'The story of the Tuskegee Airmen, the first African-American pilots to fly in a combat squadron during World War II.', 'en', 12.29603, 5.9, 'Drama Action Adventure History War', '', 'Bryan Cranston David Oyelowo Cuba Gooding Jr.'),
(72545, 'mission mysterious island missing person duringcreditsstinger 3d', 'Journey 2: The Mysterious Island', 'Sean Anderson partners with his mom\'s boyfriend on a mission to find his grandfather, who is thought to be missing on a mythical island.', 'en', 40.723459, 5.8, 'Adventure Action Science Fiction', '', 'Dwayne Johnson Josh Hutcherson Kristin Davis'),
(72559, 'terror assassin secret technology missile warhead president rescue conspiracy explosion battle surveillance cobra', 'G.I. Joe: Retaliation', 'Framed for crimes against the country, the G.I. Joe team is terminated by Presidential order. This forces the G.I. Joes into not only fighting their mortal enemy Cobra; they are forced to contend with threats from within the government that jeopardize their very existence.', 'en', 59.325589, 5.4, 'Adventure Action Science Fiction Thriller', '', 'Dwayne Johnson D.J. Cotrona Adrianne Palicki'),
(72570, 'coma amnesia based on true story memory loss car accident romantic drama', 'The Vow', 'Happy young married couple Paige and Leo are, well, happy. Then a car accident puts Paige into a life-threatening coma. Upon awakening she has lost the previous five years of memories, including those of her beloved Leo, her wedding, a confusing relationship with her parents, or the ending of her relationship with her ex-fiance. Despite these complications, Leo endeavors to win her heart again and rebuild their marriage.', 'en', 26.780961, 7, 'Drama Romance', '', 'Rachel McAdams Channing Tatum Sam Neill'),
(72571, 'witch sister sister relationship sequel prequel haunting found footage', 'Paranormal Activity 3', 'In 1988, evil begins to terrorize young sisters Katie and Kristi for the first time when an invisible entity resides in their home.', 'en', 29.15813, 5.9, 'Horror', '', 'Katie Featherston Sprague Grayden Lauren Bittner'),
(72710, 'based on novel mass murder dystopia genocide alien invasion duringcreditsstinger interspecies romance alien parasites', 'The Host', 'A parasitic alien soul is injected into the body of Melanie Stryder. Instead of carrying out her race\'s mission of taking over the Earth, \"Wanda\" (as she comes to be called) forms a bond with her host and sets out to aid other free humans.', 'en', 42.933027, 6, 'Action Adventure Romance Science Fiction Thriller', '', 'Saoirse Ronan Diane Kruger Jake Abel'),
(72766, '', 'Newlyweds', 'A newlywed couple\'s honeymoon is upended by the arrivals of their respective sisters.', 'en', 0.642552, 5.9, 'Comedy Romance', 'Edward Burns', 'Edward Burns Kerry Bishé Marsha Dietlein'),
(72914, 'diet fasting vegetable juice australian man', 'Fat, Sick & Nearly Dead', '100 pounds overweight, loaded up on steroids and suffering from a debilitating autoimmune disease, Joe Cross is at the end of his rope and the end of his hope. In the mirror he saw a 310lb man whose gut was bigger than a beach ball and a path laid out before him that wouldn\'t end well— with one foot already in the grave, the other wasn\'t far behind. FAT, SICK &amp; NEARLY DEAD is an inspiring film that chronicles Joe\'s personal mission to regain his health.', 'en', 0.545825, 7.1, 'Documentary', 'Joe Cross', 'Joe Cross Phil Riverstone Amy Badberg'),
(72976, 'usa president speech battlefield family conflict mourning american civil war cultural conflict based on true events battle of gettysburg secession presidential cabinet gettysburg address conflagration ethical dilemma emancipation abraham lincoln', 'Lincoln', 'A revealing drama that focuses on the 16th President\'s tumultuous final months in office. In a nation divided by war and the strong winds of change, Lincoln pursues a course of action designed to end the war, unite the country and abolish slavery. With the moral courage and fierce determination to succeed, his choices during this critical moment will change the fate of generations to come.', 'en', 36.307296, 6.7, 'History Drama', 'Steven Spielberg', 'Daniel Day-Lewis Sally Field David Strathairn'),
(73191, 'ballet', 'The Nutcracker', 'On Christmas Eve, a little girl named Marie (Cohen) falls asleep after a party at her home and dreams herself into a fantastic world where toys become larger than life. She meets up with the Nutcracker Prince (Culkin) who defends her from the Mouse King.', 'en', 0.068228, 5.6, 'Family Fantasy Music', 'Emile Ardolino', 'Darci Kistler Damian Woetzel Bart Robinson Cook'),
(73247, 'servant future chase lovers outlaw robot', 'Heartbeeps', 'Heartbeeps stars Andy Kaufman and Bernadette Peters as domestic robots who fall in love and run off together.', 'en', 0.518056, 3.8, 'Comedy Romance Family', '', 'Andy Kaufman Bernadette Peters Randy Quaid'),
(73511, '', 'The Californians', 'When real estate mogul Gavin Ransom (Noah Wyle) announces his plan to cover California\'s northern coast with scores of mini-mansions, his environmentalist sister, Olive (Ileana Douglas), launches a protest to stop him. But there\'s trouble ahead when Gavin begins falling for the pretty folk singer (Kate Mara) who\'s helping Olive\'s cause. This clever West Coast satire from writer-director Jonathan Parker is a twist on Henry James\'s The Bostonians.', 'en', 0.218736, 4, 'Drama Comedy', '', 'Noah Wyle Illeana Douglas Kate Mara'),
(73532, 'poverty policeman shoe shiner northern france', 'Le Havre', 'Marcel Marx, a former bohemian and struggling author, has given up his literary ambitions and relocated to the port city Le Havre. He leads a simple life based around his wife Arletty, his favourite bar and his not too profitable profession as a shoeshiner. As Arletty suddenly becomes seriously ill, Marcel\'s path crosses with an underage illegal immigrant from Africa, who needs Marcel\'s help to hide from the police.', 'fr', 10.787322, 6.8, 'Drama Comedy', 'Aki Kaurismäki', 'André Wilms Kati Outinen Blondin Miguel'),
(73567, 'trailer park gun texas deal psychopath sexual humiliation money lingerie arson police detective physical abuse neo-noir burial pizza shop drugs', 'Killer Joe', 'A cop (Matthew McConaughey) who moonlights as a hit man agrees to kill the hated mother of a desperate drug dealer (Emile Hirsch) in exchange for a tumble with the young man\'s virginal sister (Juno Temple).', 'en', 16.436178, 6.5, 'Crime Drama Thriller', '', 'Matthew McConaughey Emile Hirsch Thomas Haden Church'),
(73873, 'butler dublin maid', 'Albert Nobbs', 'Albert Nobbs struggles to survive in late 19th century Ireland, where women aren\'t encouraged to be independent. Posing as a man, so she can work as a butler in Dublin\'s most posh hotel, Albert meets a handsome painter and looks to escape the lie she has been living.', 'en', 7.802245, 6.2, 'Drama', '', 'Glenn Close Mia Wasikowska Aaron Taylor-Johnson'),
(73935, 'vampire love woman director', 'Vamps', 'The modern-day story focuses on two beautiful young vampires who are living the good nightlife in New York until love enters the picture and each has to make a choice that will jeopardize their immortality.', 'en', 7.251897, 4.8, 'Comedy Romance Horror', '', 'Alicia Silverstone Krysten Ritter Sigourney Weaver'),
(73937, 'helicopter based on novel honeymoon airplane birding birdwatching duringcreditsstinger', 'The Big Year', 'Three fanatical bird-watchers spend an entire year competing to spot the highest number of species as El Nino sends an extraordinary variety of rare breeds flying up into the U.S., but they quickly discover that there are more important things than coming out on top of the competition', 'en', 9.419726, 5.6, 'Comedy', 'David Frankel', 'Owen Wilson Steve Martin Jack Black'),
(73981, 'philosophy india healing', 'Ayurveda: Art of Being', 'Ayurveda is a science of life and a healing art, where body, mind and spirit are given equal importance. This voyage of thousands of miles across India and abroad takes you on a unique poetic journey, where we encounter remarkable men of medicine or simply a villager who lives in harmony with nature. \"Hope is nature\'s way of enabling us to survive so that we can discover nature itself.\"', 'en', 0.055868, 5.5, 'Documentary', 'Pan Nalin', ''),
(74457, '', 'Redemption Road', 'A Tennessee-set drama focused on an individual\'s spiritual redemption.', 'en', 0.197264, 4.7, 'Drama', 'Mario Van Peebles', 'Michael Clarke Duncan Morgan Simpson Kiele Sanchez'),
(74465, 'zoo', 'We Bought a Zoo', 'Benjamin has lost his wife and, in a bid to start his life over, purchases a large house that has a zoo – welcome news for his daughter, but his son is not happy about it. The zoo is need of renovation and Benjamin sets about the work with the head keeper and the rest of the staff, but, the zoo soon runs into financial trouble.', 'en', 38.629763, 6.5, 'Drama Comedy Family', 'Cameron Crowe', 'Matt Damon Scarlett Johansson Thomas Haden Church');
INSERT INTO `movies` (`movie_id`, `tags`, `title`, `overview`, `original_language`, `popularity`, `vote_average`, `genres`, `directeur`, `acteurs`) VALUES
(74534, 'hotel based on novel india ensemble cast elderly jaipur india personal growth outsourcing', 'The Best Exotic Marigold Hotel', 'British retirees travel to India to take up residence in what they believe is a newly restored hotel. Less luxurious than its advertisements, the Marigold Hotel nevertheless slowly begins to charm in unexpected ways as the residents find new purpose in their old age.', 'en', 21.258991, 6.9, 'Drama Comedy', 'John Madden', 'Bill Nighy Maggie Smith Tom Wilkinson'),
(74643, 'film producer film history movie studio hollywood dog mustache hollywoodland silent film marquee terrier movie star flapper silent film star', 'The Artist', 'Hollywood, 1927: As silent movie star George Valentin wonders if the arrival of talking pictures will cause him to fade into oblivion, he sparks with Peppy Miller, a young dancer set for a big break.', 'en', 29.943316, 7.3, 'Drama Comedy Romance', '', 'Jean Dujardin Bérénice Bejo John Goodman'),
(74777, 'pregnancy declared dead returned alive', 'Absentia', 'Tricia\'s husband Daniel has been missing for seven years. Her younger sister Callie comes to live with her as the pressure mounts to finally declare him \'dead in absentia.\' As Tricia sifts through the wreckage and tries to move on with her life, Callie finds herself drawn to an ominous tunnel near the house. As she begins to link it to other mysterious disappearances, it becomes clear that Daniel\'s presumed death might be anything but \'natural.\' The ancient force at work in the tunnel might have set its sights on Callie and Tricia... and Daniel might be suffering a fate far worse than death in its grasp.', 'en', 6.328665, 5.8, 'Mystery Horror Thriller', 'Mike Flanagan', 'Katie Parker Courtney Bell Morgan Peter Brown'),
(75174, 'alcohol isolation wolf wilderness forest stranded alaska survival airplane crash fear howling death animal killing freezing animal attack campfire male camaraderie gun in mouth aftercreditsstinger bar fight eaten alive eaten by animal', 'The Grey', 'An oil drilling team struggles to survive after a plane crash strands them in the wilds of Alaska. Hunting them is a pack of wolves that sees them as intruders.', 'en', 48.552871, 6.4, 'Action Drama Thriller', '', 'Liam Neeson Dermot Mulroney Frank Grillo'),
(75531, 'autism based on article', 'Isn\'t She Great', 'An unsuccessful over-the-top actress becomes a successful over-the-top authoress in this biography of Jacqueline Susann, the famed writer of \"The Valley Of The Dolls\" and other trashy novels. Facing a failing career, Susann meets a successful promoter who becomes her husband. After several failures to place her in commercials and a TV quiz show, he hits upon the idea for her to become a writer. In the pre-60\'s, her books were looked upon as trash and non-printable. But then the sexual revolution hit and an audience was born for her books. The story shows the hidden behind the scenes story of Susan\'s life, including her autistic son and her continuing bout with cancer that she hid up to her death', 'de', 1.068453, 4.6, 'Drama Comedy', '', 'Bette Midler Nathan Lane Stockard Channing'),
(75612, 'spacecraft dystopia space drone imax human vs alien', 'Oblivion', 'Jack Harper is one of the last few drone repairmen stationed on Earth.  Part of a massive operation to extract vital resources after decades of war with a terrifying threat known as the Scavs, Jack’s mission is nearly complete.  His existence is brought crashing down when he rescues a beautiful  stranger from a downed spacecraft.  Her arrival triggers a chain of events that  forces him to question everything he knows and puts the fate of humanity in his hands.', 'en', 67.698004, 6.4, 'Action Science Fiction Adventure Mystery', '', 'Tom Cruise Morgan Freeman Olga Kurylenko'),
(75638, 'paranormal psychic skepticism', 'Red Lights', 'Two investigators of paranormal hoaxes, the veteran Dr. Margaret Matheson and her young assistant, Tom Buckley, study the most varied metaphysical phenomena with the aim of proving their fraudulent origins. Simon Silver, a legendary blind psychic, reappears after an enigmatic absence of 30 years to become the greatest international challenge to both orthodox science and professional sceptics. Tom starts to develop an intense obsession with Silver, whose magnetism becomes stronger with each new manifestation of inexplicable events. As Tom gets closer to Silver, tension mounts, and his worldview is threatened to its core.', 'en', 22.748174, 6, 'Thriller', 'Rodrigo Cortés', 'Sigourney Weaver Robert De Niro Cillian Murphy'),
(75656, 'paris bank secret fbi vault magic new orleans investigation heist conspiracy money escape new york city las vegas explosion', 'Now You See Me', 'An FBI agent and an Interpol detective track a team of illusionists who pull off bank heists during their performances and reward their audiences with the money.', 'en', 71.124686, 7.3, 'Thriller Crime', '', 'Jesse Eisenberg Mark Ruffalo Woody Harrelson'),
(75780, 'based on novel sniper investigation police quarry', 'Jack Reacher', 'In an innocent heartland city, five are shot dead by an expert sniper. The police quickly identify and arrest the culprit, and build a slam-dunk case. But the accused man claims he\'s innocent and says \"Get Jack Reacher.\" Reacher himself sees the news report and turns up in the city. The defense is immensely relieved, but Reacher has come to bury the guy. Shocked at the accused\'s request, Reacher sets out to confirm for himself the absolute certainty of the man\'s guilt, but comes up with more than he bargained for.', 'en', 56.868399, 6.3, 'Crime Drama Thriller', '', 'Tom Cruise Rosamund Pike Richard Jenkins'),
(75861, 'depression biography drug', 'To Write Love on Her Arms', 'The story follows 19-year-old Renee who has always loved fairy tales: the idea of a princess, a hero and a happily ever after. But Renee’s life is that of a darker tale: she’s a young woman battling addiction, depression and self-injury. In a creative blend of artistic fantasy balanced with harsh reality, the movie follows Renee on her courageous journey towards recovery.', 'en', 6.723057, 6.8, 'Drama Music', 'Nathan Frankowski', 'Kat Dennings Chad Michael Murray Rupert Friend'),
(75900, 'based on novel biography historical figure marilyn monroe', 'My Week with Marilyn', 'Sir Laurence Olivier is making a movie in London. Young Colin Clark, an eager film student, wants to be involved and he navigates himself a job on the set. When film star Marilyn Monroe arrives for the start of shooting, all of London is excited to see the blonde bombshell, while Olivier is struggling to meet her many demands and acting ineptness, and Colin is intrigued by her. Colin\'s intrigue is met when Marilyn invites him into her inner world where she struggles with her fame, her beauty and her desire to be a great actress.', 'en', 21.006078, 6.6, 'Drama', '', 'Michelle Williams Eddie Redmayne Kenneth Branagh'),
(75986, 'obsession radio nudity letter love romance lingerie extramarital affair woman director', 'Love Letters', 'A story of love and obsession. A young radio personality who, after her mother dies, discovers she had been having a love affair for 15 years. Now she finds herself recreating her mother\'s romance by getting involved with a married man.', 'en', 0.001586, 4.6, 'Drama Thriller', '', 'Jamie Lee Curtis Bonnie Bartlett Matt Clark'),
(76025, 'pornography brother sister relationship sex addiction new york city thirty something sex addict', 'Shame', 'Brandon is a New Yorker who shuns intimacy with women but feeds his desires with a compulsive addiction to sex. When his wayward younger sister moves into his apartment stirring memories of their shared painful past, Brandon\'s insular life spirals out of control.', 'en', 40.688426, 7, 'Drama', '', 'Michael Fassbender Carey Mulligan James Badge Dale'),
(76163, 'airplane number in title airplane crash violence beard ensemble cast loss of friend wisecrack humor airport lounge asian woman', 'The Expendables 2', 'Mr. Church reunites the Expendables for what should be an easy paycheck, but when one of their men is murdered on the job, their quest for revenge puts them deep in enemy territory and up against an unexpected threat.', 'en', 53.732892, 6.1, 'Action Adventure Thriller', '', 'Sylvester Stallone Jason Statham Dolph Lundgren'),
(76170, 'japan samurai mutant world war i marvel comic superhero based on comic book superhuman duringcreditsstinger', 'The Wolverine', 'Wolverine faces his ultimate nemesis - and tests of his physical, emotional, and mortal limits - in a life-changing voyage to modern-day Japan.', 'en', 15.953444, 6.3, 'Action Science Fiction Adventure Fantasy', 'James Mangold', 'Hugh Jackman Hiroyuki Sanada Famke Janssen'),
