(107985, 'end of the world apocalypse trilogy homage', 'The World\'s End', 'Five friends who reunite in an attempt to top their epic pub crawl from 20 years earlier unwittingly become humankind\'s only hope for survival.', 'en', 55.964605, 6.7, 'Comedy Action Science Fiction', '', 'Simon Pegg Nick Frost Martin Freeman'),
(108346, 'lust love crime', 'Dreaming of Joseph Lees', 'Set in rural England in the 1950s Eva (Samantha Morton) fantasises about her handsome, worldly cousin Joseph Lees (Rupert Graves), with whom she fell in love as a girl. However, stuck in a closed community she becomes the object of someone else\'s fantasy, Harry (Lee Ross). When Harry learns that Eva is planning to leave the village in order to live with and look after the injured Lees, he devises a gruesome scheme in order to force her to stay and look after him.', 'en', 0.11615, 8, 'Romance Drama', 'Eric Styles', 'Rupert Graves Samantha Morton Nicholas Woodeson'),
