(168672, 'con artist scam mobster fbi agent', 'American Hustle', 'A con man, Irving Rosenfeld, along with his seductive partner Sydney Prosser, is forced to work for a wild FBI agent, Richie DiMaso, who pushes them into a world of Jersey powerbrokers and mafia.', 'en', 49.664128, 6.8, 'Drama Crime', '', 'Christian Bale Bradley Cooper Amy Adams'),
(168705, 'vampire vampire hunter based on video game romania', 'BloodRayne', 'In eighteenth century Romania, Rayne, a dhampir (half-human, half-vampire), prone to fits of blind blood rage but saddled with a compunction for humans, strives to avenge her mother\'s rape by her father, Kagan, King of Vampires. Two vampire hunters, Sebastian and Vladimir, from the Brimstone Society persuade her to join their cause.', 'en', 7.008216, 3.5, 'Action Adventure Fantasy Horror', 'Uwe Boll', 'Kristanna Loken Ben Kingsley Michelle Rodriguez'),
(169917, 'based on novel murder mafia private investigator new york city alcoholic kingpin wife murder matt scudder', 'A Walk Among the Tombstones', 'Private investigator Matthew Scudder is hired by a drug kingpin to find out who kidnapped and murdered his wife.', 'en', 61.309619, 6.2, 'Crime Drama Mystery Thriller', 'Scott Frank', 'Liam Neeson Dan Stevens David Harbour'),
(170480, '', 'The Deported', 'An Italian-American actor is deported to Mexico by some crooked INS Agents, and a pack of orphans helps him find his way back to America', 'en', 0.194848, 0, 'Comedy Family', 'Lance Kawas', 'Nicholas Turturro Talia Shire Paul Rodríguez'),
(170687, 'based on novel stop motion father daughter relationship unlikely friendship duringcreditsstinger', 'The Boxtrolls', 'An orphaned boy raised by underground creatures called Boxtrolls comes up from the sewers and out of his box to save his family and the town from the evil exterminator, Archibald Snatcher.', 'en', 30.656345, 6.6, 'Animation Comedy Family Fantasy', '', 'Ben Kingsley Isaac Hempstead-Wright Elle Fanning'),
(171274, 'based on novel 1970s private investigator smoking marijuana los angeles 1960s', 'Inherent Vice', 'In Los Angeles at the turn of the 1970s, drug-fueled detective Larry \"Doc\" Sportello investigates the disappearance of an ex-girlfriend.', 'en', 45.742217, 6.5, 'Comedy Romance Crime Drama Mystery', 'Paul Thomas Anderson', 'Joaquin Phoenix Josh Brolin Owen Wilson'),
(171424, 'chile gore jungle extreme violence cannibal south america', 'The Green Inferno', 'A group of student activists travel from New York City to the Amazon to save the rainforest.  However, once they arrive in this vast green landscape, they soon discover that they are not alone… and that no good deed goes unpunished.', 'en', 17.845161, 5, 'Action Adventure Horror Thriller', 'Eli Roth', 'Lorenza Izzo Ariel Levy Sky Ferreira'),
(172385, 'bird sequel jungle audition amazon rainforest parrots', 'Rio 2', 'It\'s a jungle out there for Blu, Jewel and their three kids after they\'re hurtled from Rio de Janeiro to the wilds of the Amazon. As Blu tries to fit in, he goes beak-to-beak with the vengeful Nigel, and meets the most fearsome adversary of all: his father-in-law.', 'en', 42.40024, 6.3, 'Animation Adventure Comedy Family', 'Carlos Saldanha', 'Jesse Eisenberg Anne Hathaway Leslie Mann'),
(172533, 'male female relationship co-worker relationship mumblecore', 'Drinking Buddies', 'Weekend trips, office parties, late night conversations, drinking on the job, marriage pressure, biological clocks, holding eye contact a second too long… you know what makes the line between “friends” and “more than friends” really blurry? Beer.', 'en', 17.378455, 6, 'Romance Drama', 'Joe Swanberg', 'Olivia Wilde Jake Johnson Anna Kendrick'),
(173224, 'road movie', 'Along the Roadside', 'Road movie about two young people from different parts of the world, their vastly different clashing cultures and their journey of self-discovery during the drive to the largest music festival in California.', 'en', 0.166655, 7.7, 'Romance Comedy Music', 'Zoran Lisinac', 'Michael Madsen Iman Crosson Lazar Ristovski'),
(173931, '', 'Legend of a Rabbit', 'In order to keep his promise to an aging kung fu master, Fu the Rabbit must venture out of the comfort of his kitchen and team up with Penny, a kung fu prodigy, on a heroic quest to save their kung fu academy.', 'zh', 0.738652, 3, 'Animation Family Action Adventure Comedy', 'Lijun Sun', 'Jon Heder Tom Arnold Michael Clarke Duncan'),
(174362, '', 'Bending Steel', 'The Cyclone, The Freakshow, The Mermaid Parade: all Coney Island icons. But Chris “Wonder” Schoeck has always preferred the Coney Island Strongman. Bending Steel follows the sweet, unassuming Schoeck as he parlays his extraordinary strength into the pursuit of his lifelong dream. Training with an elite group of men whose hands bend, drag, twist and shred metal, he tackles an enormous physical and mental challenge, taking a surprisingly emotional journey as a result.', 'en', 0.048726, 5, 'Documentary', 'Dave Carroll', ''),
(174751, '', 'Jane Got a Gun', 'After her outlaw husband returns home shot with eight bullets and barely alive, Jane reluctantly reaches out to an ex-lover who she hasn\'t seen in over ten years to help her defend her farm when the time comes that her husband\'s gang eventually tracks him down to finish the job.', 'en', 15.333575, 5.4, 'Action Drama Western', '', 'Natalie Portman Joel Edgerton Ewan McGregor');
INSERT INTO `movies` (`movie_id`, `tags`, `title`, `overview`, `original_language`, `popularity`, `vote_average`, `genres`, `directeur`, `acteurs`) VALUES
(175291, 'suspense mumblegore', 'Cheap Thrills', 'Recently fired and facing eviction, a new dad has his life turned upside down when he meets a wealthy couple who offer a path to financial security... but at a price.', 'en', 10.826253, 6.3, 'Drama Comedy Crime', 'E.L. Katz', 'Pat Healy Ethan Embry Sara Paxton'),
(175528, '', 'Baggage Claim', 'Pledging to keep herself from being the oldest and the only woman in her entire family never to wed, Montana embarks on a thirty-day, thirty-thousand-mile expedition to charm a potential suitor into becoming her fiancé.', 'en', 11.436405, 5.6, 'Comedy', '', 'Paula Patton Adam Brody Djimon Hounsou'),
(175541, 'musical based on stage musical woman director based on the bible nativity christmas', 'Black Nativity', 'A street-wise teen from Baltimore who has been raised by a single mother travels to New York City to spend the Christmas holiday with his estranged relatives, where he embarks on a surprising and inspirational journey.', 'en', 7.180403, 5.8, 'Drama Music', 'Kasi Lemmons', 'Forest Whitaker Angela Bassett Jennifer Hudson'),
(175555, 'christmas', 'A Madea Christmas', 'Madea dispenses her unique form of holiday spirit on rural town when she\'s coaxed into helping a friend pay her daughter a surprise visit in the country for Christmas.', 'en', 5.377155, 7, 'Comedy Drama', 'Tyler Perry', 'Tyler Perry Anna Maria Horsford Tika Sumpter'),
(175574, 'holiday thanksgiving freedom duringcreditsstinger 3d', 'Free Birds', 'In this irreverent, hilarious, adventurous buddy comedy for audiences of all ages, directed by Jimmy Hayward (Horton Hears a Who!), two turkeys from opposite sides of the tracks must put aside their differences and team up to travel back in time to change the course of history - and get turkey off the holiday menu for good.', 'en', 14.414937, 5.7, 'Animation Comedy Family', 'Jimmy Hayward', 'Owen Wilson Woody Harrelson Amy Poehler'),
(176074, 'wife husband relationship reality reality tv reality spoof', 'Reality Show', 'The Warwick family are unknowingly being filmed for a new reality show. Problem is, they\'re boring. So the producer must add conflict and drama to their lives. Their lives begin to unravel with shocking consequences.', 'en', 0.472123, 5.5, '', 'Adam Rifkin', 'Adam Rifkin Kelley Menighan Hensley Kendra Sue Waldman'),
(176077, 'composer obsession', 'Enter the Dangerous Mind', 'A psychological thriller set in the world of underground dubstep, Snap is the story of Jim Whitman, a brilliant but painfully introverted musician who develops a crush on a young social worker.', 'en', 1.998826, 4.8, 'Thriller', 'Youssef Delara', 'Jake Hoffman Nikki Reed Thomas Dekker'),
(176124, 'baseball', 'Home Run', 'A pro ball player with a substance abuse problem is forced into rehab in his hometown, finding new hope when he gets honest about his checkered past, and takes on coaching duties for a misfit Little League team', 'en', 3.085411, 6.3, 'Drama', 'David Boyd', 'Scott Elrod Dorian Brown Charles Henry Wyson'),
(177572, 'brother brother relationship hero talent revenge best friend another dimension robot boy genius hate aftercreditsstinger moral dilemma 3d teen superheroes dead brother', 'Big Hero 6', 'The special bond that develops between plus-sized inflatable robot Baymax, and prodigy Hiro Hamada, who team up with a group of friends to form a band of high-tech heroes.', 'en', 203.73459, 7.8, 'Adventure Family Animation Action Comedy', '', 'Scott Adsit Ryan Potter Daniel Henney'),
(177677, 'london england spy austria villain sequel mission conspiracy vienna opera vienna', 'Mission: Impossible - Rogue Nation', 'Ethan and team take on their most impossible mission yet, eradicating the Syndicate - an International rogue organization as highly skilled as they are, committed to destroying the IMF.', 'en', 114.522237, 7.1, 'Action Adventure Thriller', '', 'Tom Cruise Rebecca Ferguson Simon Pegg'),
(178862, 'pornography interview biography photography porno star fashion woman director', 'Aroused', 'Get up close and personal with 16 of the most successful women in the adult film industry as they shed their clothes for an intimate photo shoot with director Deborah Anderson. As questions are asked, personal stories about their lives are revealed, from why they chose the business of sex to how they got into it in the first place. These porn stars have always been discreet about their private lives in the past, yet Anderson has a way of opening up a dialog allowing them to share more than just their naked skin on screen. Their true inner vulnerability is touching, yet the characters they have created are confident and intoxicating. Once you hear their stories, you\'ll never look at them in the same way again.', 'en', 2.557258, 7.2, 'Documentary', 'Deborah Anderson', 'Lisa Ann Kayden Kross Belladonna'),
(180296, '', 'They Came Together', 'A small business owner is about to lose her shop to a major corporate development.', 'en', 12.036888, 5.3, 'Comedy', 'David Wain', 'Paul Rudd Amy Poehler Bill Hader'),
(180383, 'magic woman director', 'Deceptive Practice: The Mysteries and Mentors of Ricky Jay', 'The life and career of renowned magician and sleight of hand artist Ricky Jay.', 'en', 0.425195, 7.1, 'Documentary', '', 'Ricky Jay Dick Cavett Winston Simon'),
(181283, 'based on novel soviet union russian murder serial killer military child murder stalinism 1950s', 'Child 44', 'Set in Stalin-era Soviet Union, a disgraced MGB agent is dispatched to investigate a series of child murders -- a case that begins to connect with the very top of party leadership.', 'en', 40.371098, 6.1, 'Crime Thriller', '', 'Tom Hardy Gary Oldman Noomi Rapace'),
(181330, 'stand-up comedy manhattan, new york city madison square garden duringcreditsstinger', 'Kevin Hart: Let Me Explain', 'Captures the laughter, energy and mayhem from Hart\'s 2012 \"Let Me Explain\" concert tour, which spanned 10 countries and 80 cities, and generated over $32 million in ticket sales.', 'en', 9.799357, 7.1, 'Comedy Documentary', '', 'Kevin Hart David Terrell David Jason Perez'),
(181533, 'night watchman museum natural history history smithsonian', 'Night at the Museum: Secret of the Tomb', 'When the magic powers of The Tablet of Ahkmenrah begin to die out, Larry Daley (Ben Stiller) spans the globe, uniting favorite and new characters while embarking on an epic quest to save the magic before it is gone forever.', 'en', 115.597753, 6.1, 'Adventure Comedy Fantasy Family', '', 'Ben Stiller Rami Malek Rebel Wilson'),
(181940, '', 'Carousel of Revenge', 'When strangers Frank Delano and his Uncle Bobby purchase the local amusement park of a \"peaceful\" resort town they stir up guilt and suspicion among the locals over a murder and suicide the town would rather forget.', 'en', 0.006069, 0, 'Thriller Mystery', 'Gene Teigland', 'Erik Allen Randy Baranczyk Chris Carlson'),
(182291, 'confession hazing gang member latino lgbt catholic priest shakespeare\'s romeo and juliet latino lgbt gang initiation gunplay', 'On The Downlow', 'Isaac and Angel are two young Latinos involved in a south side Chicago gang. They have a secret in a world where secrets are forbidden.', 'en', 0.029757, 6, 'Drama', 'Tadeo Garcia', 'Tony Sancho Michael Cortez Donato Cruz'),
(182873, '', 'Green Street Hooligans: Underground', 'An old firm leader returns to Green Street for Revanche after receiving a call that his little brother was killed, but is he able to cope with a new type of hooliganism and can he find his killer?', 'en', 5.0005, 5.4, 'Action Drama', '', 'Scott Adkins Joey Ansah Kacey Clarke'),
(183894, '', 'Emma', 'Emma Woodhouse seems to be perfectly content, a loving father whom she cares for, friends, and a home. But Emma has a terrible habit - matchmaking. She cannot resist finding suitors for her friends, most of all Harriet Smith. Emma is desperate for Harriet to find happiness, but every suitor she finds for her friend ends up attracted to Emma herself. But is Emma so focused on Harriet\'s happiness that she is not considering her own happiness in love?', 'en', 2.135689, 7.6, 'Romance Comedy Drama', 'Jim O\'Hanlon', 'Romola Garai Michael Gambon Jonny Lee Miller'),
(184098, '', 'Think Like a Man Too', 'All the couples are back for a wedding in Las Vegas, but plans for a romantic weekend go awry when their various misadventures get them into some compromising situations that threaten to derail the big event.', 'en', 15.237142, 6.4, 'Comedy Romance', '', 'Adam Brody Michael Ealy Jerry Ferrara'),
(184315, 'mercenary battle ancient greece hercules warrior sagen', 'Hercules', 'Fourteen hundred years ago, a tormented soul walked the earth that was neither man nor god. Hercules was the powerful son of the god king Zeus, for this he received nothing but suffering his entire life. After twelve arduous labors and the loss of his family, this dark, world-weary soul turned his back on the gods finding his only solace in bloody battle. Over the years he warmed to the company of six similar souls, their only bond being their love of fighting and presence of death. These men and woman never question where they go to fight or why or whom, just how much they will be paid. Now the King of Thrace has hired these mercenaries to train his men to become the greatest army of all time. It is time for this bunch of lost souls to finally have their eyes opened to how far they have fallen when they must train an army to become as ruthless and blood thirsty as their reputation has become.', 'en', 76.842247, 5.6, 'Action Adventure', '', 'Dwayne Johnson Ian McShane John Hurt'),
(184341, '', 'Hands of Stone', 'The legendary Roberto Duran and his equally legendary trainer Ray Arcel change each other\'s lives.', 'en', 7.444189, 6.1, 'Drama', 'Jonathan Jakubowicz', 'Robert De Niro Edgar Ramírez Jurnee Smollett'),
(184345, 'haunted house', 'A Haunted House 2', 'Having exorcised the demons of his ex, Malcolm is starting fresh with his new girlfriend and her two children. After moving into their dream home, however, Malcolm is once again plagued by bizarre paranormal events.', 'en', 18.428909, 5.4, 'Comedy Horror', 'Michael Tiddes', 'Marlon Wayans Jaime Pressly Essence Atkins'),
(184346, 'possessed demon occult demonic possession', 'Deliver Us from Evil', 'When a frightening wave of violence sweeps through New York City, troubled cop Sarchie fails to find a rational explanation for the bizarre crimes. However, his eyes are opened to a frightening alternate reality when renegade Jesuit priest, Mendoza convinces him that demonic possession may be to blame for the gruesome murders. Together, they wage a valiant supernatural struggle to rid the city of an otherworldly evil.', 'en', 29.359201, 5.9, 'Thriller Crime Horror', '', 'Eric Bana Edgar Ramírez Olivia Munn'),
(184374, 'mexican', 'Cinco de Mayo: La Batalla', 'On May 5th, 1862, a few thousand Mexican soldiers put their lives on the line against the world\'s largest and most powerful army in one legendary battle for freedom and for Mexico.', 'es', 0.072085, 5.8, 'War History Drama', '', 'Christian Vazquez Liz Gallardo Angélica Aragón'),
(185008, '', 'Yeh Jawaani Hai Deewani', 'Yeh Jawaani Hai Deewani features two polar opposite characters, who at one point were classmates in Modern School. The first is Naina Talwar (Deepika Padukone), a studious bespectacled young girl. The second is Bunny (Ranbir Kapoor), a carefree young travel-show host, intent on breaking out of the pattern of getting an education, a career, a wife, children, retirement, and eventually death.', 'hi', 3.353176, 7.2, 'Romance', 'Ayan Mukherjee', 'Ranbir Kapoor Deepika Padukone Kalki Koechlin'),
(185465, '', 'Manito', 'Fifteen years ago, their Washington Heights neighborhood was dubbed the crack-cocaine capital of the world, but today it is transforming into one of the most vibrant, Spanish-speaking communities in the United States. While the drug dealers continue to disappear, their violent legacy still casts a shadow over the neighborhood and its residents. Junior, an ex-convict struggling to get his life back on track, is a product of this legacy. His younger brother Manny, the salutatorian of his high school class, embodies the hope of the future. On the night of his graduation party, Manny finds himself faced with an ill-fated decision that could change his life forever', 'en', 0.039264, 5.5, 'Drama', 'Eric Eason', 'Franky G Leo Minaya Manuel Cabral'),
(185567, '', 'Zulu', 'As a child, Ali Neuman narrowly escaped being murdered by Inkhata, a militant political party at war with Nelson Mandela\'s African National Congress. Only he and his mother survived the carnage of those years. But as with many survivors, the psychological scars remain.', 'en', 14.529496, 6.7, 'Crime Drama Thriller', '', 'Orlando Bloom Forest Whitaker Conrad Kemp'),
(187017, 'high school undercover cop buddy comedy aftercreditsstinger duringcreditsstinger', '22 Jump Street', 'After making their way through high school (twice), big changes are in store for officers Schmidt and Jenko when they go deep undercover at a local college. But when Jenko meets a kindred spirit on the football team, and Schmidt infiltrates the bohemian art major scene, they begin to question their partnership. Now they don\'t have to just crack the case - they have to figure out if they can have a mature relationship. If these two overgrown adolescents can grow from freshmen into real men, college might be the best thing that ever happened to them.', 'en', 52.380982, 7, 'Crime Comedy Action', '', 'Jonah Hill Channing Tatum Dave Franco'),
(188161, 'gunslinger farmer wild west laxative', 'A Million Ways to Die in the West', 'As a cowardly farmer begins to fall for the mysterious new woman in town, he must put his new-found courage to the test when her husband, a notorious gun-slinger, announces his arrival.', 'en', 32.808675, 5.8, 'Comedy Western', '', 'Seth MacFarlane Charlize Theron Liam Neeson'),
(188166, 'revenge drifter virginia character study neo-noir visual storytelling mumblegore', 'Blue Ruin', 'The quiet life of a beach bum is upended by dreadful news. He sets off for his childhood home to carry out an act of vengeance but proves an inept assassin and finds himself in a brutal fight to protect his estranged family.', 'en', 25.349758, 6.9, 'Crime Thriller', 'Jeremy Saulnier', 'Macon Blair Devin Ratray Amy Hargreaves'),
(188207, 'mythology zeus ancient greece demigod city of argos mistaken parentage', 'The Legend of Hercules', 'In Ancient Greece 1200 B.C., a queen succumbs to the lust of Zeus to bear a son promised to overthrow the tyrannical rule of the king and restore peace to a land in hardship. But this prince, Hercules, knows nothing of his real identity or his destiny. He desires only one thing: the love of Hebe, Princess of Crete, who has been promised to his own brother. When Hercules learns of his greater purpose, he must choose: to flee with his true love or to fulfill his destiny and become the true hero of his time. The story behind one of the greatest myths is revealed in this action-packed epic - a tale of love, sacrifice and the strength of the human spirit.', 'en', 25.020428, 4.4, 'Action Adventure', 'Renny Harlin', 'Kellan Lutz Liam McIntyre Gaia Weiss'),
(188927, 'sequel stranded hatred space opera', 'Star Trek Beyond', 'The USS Enterprise crew explores the furthest reaches of uncharted space, where they encounter a mysterious new enemy who puts them and everything the Federation stands for to the test.', 'en', 65.352913, 6.6, 'Action Adventure Science Fiction', '', 'Chris Pine Zachary Quinto Karl Urban'),
(189711, '', 'Love in the Time of Monsters', 'Two sisters travel to a cheesy tourist trap where they battle toxic monsters dressed in bigfoot costumes in order to save the ones they love.', 'en', 0.133619, 5, 'Horror Comedy', 'Matt Jackson', 'Kane Hodder Doug Jones Gena Shaw'),
(190847, 'mars science fiction zombie', 'The Last Days on Mars', 'On the last day of the first manned mission to Mars, a crew member of Tantalus Base believes he has made an astounding discovery – fossilized evidence of bacterial life. Unwilling to let the relief crew claims all the glory, he disobeys orders to pack up and goes out on an unauthorized expedition to collect further samples. But a routine excavation turns to disaster when the porous ground collapses and he falls into a deep crevice and near certain death. His devastated colleagues attempt to recover his body. However, when another vanishes, they start to suspect that the life-form they have discovered is not without danger.', 'en', 18.764453, 5.2, 'Science Fiction Thriller Horror', '', 'Liev Schreiber Romola Garai Elias Koteas'),
(190859, 'sniper biography iraq navy seal u.s. soldier', 'American Sniper', 'U.S. Navy SEAL Chris Kyle takes his sole mission—protect his comrades—to heart and becomes one of the most lethal snipers in American history. His pinpoint accuracy not only saves countless lives but also makes him a prime target of insurgents. Despite grave danger and his struggle to be a good husband and father to his family back in the States, Kyle serves four tours of duty in Iraq. However, when he finally returns home, he finds that he cannot leave the war behind.', 'en', 87.53437, 7.4, 'War Action', 'Clint Eastwood', 'Bradley Cooper Sienna Miller Kyle Gallner'),
(190955, '', 'Blood Ties', 'Two brothers, on either side of the law, face off over organized crime in Brooklyn during the 1970s.', 'en', 12.756344, 6, 'Thriller Crime Drama', '', 'Clive Owen Billy Crudup Marion Cotillard'),
(191229, '', 'Iguana', 'A grotesquely disfigured harpooner called Iguana is severely mistreated by his fellow sailors on a whaling ship in the 19th century. One night he escapes and takes up residence on a remote island. He makes himself ruler of the island and declares war on mankind. Anyone unfortunate enough to wind up on the island with Iguana is subjected to his cruel tyranny.', 'en', 0.214704, 6, '', 'Monte Hellman', 'Everett McGill Fabio Testi Michael Madsen'),
(192102, 'retirement secret service illegal drugs', '3 Days to Kill', 'A dangerous international spy is determined to give up his high stakes life to finally build a closer relationship with his estranged wife and daughter. But first, he must complete one last mission - even if it means juggling the two toughest assignments yet: hunting down the world\'s most ruthless terrorist and looking after his teenage daughter for the first time in ten years, while his wife is out of town.', 'en', 41.638961, 6, 'Action Drama Thriller Crime', '', 'Kevin Costner Amber Heard Hailee Steinfeld'),
(192132, 'high school soccer teenager older man younger woman relationship teenage sexuality woman director', 'Palo Alto', 'Palo Alto weaves together three stories of teenage lust, boredom, and self-destruction: shy, sensitive April, torn between an illicit flirtation with her soccer coach and an unrequited crush on sweet stoner Teddy; Emily, who offers sexual favors to any boy to cross her path; and the increasingly dangerous exploits of Teddy and his best friend Fred, whose behavior may or may not be sociopathic.', 'en', 16.570708, 6.4, 'Drama', '', 'Emma Roberts Jack Kilmer Nat Wolff'),
(192134, 'growing up money crime fatherhood', 'Dom Hemingway', 'After spending 12 years in prison for keeping his mouth shut, notorious safe-cracker Dom Hemingway is back on the streets of London looking to collect what he\'s owed.', 'en', 10.416332, 5.8, 'Comedy Crime Drama', '', 'Jude Law Demián Bichir Richard E. Grant'),
(192136, 'prison south africa apartheid biography nelson mandela historical figure', 'Mandela: Long Walk to Freedom', 'A chronicle of Nelson Mandela\'s life journey from his childhood in a rural village through to his inauguration as the first democratically elected president of South Africa.', 'en', 15.50957, 6.5, 'Drama History', '', 'Idris Elba Naomie Harris Tony Kgoroge'),
(192210, 'drug dealer police killer illegal drugs dealer', 'Open Road', 'Angie, a young Brazilian artist, abandons her old life and embarks on a journey around the country. Running from her past, and searching for her foundation in life, Angie finds not only herself but love in its many forms.', 'en', 2.680629, 5.2, 'Action Drama Thriller', 'Márcio Garcia', 'Camilla Belle Andy García Colin Egglesfield'),
(192577, '', 'Space Pirate Captain Harlock', 'Space Pirate Captain Harlock and his fearless crew face off against the space invaders who seek to conquer the planet Earth.', 'ja', 14.726338, 6.5, 'Animation Science Fiction', 'Shinji Aramaki', 'Shun Oguri Haruma Miura Yu Aoi'),
(193603, 'haunted house slasher', 'Hayride', 'A college student returning home for Halloween is forced to face his childhood fears when an escaped killer takes refuge in his family\'s \"Haunted Hayride\".', 'en', 0.412342, 5.1, 'Thriller Horror', 'Terron R. Parsons', 'Richard Tyson Sherri Eakin Jeremy Ivy'),
(193610, 'infidelity revenge unfaithful boyfriend woman sitting on a toilet public toilet marital infidelity laxative unfaithful husband', 'The Other Woman', 'After discovering her boyfriend is married, Carly soon meets the wife he\'s been cheating on. And when yet another affair is discovered, all three women team up to plot mutual revenge on the three-timing SOB.', 'en', 34.519636, 6.2, 'Comedy Romance', 'Nick Cassavetes', 'Cameron Diaz Leslie Mann Kate Upton'),
(193613, 'heavy metal live concert', 'Metallica: Through the Never', 'Trip, a young roadie for Metallica, is sent on an urgent mission during the band\'s show. But what seems like a simple assignment turns into a surreal adventure.', 'en', 7.871686, 6.7, 'Music', 'Nimród Antal', 'Dane DeHaan Mackenzie Gray James Hetfield'),
(193722, 'dominatrix bdsm', 'R100', 'Ruthless dominatrixes pursue a mild-mannered salesman who wants to get out of his unbreakable contract with a secret bondage club.', 'ja', 3.21392, 5.4, 'Comedy Drama', 'Hitoshi Matsumoto', 'Nao Omori Mao Daichi Shinobu Terajima'),
(193756, 'war survival navy seal military dangerous mission', 'Lone Survivor', 'Based on the failed June 28, 2005 mission \"Operation Red Wing.\" Four members of SEAL Team 10, were tasked with the mission to capture or kill notorious Taliban leader, Ahmad Shah. Only one member of the team survived.', 'en', 37.084384, 7.4, 'Action Drama Thriller War', '', 'Mark Wahlberg Taylor Kitsch Emile Hirsch'),
(193893, 'corruption robbery kidnapping nightclub male friendship investigation police party murder mobster los angeles lying impersonating a police officer flashback', 'Let\'s Be Cops', 'It\'s the ultimate buddy cop movie except for one thing: they\'re not cops.  When two struggling pals dress as police officers for a costume party, they become neighborhood sensations.  But when these newly-minted “heroes” get tangled in a real life web of mobsters and dirty detectives, they must put their fake badges on the line.', 'en', 70.668923, 6.4, 'Comedy', '', 'Jake Johnson Damon Wayans Jr. Nina Dobrev'),
(194588, '', 'Short Cut to Nirvana: Kumbh Mela', 'Every 12 years over 70 million pilgrims gather at the meeting of India\'s holiest rivers, the Ganges and the Yamuna, for a spectacular spiritual festival: the Kumbh Mela. This documentary takes a voyage of discovery through this colorful event through the eyes of several Westerners and an ebullient young Hindu monk, Swami Krishnanand. Featuring encounters with some of India\'s most respected holy men and exclusive footage of His Holiness the Dalai Lama.', 'en', 0.004998, 0, '', '', ''),
(194662, 'times square superhero long take new york city play broadway actor', 'Birdman', 'A fading actor best known for his portrayal of a popular superhero attempts to mount a comeback by appearing in a Broadway play. As opening night approaches, his attempts to become more altruistic, rebuild his career, and reconnect with friends and family prove more difficult than expected.', 'en', 89.811154, 7.4, 'Drama Comedy', 'Alejandro González Iñárritu', 'Michael Keaton Emma Stone Zach Galifianakis'),
(195589, 'alcohol baby party family fraternity fraternity house neighbor neighbor relationship bathroom humor', 'Neighbors', 'A couple with a newborn baby face unexpected difficulties after they are forced to live next to a fraternity house.', 'en', 36.471231, 6.2, 'Comedy', '', 'Seth Rogen Zac Efron Rose Byrne'),
(196867, 'musical orphan foster child', 'Annie', 'Ever since her parents left her as a baby, little Annie has led a hard-knock life with her calculating foster mother, Miss Hannigan. However, all that changes when hard-nosed billionaire and mayoral candidate Will Stacks takes her in on the recommendation of his advisers. Stacks believes that he\'s Annie\'s guardian angel, but the plucky youngster\'s confidence and sunny outlook may mean that Annie will save Will instead.', 'en', 33.439187, 6, 'Comedy Drama Family', '', 'Quvenzhané Wallis Jamie Foxx Rose Byrne'),
(198184, 'artificial intelligence android robot near future robot cop', 'Chappie', 'Every child comes into the world full of promise, and none more so than Chappie: he is gifted, special, a prodigy. Like any child, Chappie will come under the influence of his surroundings—some good, some bad—and he will rely on his heart and soul to find his way in the world and become his own man. But there\'s one thing that makes Chappie different from any one else: he is a robot.', 'en', 116.700319, 6.6, 'Crime Action Science Fiction', '', 'Sharlto Copley Dev Patel Ninja'),
(198185, 'baseball sport duringcreditsstinger', 'Million Dollar Arm', 'In a last-ditch effort to save his career, sports agent JB Bernstein (Jon Hamm) dreams up a wild game plan to find Major League Baseball’s next great pitcher from a pool of cricket players in India. He soon discovers two young men who can throw a fastball but know nothing about the game of baseball. Or America. It’s an incredible and touching journey that will change them all — especially JB, who learns valuable lessons about teamwork, commitment and family.', 'en', 17.312433, 6.6, 'Drama', 'Craig Gillespie', 'Jon Hamm Bill Paxton Lake Bell'),
(198277, '', 'Begin Again', 'Gretta\'s celebrity boyfriend breaks up with her after a long-term relationship, leaving the singer to find success on her own. With the help of record producer, Dan and hip-hop celebrity, Trouble Gum, Gretta strives to fulfil her musical ambitions.', 'en', 35.735689, 7.3, 'Comedy Music Romance Drama', '', 'Mark Ruffalo Keira Knightley Adam Levine'),
(198370, '', 'Mutual Friends', 'Surprise parties rarely go well. This one is no different, as a group of 30-somethings head through life, love and a day in New York City.', 'en', 0.136721, 0, '', 'Matthew Watts', 'Caitlin Fitzgerald Cheyenne Jackson Peter Scanavino'),
(198663, 'based on novel maze post-apocalyptic dystopia escape memory loss erased memory trapped dystopic future runner based on young adult novel', 'The Maze Runner', 'Set in a post-apocalyptic world, young Thomas is deposited in a community of boys after his memory is erased, soon learning they\'re all trapped in a maze that will require him to join forces with fellow \"runners\" for a shot at escape.', 'en', 131.815575, 7, 'Action Mystery Science Fiction Thriller', '', 'Dylan O\'Brien Ki Hong Lee Kaya Scodelario'),
(199373, 'gun escape serial killer man hunt hunting', 'The Frozen Ground', 'An Alaska State Trooper partners with a young woman who escaped the clutches of serial killer Robert Hansen to bring the murderer to justice. Based on actual events.', 'en', 28.060472, 6.1, 'Thriller Crime', '', 'Nicolas Cage Vanessa Hudgens John Cusack'),
(200505, 'sport duringcreditsstinger', 'Draft Day', 'At the NFL Draft, general manager Sonny Weaver has the opportunity to rebuild his team when he trades for the number one pick. He must decide what he\'s willing to sacrifice on a life-changing day for a few hundred young men with NFL dreams.', 'en', 14.17009, 6.5, 'Drama', '', 'Kevin Costner Jennifer Garner Tom Welling'),
(201088, 'terrorist technology anti hero hacker computer virus national security agency (nsa) race against time computer malaysia nuclear power plant suspense betrayal conspiracy on the run fugitive shootout hacking terrorism cat and mouse one against many computer hacker no opening credits terrorist plot stock exchange cybercrime cyber terrorism chinese military cyber terrorist cyber thriller', 'Blackhat', 'A man is released from prison to help American and Chinese authorities pursue a mysterious cyber criminal. The dangerous search leads them from Chicago to Hong Kong.', 'en', 46.832372, 5.1, 'Crime Drama Mystery', '', 'Chris Hemsworth Leehom Wang Tang Wei'),
(201132, 'biography antarctica', 'Antarctica: A Year on Ice', 'Filling the giant screen with stunning time-lapse vistas of Antarctica, and detailing year-round life at McMurdo and Scott Base, Anthony Powell’s documentary is a potent hymn to the icy continent and the heavens above.', 'en', 1.883947, 7.2, 'Drama Adventure Documentary', 'Anthony Powell', 'Genevieve Bachman William Brotman Michael Christiansen'),
(202575, 'magic 3d', 'Thunder and the House of Magic', 'Thunder, an abandoned young cat seeking shelter from a storm, stumbles into the strangest house imaginable, owned by an old magician and inhabited by a dazzling array of automatons and gizmos. Not everyone welcomes the new addition to the troupe as Jack Rabbit and Maggie Mouse plot to evict Thunder. The situation gets worse when the magician lands in hospital and his scheming nephew sees his chance to cash in by selling the mansion. Our young hero is determined to earn his place and so he enlists the help of some wacky magician\'s assistants to protect his magical new home.', 'en', 12.867326, 6.3, 'Family Fantasy Animation Adventure', 'Ben Stassen', 'Brianne Siddall Joey Camen Elisa Gabrielli'),
(202604, 'exorcism', 'The Vatican Exorcisms', 'Documentary following US film-maker Joe Marino as he heads to Italy to investigate exorcisms and the truth behind rumors of demonic possession.', 'en', 0.447166, 4.4, 'Horror Documentary Mystery', 'Joe Marino', 'Joe Marino'),
(203801, 'spy cold war remake based on tv series buddy cop russian spy american spy', 'The Man from U.N.C.L.E.', 'At the height of the Cold War, a mysterious criminal organization plans to use nuclear weapons and technology to upset the fragile balance of power between the United States and Soviet Union. CIA agent Napoleon Solo and KGB agent Illya Kuryakin are forced to put aside their hostilities and work together to stop the evildoers in their tracks. The duo\'s only lead is the daughter of a missing German scientist, whom they must find soon to prevent a global catastrophe.', 'en', 48.744209, 7.1, 'Comedy Action Adventure', 'Guy Ritchie', 'Henry Cavill Armie Hammer Alicia Vikander'),
(203833, 'world war ii book nazi germany jewish', 'The Book Thief', 'While subjected to the horrors of WWII Germany, young Liesel finds solace by stealing books and sharing them with others. Under the stairs in her home, a Jewish refuge is being sheltered by her adoptive parents.', 'en', 57.84156, 7.4, 'Drama', '', 'Geoffrey Rush Sophie Nélisse Emily Watson'),
(204082, 'based on novel drug dealer ex-cop rural setting undercover cop methamphetamine motorcycle gang drug revenge motive father daughter relationship lousiana bayou', 'Homefront', 'Phil Broker is a former DEA agent who has gone through a crisis after his action against a biker gang went horribly wrong and it cost the life of his boss\' son. He is recently widowed and is left with a 9-years-old daughter,Maddy. He decides to quit the turbulent and demanding life of thrill for Maddy\'s sake and retires to a small town. His daughter fights off a boy who was bullying her at school and this sets in motion a round of events that end in his direct confrontation with the local Meth drug lord. His past history with the biker gang also enters the arena, making matters more complex. But he has a mission in his mind to protect his daughter and he is ready to pay any cost that it demands.', 'en', 35.737655, 6.4, 'Action Thriller', 'Gary Fleder', 'Jason Statham James Franco Izabela Vidovic'),
(204922, 'amnesia therapist aggression hospital flashback', 'Before I Go to Sleep', 'A woman wakes up every day, remembering nothing as a result of a traumatic accident in her past. One day, new terrifying truths emerge that force her to question everyone around her.', 'en', 48.784734, 6.2, 'Mystery Thriller', '', 'Nicole Kidman Colin Firth Mark Strong'),
(205321, 'california helicopter beach tornado hurricane attack blood chainsaw storm explosion danger shark tv movie flood', 'Sharknado', 'A freak hurricane hits Los Angeles, causing man-eating sharks to be scooped up in tornadoes and flooding the city with shark-infested seawater. Surfer and bar-owner Fin sets out with his friends Baz and Nova to rescue his estranged wife April and teenage daughter Claudia', 'en', 20.466433, 3.8, 'TV Movie Horror', 'Anthony C. Ferrante', 'Ian Ziering Tara Reid Cassandra Scerbo'),
(205584, 'egypt underworld fight mythology nile war thief rescue desert gods egyptian mythology egyptian myth', 'Gods of Egypt', 'A common thief joins a mythical god on a quest through Egypt.', 'en', 56.257249, 5.3, 'Fantasy', '', 'Brenton Thwaites Nikolaj Coster-Waldau Gerard Butler'),
(205587, 'father son relationship judge lawyer', 'The Judge', 'A successful lawyer returns to his hometown for his mother\'s funeral only to discover that his estranged father, the town\'s judge, is suspected of murder.', 'en', 42.472324, 7.2, 'Drama', '', 'Robert Duvall Robert Downey Jr. Vera Farmiga'),
(205588, 'based on novel woman director', 'Our Kind of Traitor', 'A young Oxford academic and his attorney girlfriend holiday on Antigua. They bump into a Russian millionaire who owns a peninsula and a diamond watch. He wants a game of tennis. What else he wants propels the lovers on a tortuous journey to the City of London and its unholy alliance with Britain\'s intelligence establishment, to Paris and the Alps.', 'en', 10.547959, 6, 'Thriller', '', 'Ewan McGregor Stellan Skarsgård Damian Lewis'),
(205596, 'gay england world war ii mathematician biography logician cryptography', 'The Imitation Game', 'Based on the real life story of legendary cryptanalyst Alan Turing, the film portrays the nail-biting race against time by Turing and his brilliant team of code-breakers at Britain\'s top-secret Government Code and Cypher School at Bletchley Park, during the darkest days of World War II.', 'en', 145.364591, 8, 'History Drama Thriller War', '', 'Benedict Cumberbatch Keira Knightley Matthew Goode'),
(205775, 'suicide ocean sea hunger shipwreck ship whale based on true story stranded survival whaling death new england lost at sea based on true events whaling ship starvation 19th century cannibalism reference to moby dick whale oil nantucket', 'In the Heart of the Sea', 'In the winter of 1820, the New England whaling ship Essex was assaulted by something no one could believe: a whale of mammoth size and will, and an almost human sense of vengeance.  The real-life maritime disaster would inspire Herman Melville’s Moby Dick.  But that told only half the story.  “Heart of the Sea” reveals the encounter’s harrowing aftermath, as the ship’s surviving crew is pushed to their limits and forced to do the unthinkable to stay alive.  Braving storms, starvation, panic and despair, the men will call into question their deepest beliefs, from the value of their lives to the morality of their trade, as their captain searches for direction on the open sea and his first mate still seeks to bring the great whale down.', 'en', 50.767332, 6.5, 'Thriller Drama Adventure Action History', '', 'Chris Hemsworth Benjamin Walker Cillian Murphy'),
(206412, '', 'Lisa Picard Is Famous', 'A documentarian decides to follow the career of New York actress Lisa Picard, believing she is on the brink of fame. Instead, he bears witness to Lisa\'s continued, humorous, struggles as an actress, as well as the conflict that arises when Lisa\'s best friend Tate hits it big with an off-Broadway one-man show.', 'en', 0.690089, 4, '', 'Griffin Dunne', 'Laura Kirk Nat DeWolf Griffin Dunne'),
(206563, 'brazilian drama thriller', 'Trash', 'Set in Brazil, three kids who make a discovery in a garbage dump soon find themselves running from the cops and trying to right a terrible wrong.', 'pt', 14.637357, 7.1, 'Adventure Crime Drama Thriller', 'Stephen Daldry', 'Rickson Tevez Eduardo Luis Gabriel Weinstein'),
(206647, 'spy based on novel secret agent sequel mi6 british secret service united kingdom', 'Spectre', 'A cryptic message from Bond’s past sends him on a trail to uncover a sinister organization. While M battles political forces to keep the secret service alive, Bond peels back the layers of deceit to reveal the terrible truth behind SPECTRE.', 'en', 107.376788, 6.3, 'Action Adventure Crime', 'Sam Mendes', 'Daniel Craig Christoph Waltz Léa Seydoux'),
(208134, 'duringcreditsstinger', 'Bad Grandpa', '86-year-old Irving Zisman is on a journey across America with the most unlikely companion: his 8 year-old grandson, Billy.', 'en', 27.165222, 6, 'Comedy', '', 'Johnny Knoxville Jackson Nicoll Georgina Cates'),
(208763, 'monster mystic church demon witchcraft science dark fantasy 3d', 'Forbidden Kingdom', 'Early 18th century. Cartographer Jonathan Green undertakes a scientific voyage from Europe to the East. Having passed through Transylvania and crossed the Carpathian Mountains, he finds himself in a small village lost in impassible woods. Nothing but chance and heavy fog could bring him to this cursed place. People who live here do not resemble any other people which the traveler saw before that. The villagers, having dug a deep moat to fend themselves from the rest of the world, share a naive belief that they could save themselves from evil, failing to understand that evil has made its nest in their souls and is waiting for an opportunity to gush out upon the world.', 'ru', 7.182761, 4.9, 'Thriller Adventure Mystery Fantasy', 'Oleg Stepchenko', 'Jason Flemyng Aleksey Chadov Agniya Ditkovskite'),
(208869, '', 'Plastic', 'Sam &amp; Fordy run a credit card fraud scheme, but when they steal from the wrong man, they find themselves threatened by sadistic gangster. They need to raise £5m and pull off a daring diamond heist to clear their debt.', 'en', 9.70276, 6.1, 'Drama Action Comedy Crime', 'Julian Gilbey', 'Ed Speleers Will Poulter Alfie Allen'),
(209112, 'dc comics vigilante superhero based on comic book revenge super powers clark kent bruce wayne dc extended universe', 'Batman v Superman: Dawn of Justice', 'Fearing the actions of a god-like Super Hero left unchecked, Gotham City’s own formidable, forceful vigilante takes on Metropolis’s most revered, modern-day savior, while the world wrestles with what sort of hero it really needs. And with Batman and Superman at war with one another, a new threat quickly arises, putting mankind in greater danger than it’s ever known before.', 'en', 155.790452, 5.7, 'Action Adventure Fantasy', '', 'Ben Affleck Henry Cavill Gal Gadot'),
(209263, 'masseuse thanksgiving party romance mother daughter relationship dating relationship divorce divorcee woman director massage therapist', 'Enough Said', 'Eva is a divorced soon-to-be empty-nester wondering about her next act. Then she meets Marianne, the embodiment of her perfect self. Armed with a restored outlook on being middle-aged and single, Eva decides to take a chance on her new love interest Albert — a sweet, funny and like-minded man. But things get complicated when Eva discovers that Albert is in fact the dreaded ex–husband of Marianne...', 'en', 14.969093, 6.6, 'Comedy Drama Romance', '', 'Julia Louis-Dreyfus Catherine Keener James Gandolfini'),
(209274, 'nun mine jew jewish poland', 'Ida', 'Poland, 1962. Anna is a novice, an orphan brought up by nuns in a convent. Before she takes her vows, she is determined to see Wanda, her only living relative. Wanda tells Anna that Anna is Jewish. Both women embark on a journey not only to discover their tragic family story, but who they really are and where they belong, questioning their religions and beliefs.', 'pl', 13.265432, 7.1, 'Drama', 'Paweł Pawlikowski', 'Agata Trzebuchowska Agata Kulesza Joanna Kulig'),
(209403, 'competition satire spelling bee estranged father unlikely friendship anger issues', 'Bad Words', 'A misanthropic man sets out to exact revenge on his estranged father, by finding a loophole and attempting to win the National Spelling Bee as an adult. Figuring it would destroy his father, and everything he\'s worked so hard for as head of the Spelling Bee Championship Organization, Guy Trilby (Jason Bateman) eventually discovers winning isn\'t necessary for revenge, and that friendship is a blessing not a curse.', 'en', 14.105392, 6.4, 'Comedy', 'Jason Bateman', 'Jason Bateman Kathryn Hahn Rohan Chand'),
(209451, 'biography based on play', 'Jersey Boys', 'From director Clint Eastwood comes the big-screen version of the Tony Award-winning musical Jersey Boys. The film tells the story of four young men from the wrong side of the tracks in New Jersey who came together to form the iconic 1960s rock group The Four Seasons. The story of their trials and triumphs are accompanied by the songs that influenced a generation, including “Sherry,” “Big Girls Don’t Cry,” “Walk Like a Man,” “Rag Doll,” and many more.', 'en', 14.199933, 6.8, 'Music Drama', 'Clint Eastwood', 'Christopher Walken Vincent Piazza Freya Tingley'),
(210577, 'based on novel marriage crisis disappearance cheating husband missing person search party criminal lawyer wife murder murder suspect missing wife', 'Gone Girl', 'With his wife\'s disappearance having become the focus of an intense media circus, a man sees the spotlight turned on him when it\'s suspected that he may not be innocent.', 'en', 143.041543, 7.9, 'Mystery Thriller Drama', '', 'Ben Affleck Rosamund Pike Carrie Coon'),
(210860, 'based on novel painting debt art dealer stolen painting', 'Mortdecai', 'Art dealer, Charles Mortdecai, searches for a stolen painting rumored to contain a secret code that gains access to hidden Nazi gold.', 'en', 52.417529, 5.4, 'Comedy Adventure', 'David Koepp', 'Johnny Depp Gwyneth Paltrow Ewan McGregor'),
(211086, 'himalaya hindu pilgrimage faith hinduism little boy spirituality new age religion orphan india religious child abandonment ganja kumbh mela ganga', 'Faith Connections', 'A filmmaker\'s insight into the biggest gathering on earth -the Kumbh Mela.', 'hi', 0.48088, 4.2, 'Documentary Drama', 'Pan Nalin', 'Bhole Baba Hatha Yogi Baba Pant Shirt Baba'),
(211672, 'assistant aftercreditsstinger duringcreditsstinger evil mastermind minions 3d', 'Minions', 'Minions Stuart, Kevin and Bob are recruited by Scarlet Overkill, a super-villain who, alongside her inventor husband Herb, hatches a plot to take over the world.', 'en', 875.581305, 6.4, 'Family Animation Adventure Comedy', 'Kyle Balda', 'Sandra Bullock Jon Hamm Michael Keaton'),
(211954, 'bachelor vespa', 'Instructions Not Included', 'Valentin is Acapulco\'s resident playboy, until a former fling leaves a baby on his doorstep and him heading with her out of Mexico.', 'es', 9.59729, 7.5, 'Comedy Drama', '', 'Loreto Peralta Eugenio Derbez Jessica Lindsey'),
(214756, 'sperm bank sequel buddy courthouse teddy bear aftercreditsstinger toy comes to life married', 'Ted 2', 'Newlywed couple Ted and Tami-Lynn want to have a baby, but in order to qualify to be a parent, Ted will have to prove he\'s a person in a court of law.', 'en', 68.734513, 6.2, 'Comedy', '', 'Mark Wahlberg Seth MacFarlane Amanda Seyfried'),
(215211, 'monaco prince', 'Grace of Monaco', 'The story of former Hollywood star Grace Kelly\'s crisis of marriage and identity, during a political dispute between Monaco\'s Prince Rainier III and France\'s Charles De Gaulle, and a looming French invasion of Monaco in the early 1960s.', 'en', 10.958697, 5.8, 'Romance Drama', 'Olivier Dahan', 'Nicole Kidman Milo Ventimiglia Paz Vega'),
(215924, 'woman director', 'The Amazing Catfish', 'Young Claudia works in a supermarket where she promotes various types of products. One night, she ends up in the emergency room with severe appendicitis and meets Martha, a patient, laying in the bed next to hers.', 'es', 1.473405, 5.7, 'Comedy Drama', '', 'Lisa Owen Ximena Ayala Sonia Franco'),
(216015, 'based on novel perversion spanking billionaire bdsm woman director', 'Fifty Shades of Grey', 'When college senior Anastasia Steele steps in for her sick roommate to interview prominent businessman Christian Grey for their campus paper, little does she realize the path her life will take. Christian, as enigmatic as he is rich and powerful, finds himself strangely drawn to Ana, and she to him. Though sexually inexperienced, Ana plunges headlong into an affair -- and learns that Christian\'s true sexual proclivities push the boundaries of pain and pleasure.', 'en', 98.755657, 5.2, 'Drama Romance Thriller', '', 'Dakota Johnson Jamie Dornan Jennifer Ehle'),
(216282, 'tornado student found footage disaster movie', 'Into the Storm', 'The town of Silverton is in one day destroyed by the unprecedented power of a series of tornadoes. The population is at the mercy of the unpredictable and deadly cyclones, while hunters warn that the worst is yet to come. Most people find shelter, but some just go to the tornado for that one, unique shot.', 'en', 20.566554, 5.8, 'Action Thriller', '', 'Richard Armitage Sarah Wayne Callies Matt Walsh'),
(217708, 'horse snow storm icelandic', 'Of Horses and Men', 'A country romance about the human streak in the horse and the horse in the human. Love and death become interlaced and with terrible consequences.The fortunes of the people in the country through the horses\' perception.', 'is', 1.617943, 6.9, 'Drama Romance Comedy', 'Benedikt Erlingsson', 'Ingvar Eggert Sigurðsson Charlotte Bøving Steinn Ármann Magnússon'),
(218043, 'airplane the rapture remake pilot hero', 'Left Behind', 'A small group of survivors are left behind after millions of people suddenly vanish during the rapture and the world is plunged into chaos and destruction.', 'en', 33.452469, 3.7, 'Thriller Action Science Fiction', '', 'Nicolas Cage Chad Michael Murray Lea Thompson'),
(218778, 'based on novel job interview bad luck wish one day based on children\'s book driver\'s test', 'Alexander and the Terrible, Horrible, No Good, Very Bad Day', 'Alexander\'s day begins with gum stuck in his hair, followed by more calamities. Though he finds little sympathy from his family and begins to wonder if bad things only happen to him, his mom, dad, brother, and sister all find themselves living through their own terrible, horrible, no good, very bad day.', 'en', 22.14595, 6.1, 'Family Comedy', '', 'Steve Carell Jennifer Garner Ed Oxenbould'),
(220488, 'hong kong macau woman director', 'My Lucky Star', 'My Lucky Star is a 2013 Chinese romance film directed by Dennie Gordon and starring Zhang Ziyi and Leehom Wang. The film also serves as a prequel to the 2009 film Sophie\'s Revenge.', 'zh', 1.86453, 4.3, 'Comedy Romance', '', 'Zhang Ziyi Leehom Wang Ruby Lin'),
(220490, '', 'Her Cry: La Llorona Investigation', 'Crew of \"Paranormal Legends\" went to film their 4th season at the place where La Llorona (Weeping woman) was reportedly seen. Only thing that\'s left was 17 hours of tapes and 2 camcorders.', 'en', 0.056459, 0, 'Horror', 'Damir Catic', 'Nichole Ceballos James Ezrin Everardo Guzman'),
(222250, '', 'A True Story', 'Mike and Matt own nothing and share everything, including their life\'s work, a screenplay, which seems to be their only escape from the harsh reality that is the Hollywood machine.', 'en', 0.970351, 6.8, 'Comedy', 'Malcolm Goodwin', 'Katrina Bowden Jon Gries Malcolm Goodwin'),
(222649, 'prison biography reporter interrogation iran american spy', 'Rosewater', 'In 2009, Iranian Canadian journalist Maziar Bahari was covering Iran\'s volatile elections for Newsweek. One of the few reporters living in the country with access to US media, he made an appearance on The Daily Show with Jon Stewart, in a taped interview with comedian Jason Jones. The interview was intended as satire, but if the Tehran authorities got the joke they didn\'t like it - and it would quickly came back to haunt Bahari when he was rousted from his family home and thrown into prison. Making his directorial debut, Jon Stewart tells the tale of Bahari\'s months-long imprisonment and interrogation in this powerful and affecting docudrama featuring a potent and performance by Gael García Bernal recounting Bahari\'s efforts to maintain his hope and his sanity in the face of isolation and persecution-through memories of his family, recollections of the music he loves, and thoughts of his wife and unborn child.', 'en', 5.75555, 6.5, 'Drama', '', 'Gael García Bernal Shohreh Aghdashloo Jason Jones'),
(222899, 'duringcreditsstinger', 'About Last Night', 'A modern reimagining of the classic romantic comedy, this contemporary version closely follows new love for two couples as they journey from the bar to the bedroom and are eventually put to the test in the real world.', 'en', 11.828068, 6, 'Comedy Romance', 'Steve Pink', 'Kevin Hart Michael Ealy Regina Hall'),
(222936, 'love triangle hawaii satellite military duringcreditsstinger communication', 'Aloha', 'A celebrated military contractor returns to the site of his greatest career triumphs and re-connects with a long-ago love while unexpectedly falling for the hard-charging Air Force watchdog assigned to him.', 'en', 29.652536, 5.2, 'Drama Comedy Romance', '', 'Bradley Cooper Emma Stone Rachel McAdams');
INSERT INTO `movies` (`movie_id`, `tags`, `title`, `overview`, `original_language`, `popularity`, `vote_average`, `genres`, `directeur`, `acteurs`) VALUES
(223485, 'fire bounty hunter shotgun horseback riding horse cabin frontier outlaw rifle unrequited love death of father native american shootout search pistol death by accident violence ireland drinking pursuit shot through a wall flaming arrow dream sequence flashback shot in the heart', 'Slow West', 'In the Old West, a 17-year-old Scottish boy teams up with a mysterious gunman to find the woman with whom he is infatuated.', 'en', 14.936661, 6.6, 'Romance Thriller Western', '', 'Michael Fassbender Kodi Smit-McPhee Ben Mendelsohn'),
(223702, 'supermarket party sausage food anthropomorphism sex scene musical number adult animation grocery store gum', 'Sausage Party', 'Sausage Party, the first R-rated CG animated movie, is about one sausage leading a group of supermarket products on a quest to discover the truth about their existence and what really happens when they become chosen to leave the grocery store.', 'en', 66.242737, 5.6, 'Adventure Animation Comedy Fantasy', 'Conrad Vernon', 'Seth Rogen Kristen Wiig Jonah Hill'),
(224141, 'witch cinderella prince fairy tale musical princess sondheim curse based on stage musical beanstalk duringcreditsstinger red riding hood', 'Into the Woods', 'In a woods filled with magic and fairy tale characters, a baker and his wife set out to end the curse put on them by their neighbor, a spiteful witch.', 'en', 65.90161, 5.6, 'Fantasy Comedy Music', '', 'Meryl Streep Emily Blunt James Corden'),
(224569, 'machinegun tax inspector wedding party', 'Taxman', 'After a homocide that the police believe is over gasoline theft, a tax investigator discovers the Russian mafia is involved and that they are stealing millions in gasoline tax money. Only one rookie cop is willing to believe him and together they must get the evidence they need or die trying.', 'en', 0.964802, 2, 'Action Crime Comedy Thriller', 'Avi Nesher', 'Joe Pantoliano Wade Dominguez Elizabeth Berkley'),
(225235, 'alcohol adultery river camping province russia wife canoe daughter friendship alcoholism school teaching schoolboy geography kama perm', 'The Geographer Drank His Globe Away', 'Victor Sluzhkin signs on as a teacher of geography in a secondary school in his native Perm (in the Urals) and gets lost in a haze of hard vodka, desperate love for a nymphet-like student and the stress of educating teenagers. Geographer, as the students immediately dub Sluzhkin, attempts to escape from the grueling, dull, stultifying reality of Russia\'s provincial life in a rafting tour to the Urals. Accompanied by wild, adventure-seeking adolescents, faced with the numerous grim surprises of the nature, Geographer is poised to find himself and his own truth.', 'ru', 1.876621, 7.3, 'Drama', '', 'Konstantin Khabenskiy Elena Lyadova Aleksandr Robak'),
(225565, 'male friendship friendship dating relationship duringcreditsstinger young adult', 'That Awkward Moment', 'Best pals Jason and Daniel indulge in casual flings and revel in their carefree, unattached lives. After learning that the marriage of their friend Mikey is over, they gladly welcome him back into their circle. The three young men make a pact to have fun and avoid commitment. However, when all three find themselves involved in serious relationships, they must keep their romances secret from one another.', 'en', 37.821106, 6.1, 'Comedy Romance', '', 'Zac Efron Miles Teller Michael B. Jordan'),
(225574, 'airplane conspiracy airplane crash cell phone hijack one night mystery killer', 'Non-Stop', 'Bill Marks is a burned-out veteran of the Air Marshals service. He views the assignment not as a life-saving duty, but as a desk job in the sky. However, today\'s flight will be no routine trip. Shortly into the transatlantic journey from New York to London, he receives a series of mysterious text messages ordering him to have the government transfer $150 million into a secret account, or a passenger will die every 20 minutes.', 'en', 83.295796, 6.8, 'Action Thriller Mystery', '', 'Liam Neeson Julianne Moore Scoot McNairy'),
(225886, 'marriage internet relationship family sex tape', 'Sex Tape', 'When Jay and Annie first got together, their romantic connection was intense – but ten years and two kids later, the flame of their love needs a spark.  To kick things up a notch, they decide – why not? – to make a video of themselves trying out every position in The Joy of Sex in one marathon three-hour session.  It seems like a great idea – until they discover that their most private video is no longer private.  With their reputations on the line, they know they’re just one click away from being laid bare to the world... but as their race to reclaim their video leads to a night they\'ll never forget, they\'ll find that their video will expose even more than they bargained for.', 'en', 72.641296, 5.3, 'Comedy', '', 'Cameron Diaz Jason Segel Rob Corddry'),
(226354, 'angel miracle village christian candle christmas', 'The Christmas Candle', 'Deep in the heart of the English countryside lies the enchanting village of Gladbury. Legend has it every 25 years an angel visits the village candlemaker and touches a single candle. Whoever lights this candle receives a miracle on Christmas Eve. But in 1890, at the dawn of the electric age, this centuries old legend may come to an end.', 'en', 1.799504, 5.8, 'Drama Family', '', 'Hans Matheson Samantha Barks Lesley Manville'),
(226458, 'possession', 'Backmask', 'During an all-night, drug-fueled party at an abandoned asylum known for the horrific treatment of its patients, a group of ordinary teens decide to experiment with the occult, mysteriously leading to a violent possession. In an effort to find help, the group rushes to escape, only to find themselves locked inside with no means of communication. Tempers flare, trusts are broken and in attempt to save one of their friends possessed by the demon, the amateurs try to perform an exorcism. Instead of solving the problem, and unbeknownst to them, they unleash an even more powerful and vengeful spirit, one with a distinct motive and which wants them all dead. The teen\'s only chance of survival is to uncover the asylum\'s deep mysteries and find a way out before it\'s too late.', 'en', 3.619167, 4.7, 'Thriller Horror', 'Marcus Nispel', 'Stephen Lang Kelly Blatz Brittany Curran'),
